# Ensure mute tables exist at startup so mute checks never fail on missing table
try:
    with get_db_connection() as _mc:
        _mcc = _mc.cursor()
        if USE_MYSQL:
            _mcc.execute("CREATE TABLE IF NOT EXISTS user_muted_chats (username VARCHAR(191) NOT NULL, chat_key VARCHAR(255) NOT NULL, muted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (username, chat_key))")
            _mcc.execute("CREATE TABLE IF NOT EXISTS user_muted_communities (username VARCHAR(191) NOT NULL, community_id INT NOT NULL, muted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (username, community_id))")
        else:
            _mcc.execute("CREATE TABLE IF NOT EXISTS user_muted_chats (username TEXT NOT NULL, chat_key TEXT NOT NULL, muted_at TEXT DEFAULT (datetime('now')), PRIMARY KEY (username, chat_key))")
            _mcc.execute("CREATE TABLE IF NOT EXISTS user_muted_communities (username TEXT NOT NULL, community_id INTEGER NOT NULL, muted_at TEXT DEFAULT (datetime('now')), PRIMARY KEY (username, community_id))")
        _mc.commit()
    print("[STARTUP] Mute tables ensured", file=sys.stderr, flush=True)
except Exception as _me:
    print(f"[STARTUP] Mute table init warning: {_me}", file=sys.stderr, flush=True)

try:
    with get_db_connection() as _sc:
        _scc = _sc.cursor()
        if USE_MYSQL:
            _scc.execute("""CREATE TABLE IF NOT EXISTS steve_chat_sessions (
                id INT AUTO_INCREMENT PRIMARY KEY,
                username VARCHAR(191) NOT NULL,
                community_id INT NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                INDEX idx_steve_user_comm (username, community_id)
            )""")
            _scc.execute("""CREATE TABLE IF NOT EXISTS steve_chat_messages (
                id INT AUTO_INCREMENT PRIMARY KEY,
                session_id INT NOT NULL,
                role ENUM('user','steve') NOT NULL,
                text TEXT NOT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                INDEX idx_steve_session (session_id),
                FOREIGN KEY (session_id) REFERENCES steve_chat_sessions(id) ON DELETE CASCADE
            )""")
        else:
            _scc.execute("""CREATE TABLE IF NOT EXISTS steve_chat_sessions (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                username TEXT NOT NULL,
                community_id INTEGER NOT NULL,
                created_at TEXT DEFAULT (datetime('now'))
            )""")
            _scc.execute("""CREATE TABLE IF NOT EXISTS steve_chat_messages (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                session_id INTEGER NOT NULL,
                role TEXT NOT NULL CHECK(role IN ('user','steve')),
                text TEXT NOT NULL,
                created_at TEXT DEFAULT (datetime('now')),
                FOREIGN KEY (session_id) REFERENCES steve_chat_sessions(id) ON DELETE CASCADE
            )""")
        if USE_MYSQL:
            _scc.execute("""CREATE TABLE IF NOT EXISTS steve_recommendation_feedback (
                id INT AUTO_INCREMENT PRIMARY KEY,
                session_id INT NOT NULL,
                recommended_username VARCHAR(191) NOT NULL,
                feedback ENUM('up','down') NOT NULL,
                created_by VARCHAR(191) NOT NULL,
                reasoning_text TEXT NULL,
                query_context TEXT NULL,
                created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                UNIQUE KEY uq_session_user_by (session_id, recommended_username, created_by),
                INDEX idx_feedback_user (recommended_username)
            )""")
        else:
            _scc.execute("""CREATE TABLE IF NOT EXISTS steve_recommendation_feedback (
                id INTEGER PRIMARY KEY AUTOINCREMENT,
                session_id INTEGER NOT NULL,
                recommended_username TEXT NOT NULL,
                feedback TEXT NOT NULL CHECK(feedback IN ('up','down')),
                created_by TEXT NOT NULL,
                reasoning_text TEXT NULL,
                query_context TEXT NULL,
                created_at TEXT DEFAULT (datetime('now')),
                UNIQUE(session_id, recommended_username, created_by)
            )""")
        _sc.commit()

        # Migrate new columns for contextual feedback (safe for existing DBs)
        try:
            if USE_MYSQL:
                _scc.execute("ALTER TABLE steve_recommendation_feedback ADD COLUMN IF NOT EXISTS reasoning_text TEXT NULL")
                _scc.execute("ALTER TABLE steve_recommendation_feedback ADD COLUMN IF NOT EXISTS query_context TEXT NULL")
            else:
                # SQLite doesn't support IF NOT EXISTS on ALTER, so check first
                _scc.execute("PRAGMA table_info(steve_recommendation_feedback)")
                columns = [row[1] if hasattr(row, 'keys') else row[1] for row in _scc.fetchall()]
                if 'reasoning_text' not in columns:
                    _scc.execute("ALTER TABLE steve_recommendation_feedback ADD COLUMN reasoning_text TEXT")
                if 'query_context' not in columns:
                    _scc.execute("ALTER TABLE steve_recommendation_feedback ADD COLUMN query_context TEXT")
            _sc.commit()
        except Exception as mig_err:
            print(f"[STARTUP] Feedback table migration warning: {mig_err}", file=sys.stderr, flush=True)

    print("[STARTUP] Steve chat tables ensured", file=sys.stderr, flush=True)
except Exception as _se:
    print(f"[STARTUP] Steve chat table init warning: {_se}", file=sys.stderr, flush=True)

