@app.before_request
def _set_tenant_context():
    """Phase 2: Set tenant from header, subdomain, or custom domain."""
    from flask import g
    g.tenant_id = None
    g.tenant = None
    
    # 1. Check X-Tenant-Id header
    tid = request.headers.get('X-Tenant-Id')
    if tid:
        try:
            g.tenant_id = int(tid)
            return
        except (ValueError, TypeError):
            pass
    
    # 2. Check subdomain
    host = request.host.split(':')[0].lower()  # strip port
    app_domain = os.getenv('APP_DOMAIN', 'c-point.co').lower()
    reserved_subdomains = {'www', 'app', 'admin', 'api', 'staging'}
    
    if host.endswith('.' + app_domain):
        subdomain = host[:-len('.' + app_domain)]
        if subdomain and subdomain not in reserved_subdomains:
            try:
                with get_db_connection() as conn:
                    c = conn.cursor()
                    ph = get_sql_placeholder()
                    c.execute(f"SELECT id, name, subdomain FROM tenants WHERE subdomain = {ph}", (subdomain,))
                    row = c.fetchone()
                    if row:
                        g.tenant_id = row['id'] if hasattr(row, 'keys') else row[0]
                        g.tenant = {
                            'id': row['id'] if hasattr(row, 'keys') else row[0],
                            'name': row['name'] if hasattr(row, 'keys') else row[1],
                            'subdomain': row['subdomain'] if hasattr(row, 'keys') else row[2],
                        }
            except Exception as e:
                logger.debug(f"Tenant subdomain lookup failed for {subdomain}: {e}")

def _tenant_filter(column='tenant_id'):
    """Return SQL clause and params for tenant scoping.
    When g.tenant_id is set, returns (' AND {column} = ?', (g.tenant_id,)).
    When None (landlord), returns ('', ()).
    """
    from flask import g
    tid = getattr(g, 'tenant_id', None)
    if tid is not None:
        ph = get_sql_placeholder()
        return f' AND {column} = {ph}', (tid,)
    return '', ()

# Block unverified users from entering the app except for auth/static routes
@app.before_request
def _block_unverified_users():
    try:
        # Allow all OPTIONS preflight requests for CORS (critical for admin-web cross-origin calls)
        if request.method == 'OPTIONS':
            return None
        # Allow static and auth endpoints
        path = request.path or ''
        if path.startswith('/static') or path.startswith('/assets'):
            return None
        if path in ('/', '/welcome', '/login', '/login_password', '/signup', '/signup_react', '/verify_email', '/resend_verification', '/logout', '/verify_required', '/onboarding', '/resend_verification_pending'):
            return None
        # Allow login flow API endpoints (no auth required)
        if path in ('/api/check_pending_login', '/api/invitation/verify', '/api/clear_stale_session'):
            return None
        # Health and misc
        if path in ('/health', '/vite.svg', '/favicon.svg', '/manifest.webmanifest') or path.startswith('/icons/'):
            return None
        # API behavior: return JSON instead of HTML redirects to avoid client parse errors
        # Exception for public endpoints (no auth required)
        public_api_endpoints = [
            '/api/auth/google',  # Google Sign-In (no session yet)
            '/api/public/logo',  # Public logo (no auth, used by admin/landing)
            '/api/poll_notification_check', 
            '/api/event_notification_check', 
            '/api/content-generation/cron/process-due-jobs',
            '/api/email_verified_status', 
            '/api/invitation/verify',
            '/api/push/register_fcm',  # FCM token registration (can be anonymous initially)
            '/api/admin/login-by-email',  # Phase 2: tenant lookup by email (no auth)
            # Subscription-state webhooks: Stripe/Apple/Google never have a
            # session cookie. Each handler verifies its own signature.
            '/api/webhooks/stripe',
            '/api/webhooks/apple',
            '/api/webhooks/google',
        ]
        # Cron endpoints authenticate via X-Cron-Secret, not session cookies.
        # Cloud Scheduler cannot send cookies, so they must bypass this gate.
        if path.startswith('/api/cron/'):
            return None
        # Session required, but must run even if email not verified (logout cleanup)
        session_auth_unverified_ok = (
            '/api/push/unregister_fcm',
            '/api/push/unsubscribe_web',
        )
        if path.startswith('/api/') and path in session_auth_unverified_ok:
            if not session.get('username'):
                return jsonify({'success': False, 'error': 'unauthenticated'}), 401
            return None
        if path.startswith('/api/') and path not in public_api_endpoints:
            username = session.get('username')
            if not username:
                return jsonify({'success': False, 'error': 'unauthenticated'}), 401
            with get_db_connection() as conn:
                c = conn.cursor()
                c.execute("SELECT email_verified FROM users WHERE username=?", (username,))
                row = c.fetchone()
                verified = bool((row['email_verified'] if hasattr(row, 'keys') else row[0]) if row is not None else False)
            if not verified:
                return jsonify({'success': False, 'error': 'verify_required'}), 403
            return None
        # API that must remain accessible
        if path.startswith('/api/client_log'):
            return None
        # If not logged in, normal flow
        username = session.get('username')
        if not username:
            return None
        # Check email_verified
        with get_db_connection() as conn:
            c = conn.cursor()
            c.execute("SELECT email_verified FROM users WHERE username=?", (username,))
            row = c.fetchone()
            verified = bool((row['email_verified'] if hasattr(row, 'keys') else row[0]) if row is not None else False)
        if not verified:
            # Allow only verification related pages
            if path.startswith('/verify_email') or path == '/resend_verification' or path == '/resend_verification_pending':
                return None
            # Redirect to verification required page (React onboarding-friendly)
            return redirect(url_for('verify_required'))
    except Exception:
        return None

@app.route('/verify_required')
def verify_required():
    # Always serve the simple HTML page to avoid client-side routing confusion
    try:
        return render_template('verify_required.html')
    except Exception:
        return render_template('verify_required.html')

def generate_email_token(email: str) -> str:
    s = _get_serializer()
    return s.dumps({'email': email}, salt=VERIFICATION_TOKEN_SALT)

def verify_email_token(token: str):
    s = _get_serializer()
    try:
        data = s.loads(token, salt=VERIFICATION_TOKEN_SALT, max_age=VERIFICATION_TOKEN_MAX_AGE)
        return data.get('email')
    except SignatureExpired:
        return None
    except BadSignature:
        return None

def generate_pending_signup_token(pending_id: int, email: str) -> str:
    s = _get_serializer()
    return s.dumps({'pending_id': pending_id, 'email': email}, salt=PENDING_SIGNUP_TOKEN_SALT)

def verify_pending_signup_token(token: str):
    s = _get_serializer()
    try:
        data = s.loads(token, salt=PENDING_SIGNUP_TOKEN_SALT, max_age=VERIFICATION_TOKEN_MAX_AGE)
        pid = data.get('pending_id')
        email = data.get('email')
        if pid is None or not email:
            return None
        return {'pending_id': int(pid), 'email': email}
    except Exception:
        return None

def _build_verify_url(token: str) -> str:
    try:
        scheme = (CANONICAL_SCHEME or 'https')
    except Exception:
        scheme = 'https'
    try:
        host = CANONICAL_HOST or request.headers.get('Host') or ''
    except Exception:
        host = ''
    if not host:
        # Fallback to url_root parsing
        try:
            from urllib.parse import urlparse
            p = urlparse(request.url_root)
            host = p.netloc
            if p.scheme:
                scheme = p.scheme
        except Exception:
            pass
    return f"{scheme}://{host}/verify_email?token={token}"

def _send_email_via_resend(to_email: str, subject: str, html: str, text: str = None):
    if not RESEND_API_KEY:
        logger.error('RESEND_API_KEY not set; skipping email send')
        return False
    try:
        payload = {
            'from': EMAIL_FROM,
            'to': [to_email],
            'subject': subject,
            'html': html
        }
        if text:
            payload['text'] = text
        # Use requests to call Resend API (JSON body)
        r = requests.post(
            'https://api.resend.com/emails',
            headers={'Authorization': f'Bearer {RESEND_API_KEY}'},
            json=payload,
            timeout=15,
        )
        if r.status_code in (200, 201):
            logger.info('Resend email queued successfully')
            return True
        try:
            logger.error(f'Resend send failed: {r.status_code} {r.text}')
        except Exception:
            logger.error(f'Resend send failed with status {r.status_code}')
        return False
    except Exception as e:
        logger.error(f'Resend send exception: {e}')
        return False

