def _count_reply_views_excluding_admin(c, reply_id: int) -> int:
    try:
        ph = get_sql_placeholder()
        c.execute(
            f"SELECT COUNT(*) as cnt FROM reply_views WHERE reply_id = {ph} AND LOWER(username) <> LOWER({ph})",
            (reply_id, 'admin'),
        )
        row = c.fetchone()
        return int((row['cnt'] if hasattr(row, 'keys') else row[0]) if row else 0)
    except Exception:
        return 0


def upsert_reply_view(c, reply_id: int, username: Optional[str]) -> int:
    """Record a unique view for a reply and return the updated count."""
    ensure_reply_views_table(c)
    if not username or is_app_admin(username):
        return _count_reply_views_excluding_admin(c, reply_id)
    now_str = datetime.utcnow().strftime('%Y-%m-%d %H:%M:%S')
    try:
        if USE_MYSQL:
            c.execute("INSERT IGNORE INTO reply_views (reply_id, username, viewed_at) VALUES (%s,%s,%s)", (reply_id, username, now_str))
        else:
            c.execute("INSERT OR IGNORE INTO reply_views (reply_id, username, viewed_at) VALUES (?,?,?)", (reply_id, username, now_str))
    except Exception as e:
        logger.warning(f"Failed inserting reply_view for reply {reply_id}: {e}")
    return _count_reply_views_excluding_admin(c, reply_id)


# Optional: enforce canonical host (e.g., www.c-point.co) to prevent cookie splits
CANONICAL_HOST = os.getenv('CANONICAL_HOST')  # e.g., 'www.c-point.co'
CANONICAL_SCHEME = os.getenv('CANONICAL_SCHEME', 'https')

@app.before_request
def enforce_canonical_host():
    # Skip OPTIONS preflight requests (CORS) - redirects are not valid preflight responses
    if request.method == 'OPTIONS':
        return None
    try:
        req_host = request.headers.get('Host', '').split(':')[0]
        req_scheme = request.headers.get('X-Forwarded-Proto') or request.scheme
        # Enforce host
        if CANONICAL_HOST and req_host and req_host != CANONICAL_HOST:
            target = f"{CANONICAL_SCHEME}://{CANONICAL_HOST}{request.full_path}"
            if target.endswith('?'):
                target = target[:-1]
            return redirect(target, code=301)
        # Enforce https if configured
        if CANONICAL_SCHEME == 'https' and req_scheme != 'https' and req_host:
            target = f"https://{req_host}{request.full_path}"
            if target.endswith('?'):
                target = target[:-1]
            return redirect(target, code=301)
    except Exception:
        # Never block request on redirect failure
        return None

