def create_steve_welcome_post(cursor, community_id: int, new_member_username: str) -> Optional[int]:
    """
    Create a welcome post from Steve when a new member joins a community.
    Returns the post_id if successful, None otherwise.
    
    This function is safe to call - it catches all exceptions internally.
    """
    logger.info(f"[STEVE WELCOME] Called for user={new_member_username}, community={community_id}")
    
    try:
        # Don't create welcome posts for Steve himself or system users
        if not new_member_username or new_member_username.lower() in ['steve', 'admin', 'system']:
            logger.info(f"[STEVE WELCOME] Skipping - system user: {new_member_username}")
            return None
        
        ph = get_sql_placeholder()
        
        # First ensure Steve user exists (required for posts table foreign key)
        cursor.execute(f"SELECT id FROM users WHERE username = {ph}", ('steve',))
        steve_exists = cursor.fetchone()
        logger.info(f"[STEVE WELCOME] Steve user exists: {bool(steve_exists)}")
        
        if not steve_exists:
            # Create Steve user if it doesn't exist
            try:
                cursor.execute(f"""
                    INSERT INTO users (username, password, email, verified)
                    VALUES ({ph}, {ph}, {ph}, 1)
                """, ('steve', 'AI_USER_NO_LOGIN', 'steve@c-point.ai'))
                logger.info("[STEVE WELCOME] Created Steve AI user account")
            except Exception as create_err:
                # User might already exist (race condition) or other issue
                logger.warning(f"[STEVE WELCOME] Could not create Steve user: {create_err}")
        
        # Pick a random welcome message and personalize it
        welcome_template = random.choice(STEVE_WELCOME_MESSAGES)
        content = welcome_template.format(username=new_member_username)
        
        timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        
        logger.info(f"[STEVE WELCOME] Inserting post for community {community_id}")
        
        # Insert the welcome post from Steve
        # Note: posts table uses 'timestamp' column, not 'created_at'
        cursor.execute(f"""
            INSERT INTO posts (username, content, timestamp, community_id)
            VALUES ({ph}, {ph}, {ph}, {ph})
        """, ('steve', content, timestamp, community_id))
        
        post_id = cursor.lastrowid
        logger.info(f"[STEVE WELCOME] SUCCESS! Created post {post_id} for @{new_member_username} in community {community_id}")
        
        # Invalidate community feed cache so the welcome post appears immediately
        try:
            invalidate_community_cache(community_id)
            logger.info(f"[STEVE WELCOME] Invalidated cache for community {community_id}")
        except Exception as cache_err:
            logger.warning(f"[STEVE WELCOME] Failed to invalidate cache: {cache_err}")
        
        return post_id
        
    except Exception as e:
        # Log the full exception for debugging
        logger.error(f"[STEVE WELCOME] FAILED for {new_member_username} in community {community_id}: {e}", exc_info=True)
        return None


def add_user_to_community(cursor, user_id: int, community_id: int, role: Optional[str] = 'member', username: Optional[str] = None, skip_welcome_post: bool = False) -> None:
    """Insert a user into user_communities respecting free plan limits.
    
    Also invalidates the user's dashboard and community tree caches so they see
    the new community immediately without manual refresh.
    
    Args:
        cursor: Database cursor
        user_id: The user's ID
        community_id: The community ID to add the user to
        role: The user's role (default 'member')
        username: Optional username (used for cache invalidation and welcome posts)
        skip_welcome_post: If True, don't create a Steve welcome post (use for migrations, admin setup, etc.)
    """
    ensure_free_parent_member_capacity(
        cursor, community_id, attempted_username=username
    )
    # Paid community tier caps (Paid L1 / L2 / L3). Enterprise is
    # uncapped, Free is covered by the call above. Helper is a noop on
    # environments where the communities.tier column is not yet present.
    ensure_community_tier_member_capacity(
        cursor, community_id, attempted_username=username
    )
    joined_at_value = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
    if role is None:
        if USE_MYSQL:
            cursor.execute(
                """
                INSERT INTO user_communities (user_id, community_id, joined_at)
                VALUES (%s, %s, %s)
                """,
                (user_id, community_id, joined_at_value),
            )
        else:
            cursor.execute(
                """
                INSERT INTO user_communities (user_id, community_id, joined_at)
                VALUES (?, ?, ?)
                """,
                (user_id, community_id, joined_at_value),
            )
    else:
        if USE_MYSQL:
            cursor.execute(
                """
                INSERT INTO user_communities (user_id, community_id, role, joined_at)
                VALUES (%s, %s, %s, %s)
                """,
                (user_id, community_id, role, joined_at_value),
            )
        else:
            cursor.execute(
                """
                INSERT INTO user_communities (user_id, community_id, role, joined_at)
                VALUES (?, ?, ?, ?)
                """,
                (user_id, community_id, role, joined_at_value),
            )
    
    # Invalidate dashboard caches for everyone on this subtree (members, owners,
    # admins) so rollups/descriptions refresh; includes the joining user within
    # the same transaction/cursor snapshot.
    try:
        invalidate_dashboard_caches_for_community_subtree(
            int(community_id), cursor=cursor
        )
    except Exception as subtree_exc:
        logger.warning(
            "invalidate_dashboard_caches_for_community_subtree after join: %s",
            subtree_exc,
        )
        try:
            join_un = username
            if not join_un:
                ph_fb = get_sql_placeholder()
                cursor.execute(
                    f"SELECT username FROM users WHERE id = {ph_fb}",
                    (user_id,),
                )
                _jun = cursor.fetchone()
                if _jun:
                    join_un = (
                        _jun["username"]
                        if hasattr(_jun, "keys")
                        else _jun[0]
                    )
            if join_un:
                invalidate_user_cache(join_un)
        except Exception:
            pass

    # Enterprise seat lifecycle: if the community is tagged ``enterprise``,
    # open a seat for the joining user and (when they're on a mobile-IAP
    # Premium sub) start an in-app nag record so the client shows the
    # "cancel your Apple/Google sub" banner after the 7-day grace window.
    # Best-effort — never fail the join flow on a lifecycle hook error.
    try:
        from backend.services import enterprise_membership as _em
        from backend.services import enterprise_iap_nag as _nag
        from backend.services import subscription_audit as _audit
        if _em.is_enterprise_community(int(community_id)):
            join_username = username
            if not join_username:
                ph = get_sql_placeholder()
                cursor.execute(f"SELECT username FROM users WHERE id = {ph}", (user_id,))
                _row = cursor.fetchone()
                if _row:
                    join_username = _row['username'] if hasattr(_row, 'keys') else _row[0]
            if join_username:
                _em.start_seat(
                    username=join_username,
                    community_id=int(community_id),
                    source="community_join",
                    actor_username=join_username,
                )
                # If they already hold a personal Premium, open the nag.
                try:
                    ph = get_sql_placeholder()
                    cursor.execute(
                        f"SELECT subscription FROM users WHERE username = {ph}",
                        (join_username,),
                    )
                    _sr = cursor.fetchone()
                    _sub = (_sr['subscription'] if hasattr(_sr, 'keys') else (_sr[0] if _sr else '')) or ''
                    if str(_sub).lower() in ('premium', 'pro', 'paid'):
                        _nag.start_nag(username=join_username, community_id=int(community_id))
                        _audit.log(
                            username=join_username,
                            action="iap_conflict_detected",
                            source="community_join",
                            community_id=int(community_id),
                            metadata={"reason": "premium_plus_enterprise_seat"},
                        )
                except Exception:
                    logger.warning("[SEAT] IAP nag bootstrap failed (non-fatal)", exc_info=True)
    except Exception:
        logger.warning("[SEAT] start_seat hook failed (non-fatal)", exc_info=True)

    # Steve welcome posts disabled - community admins prefer to manage welcome messaging themselves
    if False and not skip_welcome_post and role not in ['owner', 'admin']:
        try:
            member_username = username
            if not member_username:
                ph = get_sql_placeholder()
                cursor.execute(f"SELECT username FROM users WHERE id = {ph}", (user_id,))
                row = cursor.fetchone()
                if row:
                    member_username = row['username'] if hasattr(row, 'keys') else row[0]
            if member_username:
                create_steve_welcome_post(cursor, community_id, member_username)
        except Exception as welcome_err:
            # Never fail the main operation due to welcome post issues
            logger.error(f"[ADD_USER] Failed to create Steve welcome post: {welcome_err}", exc_info=True)
    else:
        logger.info(f"[ADD_USER] Skipping welcome post: skip_welcome_post={skip_welcome_post}, role={role}")


def get_scalar_result(row, column_index=0, column_name=None):
    """Helper to get a scalar value from a database row that could be dict or tuple"""
    if row is None:
        return None
    if hasattr(row, 'keys'):  # Dict-like result (MySQL with DictCursor)
        if column_name:
            return row.get(column_name)
        # If no column name provided, try to get first value
        values = list(row.values())
        return values[column_index] if values else None
    else:  # Tuple/list result (SQLite)
        return row[column_index] if len(row) > column_index else None


def get_cached_countries() -> List[Dict[str, Any]]:
    now = time.time()
    cached = COUNTRY_CACHE
    if cached['data'] and (now - cached['timestamp']) < COUNTRY_CACHE_TTL:
        return cached['data']
    url = 'https://countriesnow.space/api/v0.1/countries/iso'
    try:
        req = urllib.request.Request(url, headers={'Accept': 'application/json'})
        with urllib.request.urlopen(req, timeout=8) as resp:
            payload = json.loads(resp.read().decode('utf-8'))
        data = []
        for item in payload.get('data', []):
            name = item.get('name')
            iso2 = item.get('Iso2') or item.get('iso2')
            if name:
                data.append({'name': name, 'iso2': iso2})
        if data:
            COUNTRY_CACHE['data'] = sorted(data, key=lambda x: x['name'])
            COUNTRY_CACHE['timestamp'] = now
            return COUNTRY_CACHE['data']
    except Exception as e:
        logger.warning(f"Failed to fetch countries remotely: {e}")
        logger.info(f"Using expanded fallback countries list with {len(FALLBACK_COUNTRIES)} countries (including Mexico)")
    COUNTRY_CACHE['data'] = FALLBACK_COUNTRIES
    COUNTRY_CACHE['timestamp'] = now
    return COUNTRY_CACHE['data']


def get_cached_cities(country_name: str) -> List[str]:
    if not country_name:
        return []
    key = country_name.strip().lower()
    now = time.time()
    cached = CITY_CACHE.get(key)
    if cached and (now - cached['timestamp']) < CITY_CACHE_TTL:
        return cached['data']
    url = 'https://countriesnow.space/api/v0.1/countries/cities'
    payload = json.dumps({'country': country_name}).encode('utf-8')
    try:
        req = urllib.request.Request(
            url,
            data=payload,
            headers={'Content-Type': 'application/json', 'Accept': 'application/json'}
        )
        with urllib.request.urlopen(req, timeout=10) as resp:
            result = json.loads(resp.read().decode('utf-8'))
        data = result.get('data') or []
        if isinstance(data, list) and data:
            sorted_data = sorted(dict.fromkeys([str(city) for city in data]))
            filtered = filter_major_cities(country_name, sorted_data)
            CITY_CACHE[key] = {'data': filtered, 'timestamp': now}
            return filtered
    except Exception as e:
        logger.warning(f"Failed to fetch cities for {country_name}: {e}")
    fallback = filter_major_cities(country_name, FALLBACK_CITY_MAP.get(key, []))
    CITY_CACHE[key] = {'data': fallback, 'timestamp': now}
    return fallback


def filter_major_cities(country_name: str, incoming: List[str]) -> List[str]:
    key = country_name.strip().lower()
    override = FALLBACK_CITY_MAP.get(key)
    if override:
        return override
    unique: List[str] = []
    seen: set[str] = set()
    for name in incoming:
        if not name:
            continue
        cleaned = str(name).strip()
        if not cleaned:
            continue
        lowered = cleaned.lower()
        if lowered in seen:
            continue
        seen.add(lowered)
        unique.append(cleaned)
        if len(unique) >= 24:
            break
    return unique

def ensure_database_exists():
    """Ensure the database and all tables exist."""
    try:
        db_path = os.path.join(os.path.dirname(os.path.abspath(__file__)), 'users.db')
        logger.info(f"Database path: {db_path}")
        
        # Connect to database (this will create it if it doesn't exist)
        conn = sqlite3.connect(db_path)
        c = conn.cursor()
        
        # Check if users table exists
        c.execute("SELECT name FROM sqlite_master WHERE type='table' AND name='users'")
        users_table_exists = c.fetchone() is not None
        
        if not users_table_exists:
            logger.info("Users table does not exist. Creating all tables...")
            init_db()
        else:
            logger.info("Users table exists. Checking for missing tables and columns...")
            # Always check for missing tables and columns
            add_missing_tables()
        
        conn.close()
        logger.info("Database check completed successfully")
        
    except Exception as e:
        logger.error(f"Error ensuring database exists: {e}")
        raise


