def ensure_paulo_member_of_gym():
    """Ensure user 'Paulo' is a member of the Gym community."""
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()

            # Find Paulo (case-insensitive)
            try:
                if USE_MYSQL:
                    c.execute(f"SELECT id, username FROM users WHERE LOWER(username)=LOWER({ph})", ('Paulo',))
                else:
                    c.execute(f"SELECT id, username FROM users WHERE LOWER(username)=LOWER({ph})", ('Paulo',))
                urow = c.fetchone()
                if not urow:
                    logger.info("Paulo user not found; skipping gym membership ensure")
                    return
                user_id = urow['id'] if hasattr(urow, 'keys') else urow[0]
            except Exception as e:
                logger.warning(f"Failed to find Paulo user: {e}")
                return

            # Find Gym community by name/type/community_type
            gym_id = None
            try:
                if USE_MYSQL:
                    c.execute("""
                        SELECT id FROM communities 
                        WHERE LOWER(name)='gym' OR LOWER(type)='gym' OR LOWER(COALESCE(community_type, ''))='gym'
                        ORDER BY id LIMIT 1
                    """)
                else:
                    c.execute("""
                        SELECT id FROM communities 
                        WHERE LOWER(name)='gym' OR LOWER(type)='gym' OR LOWER(COALESCE(community_type, ''))='gym'
                        ORDER BY id LIMIT 1
                    """)
                crow = c.fetchone()
                if crow:
                    gym_id = crow['id'] if hasattr(crow, 'keys') else crow[0]
            except Exception as e:
                logger.warning(f"Failed to find Gym community: {e}")
                return

            if not gym_id:
                logger.info("Gym community not found; skipping Paulo gym membership ensure")
                return

            # Ensure membership exists
            try:
                c.execute(f"SELECT 1 FROM user_communities WHERE user_id={ph} AND community_id={ph}", (user_id, gym_id))
                exists = c.fetchone() is not None
                if not exists:
                    try:
                        add_user_to_community(c, user_id, int(gym_id), role=None, skip_welcome_post=True)
                        conn.commit()
                        logger.info(f"Added Paulo (user_id={user_id}) to Gym community (id={gym_id})")
                    except CommunityMembershipLimitError:
                        logger.warning(f"Skipped adding Paulo to Gym community {gym_id} due to free-plan member limit.")
                else:
                    logger.info("Paulo is already a member of the Gym community")
            except Exception as e:
                logger.error(f"Failed to ensure Paulo gym membership: {e}")
    except Exception as e:
        logger.error(f"ensure_paulo_member_of_gym error: {e}")


def migrate_community_ownership_from_paulo_to_admin():
    """One-time migration: Move all community ownership from Paulo to Admin.
    
    This addresses the network profiling bias where Paulo's rich profile data
    was dominating every community he created. After this migration, Paulo
    will be treated purely as platform founder rather than community owner.
    """
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()
            
            logger.info("Starting community ownership migration from Paulo to Admin...")
            
            # Count communities owned by Paulo
            c.execute(f"SELECT COUNT(*) as cnt FROM communities WHERE creator_username = {ph}", ('Paulo',))
            paulo_count = c.fetchone()
            paulo_count = paulo_count['cnt'] if hasattr(paulo_count, 'keys') else paulo_count[0] if paulo_count else 0
            
            if paulo_count == 0:
                logger.info("No communities found owned by Paulo. Migration not needed.")
                return True
            
            logger.info(f"Found {paulo_count} communities owned by Paulo. Migrating to Admin...")
            
            # Update communities table
            c.execute(f"UPDATE communities SET creator_username = 'Admin' WHERE creator_username = {ph}", ('Paulo',))
            updated = c.rowcount
            logger.info(f"Updated {updated} communities to be owned by Admin")
            
            # Ensure Admin has admin role in these communities
            c.execute("""
                INSERT IGNORE INTO user_communities (user_id, community_id, role, joined_at)
                SELECT 
                    (SELECT id FROM users WHERE username = 'Admin'),
                    c.id,
                    'admin',
                    CURRENT_TIMESTAMP
                FROM communities c
                WHERE c.creator_username = 'Admin'
                AND NOT EXISTS (
                    SELECT 1 FROM user_communities uc 
                    WHERE uc.user_id = (SELECT id FROM users WHERE username = 'Admin')
                    AND uc.community_id = c.id
                )
            """)
            logger.info("Ensured Admin has admin role in migrated communities")
            
            conn.commit()
            logger.info("✅ Community ownership migration completed successfully")
            return True
            
    except Exception as e:
        logger.error(f"❌ Community ownership migration failed: {e}", exc_info=True)
        return False


