@app.route('/api/community_photos')
@login_required
def api_community_photos():
    """Get all photos from a community feed, grouped by date."""
    username = session.get('username')
    community_id = request.args.get('community_id', type=int)
    try:
        with get_db_connection() as conn:
            c = conn.cursor()

            # Check if user is a member of the community
            if not is_app_admin(username):
                c.execute("""
                    SELECT 1 FROM user_communities
                    JOIN users u ON user_communities.user_id = u.id
                    WHERE u.username = ? AND user_communities.community_id = ?
                    LIMIT 1
                """, (username, community_id))
                if not c.fetchone():
                    return jsonify({'success': False, 'error': 'Forbidden'}), 403

            # Get all posts and replies with images/videos from this community
            # Exclude posts hidden by the current user
            c.execute("""
                SELECT
                    p.id as post_id,
                    NULL as reply_id,
                    p.username,
                    p.content,
                    p.image_path,
                    p.video_path,
                    p.media_paths,
                    p.timestamp,
                    up.profile_picture
                FROM posts p
                LEFT JOIN user_profiles up ON p.username = up.username
                LEFT JOIN hidden_posts hp ON p.id = hp.post_id AND hp.username = ?
                WHERE p.community_id = ? AND hp.id IS NULL
                  AND (p.image_path IS NOT NULL AND p.image_path != '' OR p.video_path IS NOT NULL AND p.video_path != '' OR p.media_paths IS NOT NULL AND p.media_paths != '')

                UNION ALL

                SELECT
                    p.id as post_id,
                    r.id as reply_id,
                    r.username,
                    r.content,
                    r.image_path,
                    NULL as video_path,
                    NULL as media_paths,
                    r.timestamp,
                    up.profile_picture
                FROM posts p
                JOIN replies r ON p.id = r.post_id
                LEFT JOIN user_profiles up ON r.username = up.username
                LEFT JOIN hidden_posts hp ON p.id = hp.post_id AND hp.username = ?
                WHERE p.community_id = ? AND hp.id IS NULL
                  AND r.image_path IS NOT NULL AND r.image_path != ''
                ORDER BY timestamp DESC
            """, (username, community_id, username, community_id))

            posts_raw = c.fetchall()
            posts = [dict(row) for row in posts_raw]

            def _normalize_media_url(path):
                if not path: return None
                if path.startswith('http'): return path
                if path.startswith('/static') or path.startswith('/uploads'): return path
                if path.startswith('uploads/'): return '/' + path
                return f"/uploads/{path}"

            photos = []
            media_id = 0
            for post in posts:
                if hasattr(post, 'keys'):
                    post_id = post['post_id']
                    username_val = post['username']
                    image_path = post['image_path']
                    video_path = post.get('video_path')
                    media_paths_raw = post.get('media_paths')
                    timestamp = post['timestamp'] or ''
                else:
                    post_id = post[0]
                    username_val = post[2]
                    image_path = post[4]
                    video_path = post[5] if len(post) > 5 else None
                    media_paths_raw = post[6] if len(post) > 6 else None
                    timestamp = post[7] if len(post) > 7 else (post[5] if len(post) == 7 else '')

                # Process media_paths (grouped media)
                if media_paths_raw:
                    try:
                        import json as _json
                        paths = _json.loads(media_paths_raw) if isinstance(media_paths_raw, str) else media_paths_raw
                        if isinstance(paths, list):
                            for mp in paths:
                                url = _normalize_media_url(mp)
                                if url:
                                    media_id += 1
                                    is_video = any(mp.lower().endswith(ext) for ext in ('.mp4', '.mov', '.webm', '.m4v'))
                                    photos.append({
                                        'id': f"{post_id}_mp_{media_id}",
                                        'post_id': post_id,
                                        'reply_id': None,
                                        'username': username_val,
                                        'image_url': url,
                                        'type': 'video' if is_video else 'image',
                                        'created_at': timestamp,
                                    })
                    except Exception:
                        pass

                if image_path:
                    url = _normalize_media_url(image_path)
                    if url:
                        media_id += 1
                        photos.append({
                            'id': f"{post_id}_img_{media_id}",
                            'post_id': post_id,
                            'reply_id': None,
                            'username': username_val,
                            'image_url': url,
                            'type': 'image',
                            'created_at': timestamp,
                        })

                if video_path:
                    url = _normalize_media_url(video_path)
                    if url:
                        media_id += 1
                        photos.append({
                            'id': f"{post_id}_vid_{media_id}",
                            'post_id': post_id,
                            'reply_id': None,
                            'username': username_val,
                            'image_url': url,
                            'type': 'video',
                            'created_at': timestamp,
                        })

            photos.sort(key=lambda x: x['created_at'] or '', reverse=True)

            return jsonify({'success': True, 'photos': photos})

    except Exception as e:
        logger.error(f"Error in community_photos: {e}")
        return jsonify({'success': False, 'error': 'Failed to load photos'}), 500

@app.route('/api/community_posts_search')
@login_required
def api_community_posts_search():
    try:
        username = session.get('username')
        community_id = request.args.get('community_id', type=int)
        q = (request.args.get('q') or '').strip()
        if not community_id or not q:
            return jsonify({'success': False, 'error': 'community_id and q are required'}), 400
        token = q[1:] if q.startswith('#') else q
        if not token:
            return jsonify({'success': True, 'posts': []})
        with get_db_connection() as conn:
            c = conn.cursor()
            try:
                if not is_app_admin(username):
                    c.execute("""
                        SELECT 1 FROM user_communities uc
                        JOIN users u ON uc.user_id = u.id
                        WHERE u.username = ? AND uc.community_id = ?
                        LIMIT 1
                    """, (username, community_id))
                    if not c.fetchone():
                        return jsonify({'success': False, 'error': 'Forbidden'}), 403
            except Exception:
                pass
            like_arg = f"%#{token}%"
            c.execute(
                """
                SELECT id, username, content, timestamp
                FROM posts
                WHERE community_id = ? AND LOWER(content) LIKE LOWER(?)
                ORDER BY id DESC
                LIMIT 100
                """,
                (community_id, like_arg)
            )
            rows = c.fetchall()
            results = []
            for r in rows:
                rid = r['id'] if hasattr(r, 'keys') else r[0]
                ruser = r['username'] if hasattr(r, 'keys') else r[1]
                rcontent = r['content'] if hasattr(r, 'keys') else r[2]
                rts = r['timestamp'] if hasattr(r, 'keys') else r[3]
                snippet = (rcontent or '')
                if len(snippet) > 140:
                    snippet = snippet[:137] + '…'
                results.append({'id': rid, 'username': ruser, 'content': snippet, 'timestamp': rts})
            return jsonify({'success': True, 'posts': results})
    except Exception as e:
        logger.error(f"Error in community_posts_search: {e}")
        return jsonify({'success': False, 'error': 'Server error'}), 500

