# Admin helper: is_app_admin imported from backend.services.community


def is_app_admin_or_paulo(username: Optional[str]) -> bool:
    """Product/polls/group gates: global app admin or founding user Paulo."""
    if not username:
        return False
    if is_app_admin(username):
        return True
    return (username or "").strip().lower() == "paulo"


def user_is_member_of_community(username: str, community_id: int) -> bool:
    """Check if a user is a member of a specific community (including sub-communities)."""
    if not username or not community_id:
        return False
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()

            # Check direct membership
            c.execute(f"""
                SELECT 1 FROM user_communities uc
                JOIN users u ON uc.user_id = u.id
                WHERE u.username = {ph} AND uc.community_id = {ph}
            """, (username, community_id))
            if c.fetchone():
                return True

            # Check if it's a sub-community - get parent
            c.execute(f"SELECT parent_community_id FROM communities WHERE id = {ph}", (community_id,))
            row = c.fetchone()
            if row:
                parent_id = row['parent_community_id'] if hasattr(row, 'keys') else row[0]
                if parent_id:
                    c.execute(f"""
                        SELECT 1 FROM user_communities uc
                        JOIN users u ON uc.user_id = u.id
                        WHERE u.username = {ph} AND uc.community_id = {ph}
                    """, (username, parent_id))
                    return c.fetchone() is not None
            return False
    except Exception as e:
        logger.debug(f"Error checking membership for {username} in community {community_id}: {e}")
        return False


def _execute_steve_tool(tool_name: str, tool_args: dict, username: str) -> dict:
    """Execute a Steve platform tool with proper permission checking using community_id."""
    try:
        community_id = tool_args.get('community_id')
        if not community_id:
            return {"error": "community_id is required"}

        is_admin = is_app_admin(username)

        # Regular users can only access communities they belong to
        if not is_admin and not user_is_member_of_community(username, community_id):
            return {"error": f"You don't have access to community {community_id}. I can only help with communities you're a member of."}

        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()

            if tool_name == "get_community_info":
                c.execute(f"""
                    SELECT id, name, description, type, created_at
                    FROM communities WHERE id = {ph}
                """, (community_id,))
                row = c.fetchone()
                if row:
                    r = dict(row) if hasattr(row, 'keys') else {
                        'id': row[0], 'name': row[1], 'description': row[2],
                        'type': row[3], 'created_at': row[4]
                    }
                    # Count members
                    c.execute(f"SELECT COUNT(*) FROM user_communities WHERE community_id = {ph}", (community_id,))
                    member_count_row = c.fetchone()
                    member_count = member_count_row[0] if member_count_row else 0

                    return {
                        "community_id": r['id'],
                        "name": r['name'],
                        "description": r.get('description', ''),
                        "type": r.get('type'),
                        "member_count": member_count
                    }
                return {"error": "Community not found"}

            elif tool_name == "search_members":
                city = tool_args.get('city')
                industry = tool_args.get('industry')
                role = tool_args.get('role')

                query = f"""
                    SELECT DISTINCT u.username, u.first_name, u.last_name, u.city, u.country,
                           u.company, u.industry, u.role
                    FROM users u
                    JOIN user_communities uc ON u.id = uc.user_id
                    WHERE uc.community_id = {ph}
                """
                params = [community_id]

                if city:
                    query += f" AND LOWER(u.city) LIKE LOWER({ph})"
                    params.append(f"%{city}%")
                if industry:
                    query += f" AND LOWER(u.industry) LIKE LOWER({ph})"
                    params.append(f"%{industry}%")
                if role:
                    query += f" AND LOWER(u.role) LIKE LOWER({ph})"
                    params.append(f"%{role}%")

                query += " LIMIT 20"
                c.execute(query, params)
                rows = c.fetchall()

                members = []
                for row in rows:
                    r = dict(row) if hasattr(row, 'keys') else {
                        'username': row[0], 'first_name': row[1], 'last_name': row[2],
                        'city': row[3], 'country': row[4], 'company': row[5],
                        'industry': row[6], 'role': row[7]
                    }
                    members.append({
                        "username": r['username'],
                        "name": f"{r.get('first_name','')} {r.get('last_name','')}".strip() or r['username'],
                        "city": r.get('city'),
                        "country": r.get('country'),
                        "company": r.get('company'),
                        "industry": r.get('industry'),
                        "role": r.get('role')
                    })
                return {"members": members, "count": len(members)}

            elif tool_name == "get_member_profile":
                target_username = tool_args.get('username')
                if not target_username:
                    return {"error": "username is required"}

                c.execute(f"""
                    SELECT username, first_name, last_name, city, country,
                           company, industry, role, linkedin, professional_about
                    FROM users WHERE username = {ph}
                """, (target_username,))
                row = c.fetchone()
                if row:
                    r = dict(row) if hasattr(row, 'keys') else {k: v for k, v in zip(['username','first_name','last_name','city','country','company','industry','role','linkedin','professional_about'], row)}
                    return {
                        "username": r['username'],
                        "name": f"{r.get('first_name','')} {r.get('last_name','')}".strip(),
                        "location": f"{r.get('city','')}, {r.get('country','')}".strip(', '),
                        "company": r.get('company'),
                        "industry": r.get('industry'),
                        "role": r.get('role'),
                        "linkedin": r.get('linkedin'),
                        "bio": r.get('professional_about')
                    }
                return {"error": "User not found"}

            else:
                return {"error": f"Unknown tool: {tool_name}"}

    except Exception as e:
        logger.error(f"Error executing Steve tool {tool_name}: {e}", exc_info=True)
        return {"error": f"Internal error: {str(e)}"}


# Content filtering for objectionable content (Apple App Store requirement)
OBJECTIONABLE_WORDS = [
    # Profanity and slurs - basic list, can be expanded
    'fuck', 'shit', 'ass', 'bitch', 'bastard', 'damn', 'crap',
    'dick', 'cock', 'pussy', 'cunt', 'whore', 'slut', 'fag',
    'nigger', 'nigga', 'retard', 'spic', 'chink', 'kike',
    # Violence
    'kill yourself', 'kys', 'die', 'murder', 'rape',
    # Drugs
    'cocaine', 'heroin', 'meth',
]

# Compile regex patterns for efficient matching
OBJECTIONABLE_PATTERNS = [
    re.compile(r'\b' + re.escape(word) + r'\b', re.IGNORECASE) 
    for word in OBJECTIONABLE_WORDS
]

def check_content_for_objectionable_material(content):
    """
    Check content for objectionable material.
    Returns (is_clean, flagged_words) tuple.
    If is_clean is False, the content should be flagged or rejected.
    """
    if not content:
        return True, []
    
    flagged_words = []
    content_lower = content.lower()
    
    for i, pattern in enumerate(OBJECTIONABLE_PATTERNS):
        if pattern.search(content):
            flagged_words.append(OBJECTIONABLE_WORDS[i])
    
    # Also check for common obfuscation patterns
    obfuscation_patterns = [
        (r'f+u+c+k+', 'fuck'),
        (r's+h+i+t+', 'shit'),
        (r'f+[@4a]+g+', 'fag'),
        (r'n+[i1!]+g+', 'nig'),
        (r'k+y+s+', 'kys'),
    ]
    
    for pattern, word in obfuscation_patterns:
        if re.search(pattern, content_lower):
            if word not in flagged_words:
                flagged_words.append(word)
    
    is_clean = len(flagged_words) == 0
    return is_clean, flagged_words


def filter_objectionable_content(content):
    """
    Filter/censor objectionable content by replacing with asterisks.
    Returns the filtered content string.
    """
    if not content:
        return content
    
    filtered = content
    for pattern in OBJECTIONABLE_PATTERNS:
        filtered = pattern.sub(lambda m: '*' * len(m.group()), filtered)
    
    return filtered


def auto_flag_content_if_needed(post_id, content, username, community_id):
    """
    Automatically flag content if it contains objectionable material.
    Creates a report entry for admin review.
    """
    is_clean, flagged_words = check_content_for_objectionable_material(content)
    
    if not is_clean:
        try:
            with get_db_connection() as conn:
                c = conn.cursor()
                ph = '?' if not USE_MYSQL else '%s'
                
                # Create automatic report
                c.execute(f"""
                    INSERT INTO post_reports (post_id, reporter_username, reason, details, status)
                    VALUES ({ph}, {ph}, {ph}, {ph}, 'pending')
                """, (post_id, 'system', 'Auto-flagged: Objectionable content', 
                      f"Flagged words: {', '.join(flagged_words)}"))
                conn.commit()
                
                # Notify admin
                try:
                    create_notification('admin', 'system', 'content_flagged', post_id, community_id,
                                       f"⚠️ Post auto-flagged for objectionable content: {', '.join(flagged_words[:3])}",
                                       link='/admin_dashboard?tab=content_review')
                    send_push_to_user('admin', {
                        'title': 'Content Auto-Flagged',
                        'body': f'Post by @{username} flagged for: {", ".join(flagged_words[:3])}',
                        'url': '/admin_dashboard?tab=content_review',
                        'tag': f'auto-flag-{post_id}'
                    })
                except Exception as notif_err:
                    logger.warning(f"Failed to notify admin about auto-flagged content: {notif_err}")
                    
                logger.info(f"Auto-flagged post {post_id} for objectionable content: {flagged_words}")
        except Exception as e:
            logger.error(f"Error auto-flagging content: {e}")


