@app.route('/api/admin/steve_profiles', methods=['GET'])
@login_required
def admin_steve_profiles():
    """List all users with their existing Firestore profiles (no Grok calls).
    Tenant-aware: when g.tenant_id is set, only returns users in that tenant."""
    username = session.get('username')
    if not is_app_admin(username):
        return jsonify({'success': False, 'error': 'Unauthorized'}), 403

    try:
        from backend.services.firestore_reads import list_steve_user_profiles

        tf, tp = _tenant_filter('u.tenant_id')
        with get_db_connection() as conn:
            c = conn.cursor()
            c.execute(f"""
                SELECT u.username, COALESCE(p.display_name, u.username) AS display_name
                FROM users u
                LEFT JOIN user_profiles p ON u.username = p.username
                WHERE u.username NOT IN ('admin', 'steve'){tf}
                ORDER BY u.username
            """, tp)
            all_users = [
                {'username': (r['username'] if hasattr(r, 'keys') else r[0]),
                 'display_name': (r['display_name'] if hasattr(r, 'keys') else r[1])}
                for r in c.fetchall()
            ]

        fs_profiles = list_steve_user_profiles(limit=500)
        fs_map = {p['username']: p for p in fs_profiles}

        profiles = []
        for u in all_users:
            existing = fs_map.get(u['username'])
            raw_analysis = existing.get('analysis', {}) if existing else {}
            profiles.append({
                'username': u['username'],
                'display_name': u['display_name'],
                'analysis': _migrate_analysis_to_v3(raw_analysis) if raw_analysis else {},
                'lastUpdated': existing.get('lastUpdated') if existing else None,
                'profilingExternalSources': existing.get('profilingExternalSources') if existing else None,
            })

        return jsonify({'success': True, 'profiles': profiles, 'total': len(profiles)})
    except Exception as e:
        logger.error(f"Error in admin_steve_profiles: {e}", exc_info=True)
        return jsonify({'success': False, 'error': str(e)}), 500


def _execute_steve_profile_analysis(
    target_username: str,
    depth: str = 'standard',
    reset: bool = False,
    max_output_tokens_override: Optional[int] = None,
):
    """Run Grok Steve analysis for one user and persist to Firestore.
    Returns (success, payload, http_status). On success payload is dict with username and analysis.
    On failure payload is an error string and http_status is the suggested HTTP code."""
    try:
        from backend.services.firestore_writes import write_steve_user_profile
        from backend.services.firestore_reads import get_steve_user_profile

        if depth not in ('quick', 'standard', 'deep'):
            depth = 'standard'

        tf, tp = _tenant_filter('u.tenant_id')
        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()
            c.execute(f"""
                SELECT u.username, u.first_name, u.last_name,
                       u.role, u.company, u.industry, u.degree,
                       u.school, u.skills, u.linkedin, u.experience,
                       u.professional_about, u.professional_interests, u.professional_company_intel,
                       u.country, u.city,
                       p.display_name, p.bio AS profile_bio, p.location
                FROM users u
                LEFT JOIN user_profiles p ON u.username = p.username
                WHERE u.username = {ph}{tf}
            """, (target_username,) + tp)
            user = c.fetchone()

        if not user:
            return False, 'User not found', 404

        existing_profile = get_steve_user_profile(target_username)
        existing_analysis_early = _migrate_analysis_to_v3((existing_profile or {}).get('analysis', {})) or {}
        from backend.services.steve_profiling_gates import (
            collect_social_links_for_profiling,
            format_user_provided_social_block,
        )

        def _gv_user_row(key: str) -> str:
            try:
                val = user[key] if hasattr(user, 'keys') else None
                return (str(val).strip() if val else '')
            except Exception:
                return ''

        allow_norm, social_rows = collect_social_links_for_profiling(
            linkedin_sql=_gv_user_row('linkedin'),
            firestore_profile=existing_profile or {},
            existing_analysis=existing_analysis_early,
        )

        communities = _fetch_user_communities(target_username)
        onboarding_context = _fetch_onboarding_identity_context(target_username)

        activity = _fetch_user_recent_activity(target_username) if depth in ('standard', 'deep') else None
        profile_text = _build_profile_text_for_grok(
            user,
            communities=communities,
            activity=activity,
            onboarding_context=onboarding_context,
        )
        social_block = format_user_provided_social_block(social_rows)
        if social_block:
            profile_text = profile_text + "\n\n" + social_block

        profiling_external_sources_payload = None
        profiling_enriched_content_payload = None
        if depth in ('standard', 'deep'):
            try:
                from backend.services.steve_content_enrichment import enrich_shared_activity_for_profile

                enrich_block, ingest_errors, external_sources = enrich_shared_activity_for_profile(
                    activity or {}, depth, allowlist_normalized=allow_norm
                )
                profiling_external_sources_payload = {
                    'updatedAt': datetime.utcnow().isoformat() + 'Z',
                    'items': external_sources,
                }
                if enrich_block:
                    profile_text = profile_text + "\n\n" + enrich_block
                    profiling_enriched_content_payload = {
                        'updatedAt': datetime.utcnow().isoformat() + 'Z',
                        'text': enrich_block,
                    }
                if ingest_errors:
                    profile_text += (
                        "\n\n--- CONTENT INGESTION FAILURES (factual; do not invent content for these URLs) ---\n"
                    )
                    for row in ingest_errors:
                        profile_text += f"- {row.get('url', '')}: {row.get('error', '')}\n"
            except Exception as enrich_err:
                logger.warning("Steve content enrichment skipped for %s: %s", target_username, enrich_err)

        if not profile_text.strip():
            return False, 'No profile data to analyze', 400

        existing_analysis = existing_analysis_early
        prior_feedback = existing_analysis.get('_feedback', {})

        analysis = _analyze_profile_with_grok(
            target_username,
            profile_text,
            prior_feedback=prior_feedback,
            depth=depth,
            max_output_tokens_override=max_output_tokens_override,
        )
        if not analysis:
            return False, 'Grok analysis returned empty', 502

        if reset:
            if prior_feedback:
                analysis['_feedback'] = prior_feedback
            # Even on reset, preserve admin manual edits — these are authoritative
            _preserve_admin_data(existing_analysis, analysis)
            final = analysis
        else:
            final = _merge_analyses(existing_analysis, analysis)

        write_kwargs = dict(_get_steve_profiling_write_payloads(target_username))
        if profiling_external_sources_payload is not None:
            write_kwargs['profiling_external_sources'] = profiling_external_sources_payload
        if profiling_enriched_content_payload is not None:
            write_kwargs['profiling_enriched_content'] = profiling_enriched_content_payload
        write_steve_user_profile(
            target_username,
            analysis=final,
            **write_kwargs,
        )

        refreshed = get_steve_user_profile(target_username) or {}

        try:
            from backend.services.steve_knowledge_base import (
                USE_KNOWLEDGE_BASE_V1,
                schedule_knowledge_synthesis,
            )
            if USE_KNOWLEDGE_BASE_V1:
                schedule_knowledge_synthesis(target_username)
        except Exception as kb_err:
            logger.debug("Knowledge base synthesis trigger skipped for %s: %s", target_username, kb_err)

        return True, {
            'username': target_username,
            'analysis': final,
            'profilingExternalSources': refreshed.get('profilingExternalSources'),
        }, None
    except Exception as e:
        logger.error(f"_execute_steve_profile_analysis failed for {target_username}: {e}", exc_info=True)
        return False, str(e), 500


@app.route('/api/admin/steve_profiles/<target_username>/analyze', methods=['POST'])
@login_required
def admin_steve_profile_analyze(target_username):
    """Analyze a single user's profile with Grok on-demand.
    Tenant-aware: when g.tenant_id is set, verifies user belongs to that tenant."""
    username = session.get('username')
    if not is_app_admin(username):
        return jsonify({'success': False, 'error': 'Unauthorized'}), 403

    data = request.get_json(silent=True) or {}
    depth = data.get('depth', 'standard')
    if depth not in ('quick', 'standard', 'deep'):
        depth = 'standard'
    reset = data.get('reset', False)
    max_output_tokens_override = None
    if depth == 'deep':
        raw = data.get('max_output_tokens')
        if raw is not None:
            try:
                mo = int(raw)
                floor = STEVE_DEEP_MAX_OUTPUT_TOKENS
                ceil = STEVE_ADMIN_DEEP_MAX_OUTPUT_TOKENS_CEILING
                max_output_tokens_override = max(floor, min(mo, ceil))
            except (TypeError, ValueError):
                max_output_tokens_override = None

    ok, payload, err_status = _execute_steve_profile_analysis(
        target_username,
        depth=depth,
        reset=reset,
        max_output_tokens_override=max_output_tokens_override,
    )
    if not ok:
        return jsonify({'success': False, 'error': payload}), err_status
    return jsonify({'success': True, **payload})


