@app.route('/api/admin/steve_profiles/<target_username>/edit', methods=['POST'])
@login_required
def admin_steve_profile_edit(target_username):
    """Save manual edits to a Steve profile's professional or personal section.
    Body: { "section": "professional"|"personal", "content": "JSON string or object" }
    This allows admins to add missing experience (e.g. 7 years at Deloitte) that synthesis should prioritize."""
    username = session.get('username')
    if not is_app_admin(username):
        return jsonify({'success': False, 'error': 'Unauthorized'}), 403
    try:
        data = request.get_json(force=True) or {}
        section = data.get('section')
        content = data.get('content')

        if section not in ('professional', 'personal', 'links'):
            return jsonify({'success': False, 'error': 'section must be professional, personal, or links'}), 400
        if not content:
            return jsonify({'success': False, 'error': 'content is required'}), 400

        from backend.services.firestore_reads import get_steve_user_profile
        from backend.services.firestore_writes import write_steve_user_profile

        profile = get_steve_user_profile(target_username)
        if not profile:
            return jsonify({'success': False, 'error': 'Profile not found'}), 404

        analysis = profile.get('analysis', {})

        if section == 'professional':
            if 'professional' not in analysis:
                analysis['professional'] = {}
            if not isinstance(analysis['professional'], dict):
                analysis['professional'] = {}

            # Parse structured experience data from the frontend form
            experiences = []
            try:
                if isinstance(content, dict) and 'experiences' in content:
                    experiences = content['experiences']
                elif isinstance(content, str) and content.strip().startswith('{'):
                    import json
                    parsed = json.loads(content)
                    experiences = parsed.get('experiences', [])
                elif isinstance(content, list):
                    experiences = content
            except Exception:
                experiences = []

            if experiences and isinstance(experiences, list):
                # Full replacement: the frontend sends the complete list of experiences
                normalized = []
                for exp in experiences:
                    if isinstance(exp, dict) and (exp.get('company') or exp.get('title')):
                        normalized.append({
                            'company': exp.get('company', ''),
                            'title': exp.get('title', ''),
                            'role': exp.get('title', ''),
                            'dates': exp.get('dates', ''),
                            'period': exp.get('dates', ''),
                            'description': exp.get('description', ''),
                            'highlight': exp.get('description', ''),
                            '_source': 'admin_manual',
                        })
                analysis['professional']['careerHistory'] = normalized

            # Also store as manualEdits for KB synthesis to pick up
            if experiences and isinstance(experiences, list):
                analysis['professional']['manualEdits'] = [{
                    'experiences': experiences,
                    'editedBy': username,
                    'editedAt': datetime.utcnow().isoformat() + 'Z',
                    'type': 'structured_experience'
                }]
            analysis['professional']['_lastManualEdit'] = datetime.utcnow().isoformat() + 'Z'
            analysis['professional']['_editedBy'] = username

        elif section == 'links':
            if 'personal' not in analysis:
                analysis['personal'] = {}
            if not isinstance(analysis['personal'], dict):
                analysis['personal'] = {}

            verified_links = content.get('verifiedLinks') if isinstance(content, dict) else content
            if isinstance(verified_links, list):
                analysis['personal']['verifiedLinks'] = verified_links

            analysis['personal']['_lastManualEdit'] = datetime.utcnow().isoformat() + 'Z'
            analysis['personal']['_editedBy'] = username

        else:
            # Personal edits - simple text storage
            if 'personal' not in analysis:
                analysis['personal'] = {}
            if not isinstance(analysis['personal'], dict):
                analysis['personal'] = {}

            analysis['personal']['manualContext'] = content if isinstance(content, str) else str(content)
            analysis['personal']['_lastManualEdit'] = datetime.utcnow().isoformat() + 'Z'
            analysis['personal']['_editedBy'] = username

        write_steve_user_profile(
            target_username,
            analysis=analysis,
        )

        refreshed = get_steve_user_profile(target_username) or {}
        return jsonify({
            'success': True,
            'analysis': refreshed.get('analysis', {})
        })
    except Exception as e:
        logger.error(f"Error editing Steve profile for {target_username}: {e}", exc_info=True)
        return jsonify({'success': False, 'error': str(e)}), 500


