@app.route('/api/profile/ai_suggestions', methods=['GET'])
@login_required
def api_profile_ai_suggestions():
    """Return the logged-in user's AI-generated profile suggestions (user-visible sections only)."""
    username = session.get('username')

    def _no_cache(resp):
        resp.headers['Cache-Control'] = 'no-cache, no-store, must-revalidate'
        resp.headers['Pragma'] = 'no-cache'
        resp.headers['Expires'] = '0'
        return resp

    try:
        from backend.services.firestore_reads import get_steve_user_profile
        profile = get_steve_user_profile(username)
        if not profile or profile.get('username') != username:
            return _no_cache(jsonify({'success': True, 'suggestions': None}))
        analysis = _migrate_analysis_to_v3(profile.get('analysis', {}))
        if not analysis:
            return _no_cache(jsonify({'success': True, 'suggestions': None}))
        user_review = analysis.get('_userReview', {})
        filtered = {}
        for key in STEVE_USER_VISIBLE_SECTIONS:
            val = analysis.get(key)
            if val is not None and val != [] and val != {} and val != '':
                filtered[key] = val
        if not filtered:
            return _no_cache(jsonify({'success': True, 'suggestions': None, 'forUser': username}))
        return _no_cache(jsonify({
            'success': True,
            'suggestions': filtered,
            'forUser': username,
            'userReview': user_review,
            'acceptedSections': analysis.get('_acceptedSections', []),
        }))
    except Exception as e:
        logger.error(f"Error fetching AI suggestions for {username}: {e}", exc_info=True)
        return _no_cache(jsonify({'success': False, 'error': 'Server error'})), 500


@app.route('/api/profile/ai_review', methods=['POST'])
@login_required
def api_profile_ai_review():
    """User reviews AI-generated profile: accept/edit/dismiss sections.
    Body: { "status": "confirmed"|"edited"|"disputed", "acceptedSections": ["summary","companyIntel",...], "edits": {"summary": "new text",...} }"""
    username = session.get('username')
    try:
        data = request.get_json(force=True) or {}
        status = data.get('status', '')
        if status not in ('confirmed', 'edited', 'disputed'):
            return jsonify({'success': False, 'error': 'Invalid status'}), 400
        accepted_sections = data.get('acceptedSections', [])
        edits = data.get('edits', {})

        from backend.services.firestore_reads import get_steve_user_profile
        profile = get_steve_user_profile(username)
        if not profile or profile.get('username') != username:
            return jsonify({'success': False, 'error': 'No AI profile found'}), 404

        analysis = profile.get('analysis', {})
        analysis['_userReview'] = {
            'status': status,
            'at': datetime.utcnow().isoformat(),
            'acceptedSections': accepted_sections,
        }
        analysis['_acceptedSections'] = accepted_sections

        if edits and isinstance(edits, dict):
            if '_userEdits' not in analysis:
                analysis['_userEdits'] = {}
            for section, new_val in edits.items():
                if section in STEVE_USER_EDITABLE_SECTIONS:
                    analysis['_userEdits'][section] = new_val

        from backend.services.firestore_writes import write_steve_user_profile
        write_steve_user_profile(
            username,
            analysis=analysis,
            **_get_steve_profiling_write_payloads(username),
        )

        try:
            invalidate_user_cache(username)
        except Exception:
            pass

        return jsonify({'success': True})
    except Exception as e:
        logger.error(f"Error saving AI review for {username}: {e}", exc_info=True)
        return jsonify({'success': False, 'error': 'Server error'}), 500


STEVE_SELF_REFRESH_COOLDOWN_SECONDS = int(os.environ.get('STEVE_SELF_REFRESH_COOLDOWN_SECONDS', '86400'))
STEVE_SELF_REFRESH_COOLDOWN_SECONDS_FREE = int(
    os.environ.get('STEVE_SELF_REFRESH_COOLDOWN_SECONDS_FREE', str(STEVE_SELF_REFRESH_COOLDOWN_SECONDS))
)
STEVE_SELF_REFRESH_COOLDOWN_SECONDS_PREMIUM = int(os.environ.get('STEVE_SELF_REFRESH_COOLDOWN_SECONDS_PREMIUM', '21600'))
STEVE_SELF_ANALYZE_LOCK_SECONDS = int(os.environ.get('STEVE_SELF_ANALYZE_LOCK_SECONDS', '900'))
STEVE_STANDARD_MAX_OUTPUT_TOKENS = int(os.environ.get('STEVE_STANDARD_MAX_OUTPUT_TOKENS', '2400'))
STEVE_DEEP_MAX_OUTPUT_TOKENS = int(os.environ.get('STEVE_DEEP_MAX_OUTPUT_TOKENS', '4000'))
STEVE_ADMIN_DEEP_MAX_OUTPUT_TOKENS_CEILING = int(os.environ.get('STEVE_ADMIN_DEEP_MAX_OUTPUT_TOKENS_CEILING', '8192'))


def _steve_self_refresh_cooldown_seconds(username: str) -> int:
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            sub = fetch_user_subscription(c, username)
        if is_free_subscription(sub):
            return STEVE_SELF_REFRESH_COOLDOWN_SECONDS_FREE
        return STEVE_SELF_REFRESH_COOLDOWN_SECONDS_PREMIUM
    except Exception:
        return STEVE_SELF_REFRESH_COOLDOWN_SECONDS_FREE


def _steve_analysis_payload_json_safe(obj):
    """Recursively coerce Firestore-ish values to JSON-serializable primitives."""
    if obj is None or isinstance(obj, (bool, int, float, str)):
        return obj
    if isinstance(obj, dict):
        return {str(k): _steve_analysis_payload_json_safe(v) for k, v in obj.items()}
    if isinstance(obj, (list, tuple)):
        return [_steve_analysis_payload_json_safe(v) for v in obj]
    return str(obj)


# Sections shown on "What does Steve know about me" (user-facing); admin keeps full analysis in Firestore.
STEVE_USER_SELF_VIEW_SECTIONS = frozenset({'summary', 'identity', 'networkingValue', 'interests'})


@app.route('/api/profile/steve_analysis', methods=['GET'])
@login_required
def api_profile_steve_analysis():
    """Steve analysis for the logged-in user: no observations/traits, no profiling activity snapshots."""
    username = session.get('username')

    def _no_cache(resp):
        resp.headers['Cache-Control'] = 'no-cache, no-store, must-revalidate'
        resp.headers['Pragma'] = 'no-cache'
        resp.headers['Expires'] = '0'
        return resp

    try:
        from backend.services.firestore_reads import get_steve_user_profile, _ts_to_str

        cooldown_key = f"steve_self_refresh_cooldown:{username}"
        lock_key = f"steve_self_analyze_lock:{username}"
        can_refresh = cache.get(cooldown_key) is None
        in_progress = cache.get(lock_key) is not None
        _cd = _steve_self_refresh_cooldown_seconds(username)

        profile = get_steve_user_profile(username)
        if not profile or profile.get('username') != username:
            return _no_cache(jsonify({
                'success': True,
                'profile': None,
                'forUser': username,
                'canRequestRefresh': can_refresh,
                'analysisInProgress': in_progress,
                'refreshCooldownSeconds': _cd,
            }))

        analysis = dict(_migrate_analysis_to_v3(profile.get('analysis', {})) or {})
        analysis.pop('observations', None)
        analysis.pop('traits', None)
        filtered_analysis = {
            k: v for k, v in analysis.items()
            if k.startswith('_') or k in STEVE_USER_SELF_VIEW_SECTIONS
        }
        safe_profile = {
            'username': username,
            'analysis': filtered_analysis,
            'lastUpdated': _ts_to_str(profile.get('lastUpdated')),
            'profilingExternalSources': profile.get('profilingExternalSources'),
        }
        return _no_cache(jsonify({
            'success': True,
            'profile': _steve_analysis_payload_json_safe(safe_profile),
            'forUser': username,
            'canRequestRefresh': can_refresh,
            'analysisInProgress': in_progress,
            'refreshCooldownSeconds': _cd,
        }))
    except Exception as e:
        logger.error(f"Error in api_profile_steve_analysis for {username}: {e}", exc_info=True)
        return _no_cache(jsonify({'success': False, 'error': 'Server error'})), 500


@app.route('/api/profile/steve_request_refresh', methods=['POST'])
@login_required
def api_profile_steve_request_refresh():
    """Queue a standard-depth Steve re-analysis for the logged-in user (rate-limited)."""
    username = session.get('username')
    cooldown_key = f"steve_self_refresh_cooldown:{username}"
    lock_key = f"steve_self_analyze_lock:{username}"
    cd_sec = _steve_self_refresh_cooldown_seconds(username)

    if cache.get(lock_key):
        return jsonify({
            'success': False,
            'error': 'Analysis already in progress',
            'analysisInProgress': True,
        }), 409

    if cache.get(cooldown_key):
        return jsonify({
            'success': False,
            'error': 'Please wait before requesting another refresh',
            'retryAfterSeconds': cd_sec,
        }), 429

    cache.set(lock_key, '1', ttl=STEVE_SELF_ANALYZE_LOCK_SECONDS)
    cache.set(cooldown_key, '1', ttl=cd_sec)

    def _run():
        try:
            ok, _payload, _err = _execute_steve_profile_analysis(username, depth='standard', reset=False)
            if ok:
                try:
                    invalidate_user_cache(username)
                except Exception:
                    pass
        finally:
            cache.delete(lock_key)

    _threading.Thread(target=_run, daemon=True).start()
    return jsonify({
        'success': True,
        'queued': True,
        'message': 'Steve is updating your profile analysis. Refresh this page in a minute.',
    })


STEVE_PROFILE_SCHEMA_VERSION = 3

STEVE_DATA_SECTIONS = frozenset({
    'summary', 'identity', 'professional', 'personal',
    'interests', 'traits', 'observations',
    'networkingValue', 'conversationStarters',
    'dataQuality', 'analysisDepth',
})

STEVE_USER_VISIBLE_SECTIONS = frozenset({
    'summary', 'identity', 'professional', 'personal',
    'interests', 'networkingValue', 'conversationStarters',
})

