def _migrate_analysis_to_v3(analysis: dict) -> dict:
    """Migrate a legacy (v1/v2) analysis dict to the canonical v3 schema.
    Idempotent: if already v3, returns as-is."""
    if not analysis:
        return analysis
    if analysis.get('_schemaVersion') == STEVE_PROFILE_SCHEMA_VERSION:
        if 'notes' not in analysis:
            analysis['notes'] = ''
        return analysis

    v3 = {}

    v3['_schemaVersion'] = STEVE_PROFILE_SCHEMA_VERSION
    v3['summary'] = analysis.get('summary', '')
    v3['analysisDepth'] = analysis.get('analysisDepth', 'standard')
    v3['dataQuality'] = analysis.get('dataQuality', 'sparse')

    old_identity = analysis.get('identity') or {}
    v3['identity'] = {
        'roles': old_identity.get('roles') or [],
        'drivingForces': old_identity.get('drivingForces') or '',
        'bridgeInsight': old_identity.get('bridgeInsight') or '',
    }

    old_bg = analysis.get('background') or {}
    old_company = old_bg.get('company') or analysis.get('companyIntel') or {}
    old_role = old_bg.get('role') or analysis.get('roleContext') or {}
    old_location = old_bg.get('location')
    if isinstance(old_location, str):
        old_location = {'city': '', 'country': '', 'context': old_location}
    elif not isinstance(old_location, dict):
        loc_ctx = analysis.get('locationContext', '')
        old_location = {'city': '', 'country': '', 'context': loc_ctx} if loc_ctx else None

    old_web = analysis.get('webResearch') or analysis.get('personResearch') or {}

    v3['professional'] = {
        'company': old_company if old_company.get('name') or old_company.get('description') else None,
        'role': old_role if old_role.get('title') else None,
        'careerHistory': (analysis.get('professional', {}).get('careerHistory') or []) if isinstance(analysis.get('professional'), dict) else [],
        'education': old_bg.get('education'),
        'location': old_location,
        'webFindings': old_web.get('publicSummary', ''),
        'publications': [],
    }

    old_social = old_web.get('socialProfiles') or []
    v3['personal'] = {
        'socialProfiles': old_social if isinstance(old_social, list) else [],
        'interests': [],
        'lifestyle': '',
        'webFindings': old_web.get('additionalContext', ''),
        'publicPosts': analysis.get('publicContent') or [],
    }

    v3['webResearch'] = {
        'confidence': old_web.get('confidence', 'low'),
        'publicSummary': old_web.get('publicSummary', ''),
        'socialProfiles': old_social if isinstance(old_social, list) else [],
    } if old_web.get('publicSummary') else None

    raw_interests = analysis.get('interests') or {}
    migrated_interests = {}
    for k, v in raw_interests.items():
        if isinstance(v, dict):
            migrated_interests[k] = v
        else:
            migrated_interests[k] = {'score': float(v) if v else 0.5, 'source': 'platform', 'type': 'both'}
    v3['interests'] = migrated_interests

    v3['traits'] = analysis.get('traits') or []
    v3['observations'] = analysis.get('observations') or ''
    v3['networkingValue'] = analysis.get('networkingValue') or ''
    v3['notes'] = analysis.get('notes') or ''
    v3['conversationStarters'] = analysis.get('conversationStarters') or []

    for meta_key in ('_feedback', '_userReview', '_acceptedSections', '_userEdits'):
        if meta_key in analysis:
            v3[meta_key] = analysis[meta_key]

    return v3


def _linkedin_field_looks_like_profile_url(raw: Optional[str]) -> bool:
    """True when the user supplied a concrete LinkedIn member profile URL (not company/job pages)."""
    s = (raw or "").strip().lower()
    if not s:
        return False
    if "lnkd.in" in s:
        return True
    if "linkedin.com" not in s and not s.startswith("linkedin."):
        return False
    if any(p in s for p in ("/company/", "/school/", "/jobs/", "/posts/", "/feed/", "/pulse/")):
        return False
    return "/in/" in s or "/pub/" in s


def _career_entry_has_guessed_tenure(entry: dict) -> bool:
    """True if duration looks like an invented ~N years (not explicit dates)."""
    if not isinstance(entry, dict):
        return False
    d = (entry.get('duration') or '').strip()
    if d and '~' in d:
        return True
    if d and re.match(r'^~\s*\d', d):
        return True
    if d and re.match(r'^\d+\+?\s*years?\b', d, re.I):
        return True
    return False


def _career_preference_score(entry: dict) -> float:
    """Higher = better row to keep when deduping (prefer honest Unknown over guessed tenure)."""
    if not isinstance(entry, dict):
        return 0.0
    s = 0.0
    if not _career_entry_has_guessed_tenure(entry):
        s += 2.0
    p = (entry.get('period') or '').strip().lower()
    if p == 'unknown' or not p:
        s += 1.0
    elif '~' not in p:
        s += 0.5
    return s


def _normalize_company_loose(company: str) -> str:
    c = (company or '').lower().strip()
    c = re.sub(r'\s+', ' ', c)
    c = re.sub(r'\s*\([^)]*\)\s*', ' ', c)
    return re.sub(r'\s+', ' ', c).strip()


def _role_token_jaccard(role_a: str, role_b: str) -> float:
    def tok(s):
        s = re.sub(r'[^\w\s]', ' ', (s or '').lower())
        return {w for w in s.split() if len(w) > 2}

    ta, tb = tok(role_a), tok(role_b)
    if not ta or not tb:
        return 0.0
    return len(ta & tb) / len(ta | tb)


def _normalize_career_history_key(company: str, role: str) -> str:
    """Light normalization for dedup (format only, not semantic expansion)."""
    c = (company or '').lower().strip()
    r = (role or '').lower().strip()
    c = re.sub(r'\s+', ' ', c)
    r = re.sub(r'\s+', ' ', r)
    c = re.sub(r'\s*\([^)]{1,50}\)\s*$', '', c).strip()
    return f'{c}|||{r}'


def _collapse_career_history_near_duplicates(entries: list) -> list:
    """Within same employer (loose company match), drop near-duplicate roles; keep better tenure row.
    Admin-added entries (_source == 'admin_manual') are never removed."""
    if not entries or len(entries) < 2:
        return entries
    admin_indices = {i for i, e in enumerate(entries) if isinstance(e, dict) and e.get('_source') == 'admin_manual'}
    by_comp = {}
    for i, e in enumerate(entries):
        if not isinstance(e, dict):
            continue
        ck = _normalize_company_loose(e.get('company', ''))
        if ck:
            by_comp.setdefault(ck, []).append(i)
    remove = set()
    for _ck, idxs in by_comp.items():
        if len(idxs) < 2:
            continue
        keepers = []
        for i in idxs:
            if i in remove:
                continue
            e = entries[i]
            replaced = False
            for j, kidx in enumerate(keepers):
                if kidx in remove:
                    continue
                ke = entries[kidx]
                if _role_token_jaccard(e.get('role', ''), ke.get('role', '')) < 0.42:
                    continue
                # Never remove admin entries
                if i in admin_indices and kidx in admin_indices:
                    continue
                if kidx in admin_indices:
                    remove.add(i)
                    replaced = True
                    break
                if i in admin_indices:
                    remove.add(kidx)
                    keepers[j] = i
                    replaced = True
                    break
                se, sk = _career_preference_score(e), _career_preference_score(ke)
                if se > sk:
                    remove.add(kidx)
                    keepers[j] = i
                elif sk > se:
                    remove.add(i)
                else:
                    remove.add(max(i, kidx))
                replaced = True
                break
            if not replaced:
                keepers.append(i)
    return [e for i, e in enumerate(entries) if i not in remove]


def _preserve_admin_data(existing_analysis: dict, new_analysis: dict) -> None:
    """Copy admin-authored fields from existing analysis into new analysis (mutates new_analysis).

    Used by both the reset path and merge path to ensure manual edits,
    admin-added career entries, and personal context are never lost.
    """
    _ADMIN_KEYS = ('manualEdits', 'manualContext', '_lastManualEdit', '_editedBy')

    for section in ('professional', 'personal'):
        old_sec = existing_analysis.get(section)
        if not old_sec or not isinstance(old_sec, dict):
            continue
        if section not in new_analysis or not isinstance(new_analysis.get(section), dict):
            new_analysis[section] = {}
        for key in _ADMIN_KEYS:
            if key in old_sec and old_sec[key]:
                new_analysis[section][key] = old_sec[key]

    # Preserve admin-added career history entries
    old_pro = existing_analysis.get('professional') or {}
    old_career = old_pro.get('careerHistory') or []
    admin_entries = [e for e in old_career if isinstance(e, dict) and e.get('_source') == 'admin_manual']
    if admin_entries:
        new_pro = new_analysis.get('professional') or {}
        new_career = new_pro.get('careerHistory') or []
        new_analysis.setdefault('professional', {})['careerHistory'] = admin_entries + new_career


def _merge_career_history_lists(new_hist: list, old_hist: list) -> list:
    """Merge new Grok-discovered career entries with existing ones.

    Admin-added entries (_source == 'admin_manual') are ALWAYS preserved.
    Grok entries are matched by company+role; new ones are added, existing
    ones are updated only if the new version has better data (dates, highlights).
    """
    old_valid = [e for e in (old_hist or []) if isinstance(e, dict)]
    new_valid = [e for e in (new_hist or []) if isinstance(e, dict)]

    if not new_valid:
        return old_valid
    if not old_valid:
        return new_valid

    admin_entries = [e for e in old_valid if e.get('_source') == 'admin_manual']
    grok_old = [e for e in old_valid if e.get('_source') != 'admin_manual']

    old_keys = {}
    for e in grok_old:
        key = _normalize_career_history_key(e.get('company', ''), e.get('role', '') or e.get('title', ''))
        old_keys[key] = e

    merged_grok = dict(old_keys)
    for e in new_valid:
        key = _normalize_career_history_key(e.get('company', ''), e.get('role', '') or e.get('title', ''))
        existing = merged_grok.get(key)
        if not existing:
            loose_match = None
            for ok, oe in merged_grok.items():
                if (_normalize_company_loose(e.get('company', '')) == _normalize_company_loose(oe.get('company', ''))
                        and _role_token_jaccard(e.get('role', '') or e.get('title', ''), oe.get('role', '') or oe.get('title', '')) >= 0.42):
                    loose_match = ok
                    break
            if loose_match:
                existing = merged_grok[loose_match]
                new_score = _career_preference_score(e)
                old_score = _career_preference_score(existing)
                if new_score >= old_score:
                    merged_grok[loose_match] = e
            else:
                merged_grok[key] = e
        else:
            new_score = _career_preference_score(e)
            old_score = _career_preference_score(existing)
            if new_score >= old_score:
                merged_grok[key] = e

    result = admin_entries + list(merged_grok.values())
    return _collapse_career_history_near_duplicates(result)


def _merge_analyses(existing: dict, new: dict) -> dict:
    """Merge a new Grok analysis into an existing one, preserving richer data.

    Core principle: new data COMPLEMENTS existing — never drops fields that
    the new run simply didn't return.  Only overwrites a field when the new
    value is non-empty and at least as rich as the old one.
    """
    if not existing:
        return new
    if not new:
        return existing

    merged = dict(existing)

    DEPTH_RANK = {'quick': 0, 'standard': 1, 'deep': 2}

    for key in ('summary', 'observations', 'networkingValue', 'dataQuality'):
        new_val = new.get(key)
        if new_val and (not merged.get(key) or len(str(new_val)) >= len(str(merged.get(key, ''))) * 0.7):
            merged[key] = new_val

    if 'notes' in new:
        merged['notes'] = new['notes']

    if new.get('identity'):
        old_id = existing.get('identity') or {}
        new_id = new['identity'] or {}
        merged_id = dict(old_id)
        for k, v in new_id.items():
            if v:
                if k == 'roles' and isinstance(v, list):
                    old_roles = set(old_id.get('roles') or [])
                    merged_id['roles'] = list(old_roles | set(v))
                else:
                    merged_id[k] = v
        merged['identity'] = merged_id

    # Fields that are admin-authored and must NEVER be overwritten by Grok output
    _ADMIN_PROTECTED_KEYS = {'manualEdits', 'manualContext', '_lastManualEdit', '_editedBy', '_source'}

    if new.get('professional'):
        old_pro = existing.get('professional') or {}
        new_pro = new['professional'] or {}
        merged_pro = dict(old_pro)
        for k, v in new_pro.items():
            if k == 'careerHistory' or k in _ADMIN_PROTECTED_KEYS:
                continue
            if v and k not in merged_pro:
                merged_pro[k] = v
            elif v and k in merged_pro:
                old_v = merged_pro[k]
                if isinstance(v, str) and isinstance(old_v, str):
                    if len(v) >= len(old_v) * 0.7:
                        merged_pro[k] = v
                elif isinstance(v, list) and isinstance(old_v, list):
                    merged_pro[k] = v if len(v) >= len(old_v) else old_v
                elif isinstance(v, dict) and isinstance(old_v, dict):
                    merged_sub = dict(old_v)
                    merged_sub.update({sk: sv for sk, sv in v.items() if sv})
                    merged_pro[k] = merged_sub
                else:
                    merged_pro[k] = v
        old_history = old_pro.get('careerHistory') or []
        new_history = new_pro.get('careerHistory') or []
        merged_pro['careerHistory'] = _merge_career_history_lists(new_history, old_history)
        merged['professional'] = merged_pro

    if new.get('personal'):
        old_personal = existing.get('personal') or {}
        new_personal = new['personal'] or {}
        merged_personal = dict(old_personal)
        for k, v in new_personal.items():
            if k in _ADMIN_PROTECTED_KEYS:
                continue
            if v:
                old_v = merged_personal.get(k)
                if not old_v or (isinstance(v, str) and len(v) >= len(str(old_v)) * 0.7):
                    merged_personal[k] = v
                elif isinstance(v, (list, dict)):
                    merged_personal[k] = v
        merged['personal'] = merged_personal

    old_interests = existing.get('interests') or {}
    new_interests = new.get('interests') or {}
    combined = dict(old_interests)
    for k, v in new_interests.items():
        old_v = combined.get(k)
        if not old_v or (isinstance(v, dict) and v.get('score', 0) > (old_v.get('score', 0) if isinstance(old_v, dict) else 0)):
            combined[k] = v
    merged['interests'] = combined

    old_traits = set(existing.get('traits') or [])
    new_traits = set(new.get('traits') or [])
    merged['traits'] = list(old_traits | new_traits)

    if new.get('conversationStarters'):
        old_starters = set(existing.get('conversationStarters') or [])
        new_starters = set(new['conversationStarters'])
        merged['conversationStarters'] = list(old_starters | new_starters)

    old_depth = existing.get('analysisDepth', 'quick')
    new_depth = new.get('analysisDepth', 'quick')
    merged['analysisDepth'] = max(old_depth, new_depth, key=lambda d: DEPTH_RANK.get(d, 0))

    merged['_schemaVersion'] = STEVE_PROFILE_SCHEMA_VERSION

    for meta in ('_feedback', '_userReview', '_acceptedSections', '_userEdits'):
        if meta in existing and meta not in new:
            merged[meta] = existing[meta]

    return merged


def _fetch_user_communities(username: str) -> list:
    """Fetch the communities/networks a user belongs to."""
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()
            c.execute(f"""
                SELECT c.name, c.description, uc.role, c.type
                FROM user_communities uc
                JOIN users u ON uc.user_id = u.id
                JOIN communities c ON c.id = uc.community_id
                WHERE u.username = {ph}
                ORDER BY c.name
            """, (username,))
            rows = c.fetchall()
            return [dict(r) if hasattr(r, 'keys') else {'name': r[0], 'description': r[1], 'role': r[2], 'type': r[3]} for r in rows]
    except Exception as e:
        logger.debug(f"Could not fetch communities for {username}: {e}")
        return []


def _fetch_onboarding_identity_context(username: str) -> dict:
    """Fetch persisted onboarding identity signals from steve_onboarding."""
    try:
        from backend.blueprints.onboarding import _get_firestore_client

        db = _get_firestore_client()
        if not db:
            return {}
        doc = db.collection("steve_onboarding").document(username).get()
        if not doc.exists:
            return {}
        collected = (doc.to_dict() or {}).get("collected") or {}
        return {
            "talkAllDay": (collected.get("talkAllDay") or "").strip(),
            "reachOut": (collected.get("reachOut") or "").strip(),
            "recommend": (collected.get("recommend") or "").strip(),
            "journey": (collected.get("journey") or "").strip(),
        }
    except Exception as e:
        logger.debug(f"Could not fetch onboarding identity context for {username}: {e}")
        return {}


def _get_steve_profiling_write_payloads(username: str) -> dict:
    """Build Steve profiling payload kwargs for Firestore profile writes."""
    try:
        from backend.services.steve_profiling_snapshot import (
            build_steve_profiling_firestore_payloads,
        )

        profiling_platform_activity, profiling_shared_externals = (
            build_steve_profiling_firestore_payloads(username)
        )
        return {
            'profiling_platform_activity': profiling_platform_activity,
            'profiling_shared_externals': profiling_shared_externals,
        }
    except Exception as e:
        logger.debug(f"Could not build profiling write payloads for {username}: {e}")
        return {}


def _fetch_user_recent_activity(username: str, post_limit: int = 15, reply_limit: int = 10) -> dict:
    """Fetch a user's recent posts and replies for profile analysis.
    Only includes posts from the last 12 months for link-sharing / enrichment alignment."""
    import re as _re
    from datetime import datetime, timedelta
    URL_PATTERN = _re.compile(r'https?://[^\s<>"\')\]]+')
    cutoff_dt = datetime.utcnow() - timedelta(days=365)
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()

            c.execute(f"""
                SELECT p.id, p.content, p.timestamp, c.name AS community_name
                FROM posts p
                LEFT JOIN communities c ON p.community_id = c.id
                WHERE p.username = {ph} AND p.content IS NOT NULL AND TRIM(p.content) != ''
                  AND p.timestamp >= {ph}
                ORDER BY p.timestamp DESC
                LIMIT {int(post_limit)}
            """, (username, cutoff_dt))
            raw_posts = c.fetchall()

            c.execute(f"""
                SELECT r.content, r.timestamp, c.name AS community_name,
                       SUBSTRING(p.content, 1, 100) AS parent_snippet
                FROM replies r
                LEFT JOIN posts p ON r.post_id = p.id
                LEFT JOIN communities c ON r.community_id = c.id
                WHERE r.username = {ph} AND r.content IS NOT NULL AND TRIM(r.content) != ''
                  AND r.timestamp >= {ph}
                ORDER BY r.timestamp DESC
                LIMIT {int(reply_limit)}
            """, (username, cutoff_dt))
            raw_replies = c.fetchall()

        shared = []
        original = []
        for row in raw_posts:
            r = dict(row) if hasattr(row, 'keys') else {'id': row[0], 'content': row[1], 'timestamp': row[2], 'community_name': row[3]}
            content = (r.get('content') or '').strip()
            urls = URL_PATTERN.findall(content)
            entry = {
                'postId': r.get('id'),
                'content': content[:250],
                'date': (r.get('timestamp') or '')[:10],
                'community': r.get('community_name') or '',
            }
            if urls:
                entry['urls'] = urls[:3]
                entry['domains'] = [(urlparse(u).netloc or '').lower() for u in urls[:3] if (urlparse(u).netloc or '').lower()]
                shared.append(entry)
            else:
                original.append(entry)

        replies = []
        for row in raw_replies:
            r = dict(row) if hasattr(row, 'keys') else {'content': row[0], 'timestamp': row[1], 'community_name': row[2], 'parent_snippet': row[3]}
            replies.append({
                'content': (r.get('content') or '').strip()[:200],
                'date': (r.get('timestamp') or '')[:10],
                'community': r.get('community_name') or '',
                'replying_to': (r.get('parent_snippet') or '').strip()[:80],
            })

        return {'shared': shared, 'original': original, 'replies': replies}
    except Exception as e:
        logger.debug(f"Could not fetch activity for {username}: {e}")
        return {'shared': [], 'original': [], 'replies': []}


def _build_profile_text_for_grok(
    user_row,
    communities: list = None,
    activity: dict = None,
    onboarding_context: dict = None,
) -> str:
    """Assemble all available profile fields into a text block for Grok analysis."""
    def gv(key):
        try:
            val = user_row[key] if hasattr(user_row, 'keys') else None
            return (str(val).strip() if val else '')
        except Exception:
            return ''

    parts = []
    full_name = f"{gv('first_name')} {gv('last_name')}".strip()
    if full_name:
        parts.append(f"Full name: {full_name}")
    if gv('display_name'):
        parts.append(f"Display name: {gv('display_name')}")
    if gv('role'):
        parts.append(f"Role: {gv('role')}")
    if gv('company'):
        parts.append(f"Company: {gv('company')}")
    if gv('professional_company_intel'):
        parts.append(f"Company intel: {gv('professional_company_intel')}")
    if gv('industry'):
        parts.append(f"Industry: {gv('industry')}")
    if gv('skills'):
        parts.append(f"Skills: {gv('skills')}")
    if gv('degree'):
        parts.append(f"Degree: {gv('degree')}")
    if gv('school'):
        parts.append(f"School: {gv('school')}")
    if gv('experience'):
        parts.append(f"Years of experience: {gv('experience')}")
    if gv('professional_about'):
        parts.append(f"Professional about: {gv('professional_about')}")
    if gv('professional_interests'):
        parts.append(f"Declared interests: {gv('professional_interests')}")
    if gv('profile_bio'):
        parts.append(f"Bio: {gv('profile_bio')}")
    loc_parts = []
    if gv('city'):
        loc_parts.append(gv('city'))
    if gv('country'):
        loc_parts.append(gv('country'))
    if loc_parts:
        parts.append(f"Location: {', '.join(loc_parts)}")
    elif gv('location'):
        parts.append(f"Location: {gv('location')}")
    if gv('linkedin'):
        parts.append(f"LinkedIn: {gv('linkedin')}")

    if onboarding_context:
        if onboarding_context.get('talkAllDay'):
            parts.append(
                f"Onboarding - could talk all day about: {onboarding_context['talkAllDay']}"
            )
        if onboarding_context.get('reachOut'):
            parts.append(
                f"Onboarding - wants people to reach out about: {onboarding_context['reachOut']}"
            )
        if onboarding_context.get('journey'):
            parts.append(
                f"Onboarding - what the network should remember about their journey: {onboarding_context['journey']}"
            )
        if onboarding_context.get('recommend'):
            parts.append(
                f"Onboarding - recommendation for the network: {onboarding_context['recommend']}"
            )

    if communities:
        network_lines = []
        for comm in communities:
            name = comm.get('name', '')
            if not name:
                continue
            role = comm.get('role', '')
            desc = comm.get('description', '')
            line = name
            if role:
                line += f" (role: {role})"
            if desc:
                line += f" — {desc[:120]}"
            network_lines.append(line)
        if network_lines:
            parts.append(f"Networks/Communities: {'; '.join(network_lines)}")

    if activity:
        shared = activity.get('shared', [])
        original = activity.get('original', [])
        replies = activity.get('replies', [])

        if shared:
            parts.append("\n--- SHARED CONTENT (posts with links) ---")
            for p in shared[:10]:
                line = f"[{p.get('community', '?')}, {p.get('date', '?')}]"
                if p.get('urls'):
                    line += f" URL: {p['urls'][0]}"
                line += f" — \"{p['content']}\""
                parts.append(line)

        if original:
            parts.append("\n--- OWN THOUGHTS (text-only posts) ---")
            for p in original[:10]:
                parts.append(f"[{p.get('community', '?')}, {p.get('date', '?')}] \"{p['content']}\"")

        if replies:
            parts.append("\n--- REPLIES & COMMENTS ---")
            for r in replies[:8]:
                ctx = f" (replying to: \"{r['replying_to']}...\")" if r.get('replying_to') else ''
                parts.append(f"[{r.get('community', '?')}, {r.get('date', '?')}]{ctx} \"{r['content']}\"")

    return '\n'.join(parts)


def _analyze_profile_with_grok(
    username: str,
    profile_text: str,
    prior_feedback: dict = None,
    depth: str = 'standard',
    max_output_tokens_override: Optional[int] = None,
) -> dict:
    """Call Grok to analyze a user's profile. Returns v3 schema dict.
    depth: 'quick' (platform only), 'standard' (web_search: company intel + narrow scope),
    'deep' (web_search + x_search, full research)."""
    if not XAI_API_KEY:
        logger.warning("XAI_API_KEY not set, skipping profile analysis")
        return {}
    try:
        from openai import OpenAI
        client = OpenAI(api_key=XAI_API_KEY, base_url="https://api.x.ai/v1")
        today_str = datetime.utcnow().strftime('%Y-%m-%d')

        # Founder awareness is now handled consistently at BOTH individual profile
        # analysis AND network synthesis levels with proper founderInfo metadata.
        # No special USER_OVERRIDES or PAULO-SPECIFIC overrides are applied for
        # any user. The platform founder is treated neutrally as "Platform Architect".
        identity_override = ""

        community_internal_line = (
            "- You MAY use community names in your internal reasoning and web searches — just keep them out of the output."
            if depth in ('standard', 'deep')
            else "- You MAY use community names in your internal reasoning — just keep them out of the output."
        )
        shared_links_line = (
            """- SHARED CONTENT (posts with links): These URLs reveal the user's information diet and professional focus.
  When ENRICHED SHARED LINKS already includes text for a URL, prefer that over generic web search for that URL.
  Otherwise USE YOUR WEB SEARCH to visit/analyze each URL. Understand what the content is about and what sharing
  it says about the user's interests and expertise. The user's comment alongside the link adds critical context."""
            if depth in ('standard', 'deep')
            else """- SHARED CONTENT (posts with links): These URLs reveal the user's information diet and professional focus.
  This run does NOT include web_search: rely ONLY on ENRICHED SHARED LINKS excerpts when provided for a URL;
  do not claim you fetched or read URLs that were not prefetched. The user's comment alongside the link adds critical context."""
        )

        walled_social_carve_out = """
WALLED SOCIAL NETWORKS (CRITICAL):
- Do NOT use web_search to treat as authoritative or to browse member profiles on: LinkedIn, Instagram, TikTok, Snapchat, Facebook, Threads, or similar gated sites UNLESS that exact user-supplied URL appears in the "USER-PROVIDED SOCIAL" section of the input (if present).
- X/Twitter: on depth "deep" you may use the x_search tool without a user link. On "standard" depth, x_search is not available.
- For company websites, news, sports orgs, and open-web pages, web_search is allowed."""

        base_rules = f"""IMPORTANT RULES:
- Read the FULL text holistically. Understand tone, sarcasm, humor, and career context.
- There is no wall between personal and professional — build a UNIFIED picture of the whole person.
- If someone says "recovering lawyer turned developer", they are in TECH, not law.
- If a bio is humorous or vague, still extract what you can.
- Confidence scores (0.0–1.0) reflect YOUR confidence in the interest.
- If there is very little data, say so honestly and give fewer interests with lower confidence.
- Tag each interest as "professional", "personal", or "both".

COMMUNITY PRIVACY (CRITICAL):
- The "Networks/Communities" data is provided ONLY to help you disambiguate identity and understand context.
- NEVER mention specific community or network names in ANY output field (summary, webFindings, observations,
  interests, networkingValue, conversationStarters, traits, bridgeInsight, etc.).
- Instead use generic descriptions: "an MBA program", "a tech founders network", "an executive peer group",
  "a professional community", "a startup cohort", etc.
- This protects the exclusivity and privacy of private networks. Violating this is a critical failure.
{community_internal_line}

PLATFORM ACTIVITY (if provided):
- ENRICHED SHARED LINKS (if provided): Pre-fetched article text, YouTube transcripts, or audio transcriptions
  from URLs the user shared in the last 12 months. Treat this as PRIMARY evidence for what the linked content says.
  If CONTENT INGESTION FAILURES are listed, summarize them in "notes" and do not invent facts for those URLs.
{shared_links_line}
- OWN THOUGHTS (text-only posts): These reveal the user's voice — opinions, reflections, experiences, humor.
  Pay special attention to recurring themes.
- REPLIES & COMMENTS: These show what topics the user engages with and how they think. Look for patterns in what
  they respond to. **Pay special attention to cultural and slang nuances in native languages.** E.g. Portuguese
  "Hey Malta", "E aí malta", or similar phrases in group/professional contexts are colloquial for "Hey guys/folks"
  — not literal references to the country of Malta. Use thread context and user background to disambiguate and
  capture the true meaning in observations and InferredContext.
- Recent posts and comments matter more than older ones. If a user's activity shows a clear evolution, note it.
- REQUIREMENT: If platform activity is provided, you MUST incorporate specific themes, cultural context, and
  insights from posts, comments, and shared externals in your summary, observations, identity, and InferredContext.
  Platform activity is PRIMARY data — it shows what the user actually cares about RIGHT NOW. Do not ignore it."""

        research_rules_standard = f"""
STANDARD PROFILE RESEARCH (today is {today_str}):
- The user confirmed name, role, and company on-platform where provided. Use those as GROUND TRUTH; do not replace them from the web.
- Use web_search for: (1) COMPANY INTEL for the stated employer — description, sector, stage, news; (2) what the stated ROLE means in the context of that company and industry; (3) topics clearly evidenced in platform text, onboarding, or ENRICHED SHARED LINKS / article excerpts.
- Do NOT run the full wide-to-vertical personal sweep used in "deep" analysis. Do NOT chase every hobby thread unless it is tied to evidence in the input (platform, onboarding, enrichment).
- Do NOT use x_search at standard depth (tool not available).
- Set "personal" to null unless personal detail is explicit in platform input or USER-PROVIDED SOCIAL URLs.
- Keep webFindings and interests grounded; prefer fewer, higher-confidence interests over speculative breadth.
{walled_social_carve_out}
"""

        research_rules = ""
        if depth == 'standard':
            research_rules = research_rules_standard
        elif depth == 'deep':
            research_rules = f"""
WEB RESEARCH — TWO-PHASE STRATEGY (today is {today_str}):

PHASE 1 — CONFIRM IDENTITY (do this FIRST):
- Your strongest signals are: full name + location + community/network + LinkedIn URL + company.
- If a LinkedIn URL is provided, start there — that's a confirmed identity.
- Otherwise, combine the highest-signal data points in your search: "FirstName LastName [Company] [City]"
  or "FirstName LastName [Network name like Kellogg EMBA]". This is far more effective than a bare name search.
- NETWORK MEMBERSHIPS are powerful disambiguation signals. "Kellogg EMBA", "Harvard MBA", "YPO", "Techstars" etc.
  are highly specific. Use them in your queries.
- Once you find a match, VERIFY by cross-referencing at least 1-2 data points (company, city, school, network).
- Do NOT proceed to Phase 2 until you are confident you have the right person.
- If you cannot confidently identify the person, set professional.webFindings to "" and move on.

MULTILINGUAL RESEARCH STRATEGY (CRITICAL):
- 90% of professional information will likely be in English, but 10% of valuable insights may be in the user's native language
- This 10% is often crucial for building a holistic view of the person — don't ignore native language content
- For users with non-English names, locations, or communities, ALSO search in their likely native language
- Israeli/Hebrew names: Search using both English AND Hebrew spellings when possible
- Common Hebrew search patterns: "[HebrewName] סיקסט", "[HebrewName] מינכן", "[HebrewName] ישראל", "[HebrewName] תל אביב"
- Look for native language content on:
  * Local news sites and professional publications (Hebrew, Portuguese, German, Arabic, etc.)
  * Native language social media (Facebook, Instagram, X/Twitter in native script)
  * Personal blogs, Medium/Substack equivalents in native languages
- When you find non-English content, translate and summarize the key professional and personal insights in English
- Native language content often reveals more authentic personal interests, cultural context, local professional activities, family mentions, and unfiltered opinions that don't appear in English sources

PHASE 2 — BROAD DISCOVERY SWEEP (only after identity is confirmed):

Do an initial broad search to map out ALL facets of this person's life and career.
From your initial search results, identify every distinct THREAD — a thread is any domain,
career, hobby, skill, or life chapter you encounter. Examples of threads:
- A past career ("former professional pilot")
- A sport or hobby ("competitive glider", "marathon runner")
- An industry or expertise ("real estate investing", "AI startups")
- A life chapter ("military service", "lived in Singapore for 5 years")

PHASE 2b — FOLLOW EVERY THREAD (CRITICAL — do NOT skip this):

For EACH thread you discovered, run a DEDICATED follow-up search to get full detail.
This is the difference between a shallow profile and a rich one.

Example: if your broad search found "former professional pilot" mentioned in a bio:
- Search "[Name] pilot airline" → find the airline, role, dates
- Search "[Name] aviation" → find licenses, aircraft types, flight hours
- Search "[Name] glider" or "[Name] flying" → find related activities

Example: if you found "marathon runner":
- Search "[Name] marathon results" → find specific races, times, cities
- Search "[Name] running" → find clubs, Strava, ultra events

DO THIS FOR EVERY THREAD. Do not stop at the first mention. Chase it down.
Each thread should yield enough detail for a careerHistory entry (if professional)
or a rich interest entry (if personal/hobby).

COMPANY INTEL ENRICHMENT (CRITICAL — DO THIS FOR EVERY COMPANY IN careerHistory):

The careerHistory array will contain entries added by admins (marked with _source: "admin_manual"). These are HIGH-PRIORITY and AUTHORITATIVE signals.

For EVERY unique company appearing in the careerHistory array (including admin_manual ones):
- Use your web_search tool to gather rich company intelligence. Include:
  - Company description, mission, what they actually do at a high level
  - Sector, stage (seed, Series A/B/C, public, acquired, etc.)
  - Approximate size, growth trajectory, culture
  - Recent notable news or developments
  - Why this company would be relevant for networking with this person
- If you have already researched a company earlier in this analysis run, DO NOT search it again — reuse what you found (deduplicate by normalized company name).
- Put the richest company intel into the top-level professional.company object (for the person's current or most important role).
- For every careerHistory entry, enrich the "highlight" field with 1-2 sentences of specific company context that would be useful when networking ("Deloitte is a global professional services leader with deep expertise in financial services, strategy consulting, and digital transformation across 150+ countries...").

This is one of the highest-value things you can do with your tools. Admin-added companies should be treated as especially important signals.

PHASE 2c — STRUCTURE EVERYTHING YOU FOUND:

CAREER HISTORY RULES (ABSOLUTE):
- ANY mention of a past profession or role — even a one-liner like "former pilot" — MUST
  become a careerHistory entry. If details are incomplete, use "Unknown" for missing fields.
  Example: {{"role": "Professional Pilot", "company": "Unknown", "period": "Unknown", "highlight": "Mentioned as former professional pilot prior to current career"}}
- The careerHistory array MUST be ordered from most recent to oldest.
- Include the current role as the FIRST entry (with period ending in "present").
- Include ALL types: corporate, military, consulting, entrepreneurship, non-profit, board positions, aviation, sports careers, academic positions, government, etc.
- If LinkedIn shows 5 past roles, careerHistory should have at least 5 entries.
- For each entry, the "highlight" should note why it matters for networking.

TENURE AND DATES (STRICT — DO NOT HALLUCINATE TIME IN ROLE):
- Fill "period" and "duration" ONLY when a source states them EXPLICITLY (e.g. "2015–2019", "Jan 2020 – present",
  "3 years at Company X", LinkedIn-style start/end dates). Prefer copying the source wording for ranges.
- NEVER invent, estimate, or round to "~N years" to make an entry look complete. If dates are not stated in any source,
  set "period" to "Unknown" and omit "duration" OR set "duration" to "Unknown".
- In "highlight", add a brief provenance note when dates are known (e.g. "Dates from LinkedIn") or state that tenure was
  not found in public sources when period is Unknown.
- If two sources conflict on dates, prefer structured career profiles (e.g. LinkedIn) over generic articles; if still
  conflicting, use "Unknown" for period/duration and note the conflict briefly in "highlight".

OVERLAPPING ROLES (EXPECTED):
- People often hold multiple roles at the same time (e.g. board + operating role, MD of several entities, investor + advisor).
  Do NOT force a single non-overlapping timeline. Each distinct role gets its own careerHistory entry; overlapping
  date ranges are correct and encouraged when sources support them. Order entries from most recent primary role first,
  but do not drop concurrent roles to fix artificial chronology.

WHAT COUNTS AS A CAREER ENTRY:
- Any paid professional role (even if brief or unconventional)
- Military or national service
- Professional sports or competition careers (e.g. professional racing driver, professional pilot)
- Board memberships, advisory roles, side ventures
- Significant volunteer leadership roles

IDENTITY ROLES RULE:
- identity.roles MUST include every distinct profession, hobby, or life role found — past AND present.
  If someone was a pilot, is now an investor, races cars, and does competitive gliding:
  ["Investor", "Former Professional Pilot", "Racing Driver", "Competitive Glider Pilot", "EMBA Student"]
  Do NOT curate or limit to 3. Include them all.

INTERESTS STRUCTURING RULE (EQUALLY IMPORTANT AS CAREER HISTORY):
- ANY discovered hobby, sport, personal activity, or life interest MUST get an interests entry.
- The "source" field MUST contain the SPECIFIC DETAIL from your follow-up search — not a vague attribution.
  GOOD: "Gliding": {{"score": 0.9, "source": "Active competitive glider on weglide.org. 630km flight from Serres La Bâtie at 104km/h. 2025 European championship participant.", "type": "personal"}}
  BAD:  "Gliding": {{"score": 0.8, "source": "mentioned in social media", "type": "personal"}}
  GOOD: "Marathon running": {{"score": 0.85, "source": "Completed Berlin Marathon 2024 in 3:42, NYC Marathon 2023. Active Strava profile with 2000+ km/year.", "type": "personal"}}
  BAD:  "Marathon running": {{"score": 0.7, "source": "mentioned in bio", "type": "personal"}}
- The source field is WHERE THE VALUE IS. It powers downstream matching — "I want to meet someone
  who runs marathons" should match against "Berlin Marathon 2024 in 3:42", not "mentioned in bio".
- This applies to everything: book clubs, climbing, photography, wine, cooking, volunteering,
  parenting groups, religious activities, music — if you found it, chase the thread and capture the detail.

- Apply the multilingual research strategy above — don't limit yourself to English sources only.
- Only use publicly available information.

IDENTITY CONFIDENCE RULES (STRICT):
- "high": Found the person online AND at least 2 data points match (e.g. same company AND same city, or same network AND same role).
- "medium": Found the person online AND exactly 1 data point matches.
- "low": Found someone online but ZERO data points could be verified. A name-only match is ALWAYS "low".
- NEVER set confidence to "high" or "medium" based solely on a name match.
- A recognizable network membership (e.g. "Kellogg EMBA") counts as a corroborating data point when matched online.
{walled_social_carve_out}"""

        deep_rules = ""
        if depth == 'deep':
            deep_rules = f"""
PHASE 3 — PERSONAL & SOCIAL DEEP DIVE (today is {today_str}, only after Phase 1 identity is confirmed):
- You now know this person's full identity AND you've already discovered their key threads from Phase 2.
- For each personal/hobby thread discovered, run DEDICATED follow-up searches:
  Found "glider pilot"? → Search "[Name] gliding results", "[Name] weglide", "[Name] soaring"
  Found "marathon runner"? → Search "[Name] marathon [City]", "[Name] running results"
  Found "art collector"? → Search "[Name] art collection", "[Name] gallery"
- Check Instagram, Facebook, TikTok, X/Twitter, personal blogs, Medium, Substack, YouTube
- Apply the MULTILINGUAL RESEARCH STRATEGY — look for content in both English AND the user's native language
- The 10% of information in native languages is often the most authentic and revealing
- Hebrew/Israeli users often have rich personal content in Hebrew on Facebook, Instagram, and local Israeli platforms
- Native language personal content frequently reveals more authentic interests, cultural context, family life, local social circles, and unfiltered opinions that don't appear in English sources
- Note the DATE of every finding. Content from the last 6 months is highly relevant. >2 years old may be outdated.
- Look for PATTERNS that connect their personal and professional worlds.
  A marathon runner who works in health-tech. A parent who founded an ed-tech startup.
- Build a picture of who this person IS — not just what their job title says.
- If Phase 1 confidence was "low", do NOT attempt personal research — the risk of wrong person is too high."""

        professional_schema = """  "professional": {
    "company": {"name": "...", "description": "...", "sector": "...", "stage": "..."} or null,  # richest intel from the most important company in careerHistory
    "role": {"title": "...", "seniority": "junior|mid|senior|executive|founder", "function": "...", "implication": "1 sentence"} or null,
    "careerHistory": [
      {"company": "...", "role": "...", "period": "Explicit YYYY–YYYY or YYYY–present from a source, or Unknown if not stated", "duration": "ONLY if explicitly stated (e.g. 3 years); omit or Unknown — never guessed", "highlight": "Relevance for networking + enriched company context (sector, stage, culture, recent news)"}
    ] or [],
    "education": "degree + school if known, else null",
    "location": {"city": "...", "country": "...", "context": "1 sentence on local ecosystem relevance"} or null,
    "webFindings": "Narrative professional background summary tying together the full career arc. Emphasize current focus but connect it to foundational experiences." or "",
    "publications": [{"source": "...", "date": "YYYY-MM", "insight": "...", "relevance": "high|medium|low"}] or []
  },"""

        personal_schema = '  "personal": null,'
        if depth == 'deep':
            personal_schema = """  "personal": {
    "verifiedLinks": [{"platform": "LinkedIn", "url": "...", "notes": "Primary professional profile - use as canonical source"}] or [],
    "socialProfiles": [{"platform": "Instagram|Facebook|TikTok|X|Blog|YouTube", "url": "...", "handle": "..."}] or [],
    "interests": ["running", "cooking", "travel"],
    "lifestyle": "1-2 sentences on personal life indicators found publicly" or "",
    "webFindings": "personal web research summary (social media activity, personal content)" or "",
    "publicPosts": [{"source": "...", "date": "YYYY-MM", "insight": "...", "relevance": "high|medium|low"}] or []
  },"""

        starters_schema = ""
        if depth == 'deep':
            starters_schema = """  "conversationStarters": ["1-2 natural ice-breakers that connect personal + professional"],"""

        inference_engine = """HOLISTIC EXPERIENCE INFERENCE ENGINE (CRITICAL - APPLIES TO EVERY USER AND EVERY TYPE OF EXPERIENCE):

Move beyond listing facts. For every significant experience (professional role, geographic move, educational program, personal event, volunteer work, cultural exposure, etc.), perform deep, nuanced inference. Ask:

1. **Transformative Impact**: How did this change the person? What new perspectives, values, resilience, empathy, or worldviews did it create? (Example: 9 months in Angola = profound exposure to 3rd-world society → shifts in economic views, understanding of inequality, resilience, global citizenship, and empathy that influences all subsequent decisions).

2. **Strategic Intent**: What deliberate choice does this reveal about the person's ambition, direction, or priorities? (Example: Choosing a Kellogg EMBA (tier-1 American program) = intentional pivot toward US/North American markets, access to elite networks, signaling high ambition and fluency in Western business frameworks. This implies expertise in American-style strategy, entrepreneurship, and cross-cultural leadership).

3. **Capability & Credibility Signals**: What does this experience *actually confer* beyond the title? Be specific about skills, mindset, network, and credibility:
   - M&A: High-stakes negotiation, deal structuring, strategic foresight, investor relations, risk assessment under pressure, ability to see value creation opportunities.
   - Finance: Analytical rigor, quantitative thinking, capital allocation, risk management, understanding of economic cycles and incentives.
   - Software Engineering: Systems thinking, scalability mindset, technical credibility, ability to translate business problems into technical solutions, iteration and experimentation culture.

4. **Bridging & Uniqueness**: How does this experience connect different worlds (professional/personal, cultures, industries, socioeconomic backgrounds)? What rare combination of experiences makes this person unique? This should heavily inform bridgeInsight and UniqueFingerprint.

5. **Evolution & Trajectory**: How does this fit into the person's life/career arc? What opinion shifts, depth progression, or identity evolution does it reveal? Look for contradictions and tensions — they are often the most revealing.

Rules for all users:
- Be SPECIFIC, EVIDENCE-BASED, and NUANCED. Always tie inferences to concrete details from verifiedLinks, manualContext, manualEdits, enriched content, or platform activity.
- Be HOLISTIC. Connect professional, personal, geographic, cultural, educational, and volunteer experiences into a coherent identity narrative. No experience exists in isolation.
- Avoid generic statements. "Has finance experience" is weak. "Finance experience in emerging markets shaped a risk-tolerant, capital-efficient mindset that now informs platform building at C-Point" is powerful.
- For any experience, the core question is: "What does this *mean* about who this person is, what they bring to the table, and how they see the world?"
- This inference must flow into identity, observations, bridgeInsight, UniqueFingerprint, LifeCareer.stages, Expertise.credibilitySignals, and the overall Index synthesis.
- Founder awareness is handled consistently at both individual profile and network synthesis levels with proper founderInfo metadata. Treat the platform founder neutrally as "Platform Architect / Steve Creator" providing infrastructure. Focus on genuine patterns from all community members rather than letting any single profile dominate.

This engine is the core of building a rich, accurate member identity.
"""

        system_prompt = f"""You are an expert people analyst. Given a user's profile data from a private professional network, produce a structured JSON analysis that captures the WHOLE person.

{base_rules}

ADMIN MANUAL DATA AND USER APPROVED CONTENT — ABSOLUTE GROUND TRUTH (HIGHEST PRIORITY):

The input may contain:
- manualEdits and manualContext fields
- careerHistory entries with _source: "admin_manual"
- Social media links or other URLs added by the admin
- User approved content (from _userReview, _acceptedSections, or approved feedback)

These are AUTHORITATIVE. Treat them as highest-priority ground truth. They take precedence over public web sources.

RULES:
- Give EXTREMELY HIGH WEIGHT to this admin-provided and user-approved data when forming observations, making inferences, doing identity verification, and deciding what to search.
- Observations MUST be heavily grounded in and explicitly reference admin edits, added links, and user approved content.
- All inferences should flow from or be consistent with this authoritative data.
- When admin-added links or social profiles are present, use them as primary anchors for identity confirmation (Phase 1) and prioritize searching those specific profiles.
- If public sources conflict with admin edits or approved content, prioritize the admin/user-approved data and note the conflict in "notes".

{research_rules}
{deep_rules}

|{inference_engine}

Return ONLY valid JSON (no markdown, no code fences) with this exact structure:
{{
  "summary": "3-4 sentences capturing the whole person — who they are, what they do, what they care about",
  "identity": {{
    "roles": ["e.g. Fintech founder", "Marathon runner", "Father of two"],
    "drivingForces": "1-2 sentences: what motivates this person across all dimensions of life",
    "bridgeInsight": "1-2 sentences: how their personal and professional worlds connect"
  }},
{professional_schema}
{personal_schema}
  "interests": {{"topic_name": {{"score": 0.85, "source": "where you found this", "type": "professional|personal|both"}}, ...}},
  "traits": ["trait1", "trait2", "trait3"],
  "observations": "2-3 sentences of deeper insight — what makes this person tick. Ground these heavily in admin manual edits, added links, user approved content, and manualContext. Reference them explicitly.",
  "networkingValue": "1-2 sentences: what unique value they bring and what connections would benefit them",
  "notes": "If CONTENT INGESTION FAILURES appeared in the input, briefly list what could not be loaded or analyzed (e.g. paywall, transcript unavailable). Empty string if none.",
{starters_schema}
  "dataQuality": "rich|moderate|sparse",
  "analysisDepth": "{depth}"
}}

If the company or role fields are empty, set professional.company and professional.role to null.
If no location is provided, set professional.location to null.
If depth is "quick", set personal to null. If depth is "standard", set personal to null unless personal detail is explicit in the input or USER-PROVIDED SOCIAL URLs. If depth is "deep", populate personal when evidence supports it.
Set any field to null rather than guessing with no basis."""

        user_msg = f"Analyze this user's profile (@{username}):\n\n{profile_text}"
        if prior_feedback:
            rejected = {k: v for k, v in prior_feedback.items() if isinstance(v, dict) and v.get('status') == 'rejected'}
            if rejected:
                feedback_lines = []
                for section, fb in rejected.items():
                    note = fb.get('note', '')
                    feedback_lines.append(f"- {section}: REJECTED by admin" + (f" — reason: {note}" if note else ''))
                user_msg += "\n\nADMIN FEEDBACK FROM PREVIOUS ANALYSIS (sections marked as incorrect):\n"
                user_msg += '\n'.join(feedback_lines)
                user_msg += "\nPlease be extra careful with these sections."

            wrong_person = prior_feedback.get('wrongPerson')
            if wrong_person and isinstance(wrong_person, dict) and wrong_person.get('wrongData'):
                wd = wrong_person['wrongData']
                user_msg += "\n\n⚠️ WRONG PERSON ALERT — CRITICAL ANTI-TARGET DATA:\n"
                user_msg += "A previous analysis matched the WRONG individual. The following data is INCORRECT for this user.\n"
                user_msg += "You MUST NOT match this person to these details again:\n"
                if wd.get('name'):
                    user_msg += f"- WRONG name/person: {wd['name']}\n"
                if wd.get('company'):
                    user_msg += f"- WRONG company: {wd['company']}\n"
                if wd.get('urls'):
                    for url in wd['urls'][:5]:
                        user_msg += f"- WRONG URL (not this person): {url}\n"
                if wd.get('webFindings'):
                    user_msg += f"- WRONG web findings summary: {wd['webFindings'][:300]}\n"
                user_msg += "If your web search leads you back to these details, STOP and set confidence to 'low'.\n"
                user_msg += "Search for a DIFFERENT person with the same name. Use the platform profile data as your anchor."

        tools = []
        max_tokens = 1000
        if depth == 'standard':
            tools = [{"type": "web_search"}]
            max_tokens = STEVE_STANDARD_MAX_OUTPUT_TOKENS
        elif depth == 'deep':
            tools = [{"type": "web_search"}, {"type": "x_search"}]
            max_tokens = STEVE_DEEP_MAX_OUTPUT_TOKENS

        if max_output_tokens_override is not None and depth == 'deep':
            max_tokens = max_output_tokens_override

        create_kwargs = {
            "model": GROK_MODEL_MULTI_AGENT,
            "input": [
                {"role": "system", "content": system_prompt},
                {"role": "user", "content": user_msg}
            ],
            "max_output_tokens": max_tokens,
            "temperature": 0.3,
        }
        if tools:
            create_kwargs["tools"] = tools

        _t0 = time.perf_counter()
        response = client.responses.create(**create_kwargs)
        _elapsed_ms = int((time.perf_counter() - _t0) * 1000)
        _usage = getattr(response, "usage", None)
        try:
            logger.info(
                "steve_profile_grok username=%s depth=%s max_output_tokens=%s tools=%s ms=%s usage=%s",
                username,
                depth,
                max_tokens,
                tools,
                _elapsed_ms,
                _usage,
            )
        except Exception:
            pass
        raw = (response.output_text or '').strip() if hasattr(response, 'output_text') else ''
        if not raw:
            logger.warning(f"Grok returned empty response for {username}")
            return {}

        import json as _json
        if raw.startswith('```'):
            raw = raw.split('\n', 1)[-1].rsplit('```', 1)[0].strip()
        analysis = _json.loads(raw)

        for key in ('summary', 'observations', 'dataQuality', 'networkingValue', 'notes'):
            if key not in analysis:
                analysis[key] = ''
        if not isinstance(analysis.get('interests'), dict):
            analysis['interests'] = {}
        for k, v in list(analysis['interests'].items()):
            if not isinstance(v, dict):
                analysis['interests'][k] = {'score': float(v) if v else 0.5, 'source': 'platform', 'type': 'both'}
        if 'traits' not in analysis or not isinstance(analysis['traits'], list):
            analysis['traits'] = []
        if 'identity' not in analysis or not isinstance(analysis.get('identity'), dict):
            analysis['identity'] = {'roles': [], 'drivingForces': '', 'bridgeInsight': ''}
        if 'professional' not in analysis or not isinstance(analysis.get('professional'), dict):
            analysis['professional'] = None
        if 'personal' not in analysis or not isinstance(analysis.get('personal'), dict):
            analysis['personal'] = None
        if 'conversationStarters' not in analysis:
            analysis['conversationStarters'] = []

        analysis['_schemaVersion'] = STEVE_PROFILE_SCHEMA_VERSION
        analysis['analysisDepth'] = depth

        corroborating_fields = sum(1 for marker in ('Company:', 'Role:', 'School:', 'Location:', 'LinkedIn:', 'Industry:')
                                   if marker in profile_text)
        pro = analysis.get('professional') or {}
        web_findings = pro.get('webFindings', '')
        if web_findings and corroborating_fields < 2:
            logger.info(f"Low corroboration ({corroborating_fields} fields) for {username} — web findings may be unreliable")

        return analysis
    except Exception as e:
        logger.error(f"Grok profile analysis failed for {username}: {e}", exc_info=True)
        return {}


def _ensure_onboarding_identity(profile: dict, username: str) -> dict:
    """Return onboardingIdentity from the profile dict.  If missing, attempt lazy
    backfill from steve_onboarding and merge onto steve_user_profiles so future
    reads don't need the extra hop."""
    raw = profile.get('onboardingIdentity')
    if isinstance(raw, dict) and any((raw.get(k) or '').strip() for k in ('journey', 'talkAllDay', 'reachOut', 'recommend')):
        return raw

    fallback = _fetch_onboarding_identity_context(username)
    if not any(v for v in fallback.values()):
        return {}
    try:
        from backend.services.firestore_writes import merge_onboarding_identity_to_steve_profile
        merge_onboarding_identity_to_steve_profile(username, fallback)
    except Exception:
        pass
    return fallback


def _append_onboarding_identity_verbatim_from_profile(profile: dict, parts: list, username: str = '') -> None:
    """Append user-stated onboarding lines from steve_user_profiles.onboardingIdentity."""
    raw = _ensure_onboarding_identity(profile, username) if username else (profile.get('onboardingIdentity') or {})
    if not isinstance(raw, dict):
        return
    mapping = (
        ('journey', 'User-stated journey'),
        ('talkAllDay', 'Could talk all day about'),
        ('reachOut', 'Wants reach-outs about'),
        ('recommend', 'Recommends to network'),
    )
    for key, label in mapping:
        v = (raw.get(key) or '').strip()
        if v:
            parts.append(f"{label}: {v}")


def _format_onboarding_identity_for_networking_prompt(identity: dict) -> str:
    """Compact block for networking prompts from onboardingIdentity dict."""
    if not isinstance(identity, dict):
        return ''
    lines = []
    mapping = (
        ('journey', 'Journey (verbatim)'),
        ('talkAllDay', 'Could talk all day about'),
        ('reachOut', 'Wants reach-outs about'),
        ('recommend', 'Recommends'),
    )
    for key, label in mapping:
        v = (identity.get(key) or '').strip()
        if v:
            lines.append(f"- {label}: {v}")
    return '\n'.join(lines) if lines else ''


def _onboarding_identity_from_steve_profile(username: str) -> dict:
    try:
        from backend.services.firestore_reads import get_steve_user_profile
        p = get_steve_user_profile(username) or {}
        if p.get('username') != username:
            return {}
        ob = p.get('onboardingIdentity')
        return ob if isinstance(ob, dict) else {}
    except Exception:
        return {}


STEVE_CTX_CACHE_TTL = 600  # 10 minutes


def _build_context_from_profile(profile: dict, username: str, *, networking: bool = False, context_tier: str = "full") -> str:
    """Build a context string from a pre-loaded steve_user_profiles document.

    *context_tier* controls KB richness:
      - "full"  — all dimensions, all fields (deep 1:1 queries)
      - "mid"   — structured summary across all dimensions (~300-500 tokens)
      - "slim"  — 3 dimensions only (~100 tokens, large-roster fallback)

    The legacy *networking* flag maps to "slim" for backward compatibility.
    """
    if not profile:
        return ''

    if networking and context_tier == "full":
        context_tier = "slim"

    try:
        from backend.services.steve_knowledge_base import USE_KNOWLEDGE_BASE_V1
        if USE_KNOWLEDGE_BASE_V1:
            if context_tier == "slim":
                from backend.services.steve_knowledge_base import build_knowledge_context_slim
                slim = build_knowledge_context_slim(username)
                if slim:
                    return slim
            elif context_tier == "mid":
                from backend.services.steve_knowledge_base import build_knowledge_context_mid
                mid = build_knowledge_context_mid(username)
                if mid:
                    return mid
            else:
                from backend.services.steve_knowledge_base import build_knowledge_context_for_steve
                kb_context = build_knowledge_context_for_steve(username)
                if kb_context:
                    legacy = _build_legacy_context_from_profile(profile, username)
                    if legacy:
                        return f"[MEMBER KNOWLEDGE BASE — PREFERRED SOURCE]\n{kb_context}\n\n[LEGACY PROFILE — SUPPLEMENTARY]\n{legacy}"
                    return kb_context
    except Exception as e:
        logger.debug("Knowledge base context unavailable for %s: %s", username, e)

    return _build_legacy_context_from_profile(profile, username)


def _build_legacy_context_from_profile(profile: dict, username: str) -> str:
    """Build a context string from the legacy steve_user_profiles document."""
    if not profile:
        return ''
    analysis = _migrate_analysis_to_v3(profile.get('analysis', {}))
    has_summary = bool(analysis and analysis.get('summary'))

    parts = []
    if has_summary:
        parts.append(analysis['summary'])

        identity = analysis.get('identity') or {}
        if identity.get('bridgeInsight'):
            parts.append(identity['bridgeInsight'])
        if identity.get('drivingForces'):
            parts.append(f"Driving forces: {identity['drivingForces']}")
        if identity.get('roles'):
            parts.append(f"Roles: {', '.join(identity['roles'][:5])}")

        pro = analysis.get('professional') or {}
        co = pro.get('company') or {}
        if co.get('description'):
            parts.append(f"Company ({co.get('name','?')}): {co['description']} [{co.get('sector','')} / {co.get('stage','')}]")
        role = pro.get('role') or {}
        if role.get('implication'):
            parts.append(f"Role: {role.get('title','')} ({role.get('seniority','')}) — {role['implication']}")
        career = pro.get('careerHistory') or []
        if career:
            history_lines = []
            for entry in career[:8]:
                if not isinstance(entry, dict):
                    continue
                line = f"{entry.get('role', '?')} at {entry.get('company', '?')}"
                if entry.get('duration'):
                    line += f" ({entry['duration']})"
                elif entry.get('period'):
                    line += f" [{entry['period']}]"
                if entry.get('highlight'):
                    line += f" — {entry['highlight']}"
                history_lines.append(line)
            if history_lines:
                parts.append(f"Career history: {'; '.join(history_lines)}")
        loc = pro.get('location') or {}
        if loc.get('context'):
            parts.append(f"Location: {loc['context']}")
        if pro.get('webFindings'):
            parts.append(f"Professional background: {pro['webFindings']}")
        edu = pro.get('education')
        if edu:
            if isinstance(edu, list):
                edu_lines = []
                for e in edu[:5]:
                    if isinstance(e, dict):
                        edu_lines.append(f"{e.get('degree', '')} @ {e.get('institution', '')} {e.get('year', '')}".strip())
                    elif isinstance(e, str):
                        edu_lines.append(e)
                if edu_lines:
                    parts.append(f"Education: {'; '.join(edu_lines)}")
            elif isinstance(edu, str) and edu.strip():
                parts.append(f"Education: {edu.strip()}")

        personal = analysis.get('personal') or {}
        if personal.get('lifestyle'):
            parts.append(f"Personal: {personal['lifestyle']}")
        if personal.get('webFindings'):
            parts.append(f"Personal context: {personal['webFindings']}")
        public_posts = personal.get('publicPosts') or []
        if public_posts:
            recent = [p for p in public_posts if isinstance(p, dict) and p.get('relevance') in ('high', 'medium')][:3]
            if recent:
                parts.append('Recent activity: ' + '; '.join(p.get('insight', '') for p in recent if p.get('insight')))

        interests = analysis.get('interests') or {}
        if interests:
            top = sorted(interests.items(), key=lambda x: x[1].get('score', 0) if isinstance(x[1], dict) else 0, reverse=True)[:8]
            interest_frags = []
            for k, v in top:
                if not isinstance(v, dict):
                    continue
                frag = f"{k} ({int(v.get('score', 0)*100)}%)"
                src = (v.get('source') or '').strip()
                if src:
                    frag += f" [{src[:200]}]"
                interest_frags.append(frag)
            if interest_frags:
                parts.append('Interests: ' + '; '.join(interest_frags))

        traits = analysis.get('traits') or []
        if traits:
            parts.append('Traits: ' + ', '.join(traits[:4]))

        if analysis.get('networkingValue'):
            parts.append(f"Networking: {analysis['networkingValue']}")

        starters = analysis.get('conversationStarters') or []
        if starters:
            parts.append('Conversation starters: ' + '; '.join(starters[:4]))

        if analysis.get('observations'):
            parts.append(analysis['observations'])

    _append_onboarding_identity_verbatim_from_profile(profile, parts, username=username)

    if not parts:
        return ''
    return ' | '.join(parts)


def get_steve_context_for_user(username: str, viewer_username: str = None, _profile: dict = None) -> str:
    """Return a concise context string for Steve's system prompts.

    If *_profile* is provided (from a batch read), uses it directly instead
    of hitting Firestore.  Results (without viewer scrubbing) are cached in
    Redis for STEVE_CTX_CACHE_TTL seconds.
    """
    from redis_cache import cache
    cache_key = f"steve_ctx:{username}"

    try:
        cached = cache.get(cache_key)
        if cached is not None and isinstance(cached, str):
            result = cached
        else:
            if _profile is None:
                from backend.services.firestore_reads import get_steve_user_profile
                _profile = get_steve_user_profile(username)
            if not _profile or _profile.get('username') != username:
                return ''
            result = _build_context_from_profile(_profile, username)
            if result:
                cache.set(cache_key, result, STEVE_CTX_CACHE_TTL)

        if viewer_username and result:
            result = _scrub_community_names(result, username, viewer_username)
        return result
    except Exception as e:
        logger.debug(f"Could not load Steve profile for {username}: {e}")
        return ''


def invalidate_steve_context_cache(username: str):
    """Clear cached context string for a user. Call after profile analysis or onboarding merge."""
    try:
        from redis_cache import cache
        cache.delete(f"steve_ctx:{username}")
    except Exception:
        pass


def batch_get_steve_contexts(
    usernames: list,
    viewer_username: str = None,
) -> dict:
    """Build context strings for multiple users using a single Firestore
    batch read.  Returns {username: context_string}.
    """
    from redis_cache import cache
    from backend.services.firestore_reads import batch_get_steve_user_profiles

    results = {}
    to_fetch = []
    for u in usernames:
        cached = cache.get(f"steve_ctx:{u}")
        if cached is not None and isinstance(cached, str):
            results[u] = cached
        else:
            to_fetch.append(u)

    if to_fetch:
        profiles = batch_get_steve_user_profiles(to_fetch)
        for u in to_fetch:
            p = profiles.get(u)
            if p and p.get('username') == u:
                ctx = _build_context_from_profile(p, u)
                if ctx:
                    cache.set(f"steve_ctx:{u}", ctx, STEVE_CTX_CACHE_TTL)
                results[u] = ctx or ''
            else:
                results[u] = ''

    if viewer_username:
        for u in list(results.keys()):
            if results[u]:
                results[u] = _scrub_community_names(results[u], u, viewer_username)

    return results


def _scrub_community_names(text: str, target_username: str, viewer_username: str) -> str:
    """Remove references to community names that the viewer doesn't share with the target user.
    This is a safety net — Grok should already avoid naming communities in output."""
    try:
        target_communities = _fetch_user_communities(target_username)
        viewer_communities = _fetch_user_communities(viewer_username)

        target_names = {c.get('name', '') for c in target_communities if c.get('name')}
        viewer_names = {c.get('name', '') for c in viewer_communities if c.get('name')}
        private_names = target_names - viewer_names

        if not private_names:
            return text

        import re as _re
        # Longer names first so "Kellogg Global Network" replaces before "Kellogg"
        for name in sorted(private_names, key=len, reverse=True):
            if len(name) >= 3:
                text = _re.sub(_re.escape(name), 'a private network', text, flags=_re.IGNORECASE)
        return text
    except Exception:
        return text


def _trigger_background_profile_analysis(username: str):
    """Fetch user profile data from MySQL and run Grok analysis in a background thread.
    Skips if the profile was analyzed less than 10 minutes ago (debounce)."""
    def _run():
        try:
            from backend.services.firestore_reads import get_steve_user_profile
            from backend.services.firestore_writes import write_steve_user_profile

            existing = get_steve_user_profile(username)
            if existing and existing.get('username') == username and existing.get('lastUpdated'):
                from datetime import datetime, timezone
                last = existing['lastUpdated']
                if hasattr(last, 'timestamp'):
                    last_dt = last.replace(tzinfo=timezone.utc) if last.tzinfo is None else last
                else:
                    try:
                        last_dt = datetime.fromisoformat(str(last).replace('Z', '+00:00'))
                    except Exception:
                        last_dt = None
                if last_dt:
                    age_seconds = (datetime.now(timezone.utc) - last_dt).total_seconds()
                    if age_seconds < 60:
                        logger.info(f"Skipping profile analysis for {username}: analyzed {int(age_seconds)}s ago (debounce)")
                        return

            with get_db_connection() as conn:
                c = conn.cursor()
                ph = get_sql_placeholder()
                c.execute(f"""
                    SELECT u.username, u.first_name, u.last_name,
                           u.role, u.company, u.industry, u.degree,
                           u.school, u.skills, u.linkedin, u.experience,
                           u.professional_about, u.professional_interests, u.professional_company_intel,
                           u.country, u.city,
                           p.display_name, p.bio AS profile_bio, p.location
                    FROM users u
                    LEFT JOIN user_profiles p ON u.username = p.username
                    WHERE u.username = {ph}
                """, (username,))
                user = c.fetchone()

            if not user:
                logger.warning(f"Background analysis: user {username} not found")
                return

            communities = _fetch_user_communities(username)
            onboarding_context = _fetch_onboarding_identity_context(username)
            profile_text = _build_profile_text_for_grok(
                user,
                communities=communities,
                onboarding_context=onboarding_context,
            )
            if not profile_text.strip():
                logger.info(f"Background analysis: no profile data for {username}")
                return

            prior_feedback = (existing or {}).get('analysis', {}).get('_feedback', {})
            logger.info(f"Background profile analysis starting for {username}")
            analysis = _analyze_profile_with_grok(username, profile_text, prior_feedback=prior_feedback, depth='quick')
            # Background auto-trigger uses 'quick' depth — no activity fetch (saves tokens)
            if analysis:
                if prior_feedback:
                    analysis['_feedback'] = prior_feedback
                write_steve_user_profile(
                    username,
                    analysis=analysis,
                    **_get_steve_profiling_write_payloads(username),
                )
                logger.info(f"Background profile analysis completed for {username}")
            else:
                logger.warning(f"Background profile analysis returned empty for {username}")
        except Exception as e:
            logger.error(f"Background profile analysis failed for {username}: {e}", exc_info=True)

    _threading.Thread(target=_run, daemon=True).start()


