@app.route('/api/admin/add_user', methods=['POST'])
@login_required
def admin_add_user():
    """Add a new user as admin"""
    username = session.get('username')
    if not is_app_admin(username):
        return jsonify({'success': False, 'error': 'Unauthorized'}), 403
    
    data = request.get_json()
    new_username = data.get('username')
    new_password = data.get('password')
    subscription = data.get('subscription', 'free')
    
    if not new_username or not new_password:
        return jsonify({'success': False, 'error': 'Username and password required'}), 400
    
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            
            # Check if user already exists
            c.execute("SELECT 1 FROM users WHERE username = ?", (new_username,))
            if c.fetchone():
                return jsonify({'success': False, 'error': 'Username already exists'}), 400
            
            # Hash the password
            from werkzeug.security import generate_password_hash
            hashed_password = generate_password_hash(new_password)
            
            # Insert new user
            c.execute("""
                INSERT INTO users (username, password, subscription, created_at)
                VALUES (?, ?, ?, NOW())
            """, (new_username, hashed_password, subscription))
            
            conn.commit()
            return jsonify({'success': True})
            
    except Exception as e:
        logger.error(f"Error adding user: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

@app.route('/api/admin/compress_images', methods=['POST'])
@login_required
def admin_compress_images():
    """Admin-only: compress existing uploaded images on disk referenced by DB.
    Scans posts, replies, user profile pictures, community backgrounds, message photos.
    """
    username = session.get('username')
    if not is_app_admin(username):
        return jsonify({'success': False, 'error': 'Unauthorized'}), 403

    compressed = 0
    skipped = 0
    missing = 0
    errored = 0

    paths: set[str] = set()
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            for query in (
                "SELECT image_path FROM posts WHERE image_path IS NOT NULL AND image_path != ''",
                "SELECT image_path FROM replies WHERE image_path IS NOT NULL AND image_path != ''",
                "SELECT profile_picture FROM user_profiles WHERE profile_picture IS NOT NULL AND profile_picture != ''",
                "SELECT background_path FROM communities WHERE background_path IS NOT NULL AND background_path != ''",
                "SELECT image_path FROM messages WHERE image_path IS NOT NULL AND image_path != ''",
            ):
                try:
                    c.execute(query)
                    for row in c.fetchall():
                        try:
                            val = row[0] if not hasattr(row, 'keys') else list(row.values())[0]
                        except Exception:
                            # Fallback: handle mapping/dict-style
                            if hasattr(row, 'keys'):
                                val = next(iter(row.values()))
                            else:
                                val = None
                        if val:
                            paths.add(str(val))
                except Exception:
                    continue
    except Exception as e:
        logger.error(f"Error collecting image paths: {e}")
        return jsonify({'success': False, 'error': 'Failed to collect image paths'})

    base_dir = os.path.dirname(os.path.abspath(__file__))
    static_uploads = os.path.join(base_dir, 'static', 'uploads')
    root_uploads = os.path.join(base_dir, 'uploads')

    def resolve_path(p: str) -> str:
        clean = (p or '').replace('\r', '').replace('\n', '').strip('/')
        candidates = []
        if clean.startswith('uploads/'):
            candidates.append(os.path.join(base_dir, clean))
            candidates.append(os.path.join(static_uploads, clean.split('uploads/',1)[1]))
        else:
            candidates.append(os.path.join(static_uploads, clean))
            candidates.append(os.path.join(root_uploads, clean))
        for c in candidates:
            if os.path.exists(c):
                return c
        return candidates[0]

    for p in list(paths):
        disk_path = resolve_path(p)
        if not os.path.exists(disk_path):
            missing += 1
            continue
        try:
            before = os.path.getsize(disk_path)
            ok = optimize_image(disk_path, max_width=1280, quality=80)
            if ok:
                after = os.path.getsize(disk_path)
                compressed += 1
            else:
                skipped += 1
        except Exception as e:
            errored += 1
            logger.warning(f"Compress error {disk_path}: {e}")

    return jsonify({
        'success': True,
        'total_paths': len(paths),
        'compressed': compressed,
        'skipped': skipped,
        'missing': missing,
        'errored': errored,
    })




@app.route('/api/admin/add_user_to_community', methods=['POST'])
@login_required
def admin_add_user_to_community_api():
    """Add any user to any community/sub-community (admin only)."""
    if not is_app_admin(session.get('username')):
        return jsonify({'success': False, 'error': 'Unauthorized'}), 403
    data = request.get_json(silent=True) or {}
    user_id = data.get('user_id')
    community_id = data.get('community_id')
    if not user_id or not community_id:
        return jsonify({'success': False, 'error': 'user_id and community_id required'}), 400
    try:
        ph = get_sql_placeholder()
        with get_db_connection() as conn:
            c = conn.cursor()
            c.execute(f"SELECT username FROM users WHERE id={ph}", (int(user_id),))
            u = c.fetchone()
            if not u:
                return jsonify({'success': False, 'error': 'User not found'}), 404
            target_username = u['username'] if hasattr(u, 'keys') else u[0]
            c.execute(f"SELECT name FROM communities WHERE id={ph}", (int(community_id),))
            comm = c.fetchone()
            if not comm:
                return jsonify({'success': False, 'error': 'Community not found'}), 404
            comm_name = comm['name'] if hasattr(comm, 'keys') else comm[0]
            c.execute(f"SELECT 1 FROM user_communities WHERE user_id={ph} AND community_id={ph}", (int(user_id), int(community_id)))
            if c.fetchone():
                return jsonify({'success': False, 'error': f'{target_username} is already a member of {comm_name}'})
            add_user_to_community(c, int(user_id), int(community_id), role='member', username=target_username)
            conn.commit()
            return jsonify({'success': True, 'message': f'Added {target_username} to {comm_name}'})
    except CommunityMembershipLimitError as e:
        from backend.services.community import render_member_cap_error
        payload, status = render_member_cap_error(e, session_username=session.get('username'))
        return jsonify(payload), status
    except Exception as e:
        logger.error(f"admin_add_user_to_community error: {e}")
        return jsonify({'success': False, 'error': str(e)}), 500

