@app.route('/api/networking/steve_feedback', methods=['POST'])
@login_required
def api_steve_feedback():
    """Submit thumbs-up/down feedback on a recommended member with optional reasoning.

    Request: {session_id, recommended_username, feedback: 'up'|'down'|null, reasoning?: string}
    If feedback is null, removes the existing entry (un-click).
    """
    username = session.get('username')
    data = request.get_json() or {}
    session_id = data.get('session_id')
    rec_username = (data.get('recommended_username') or '').strip()
    feedback = data.get('feedback')
    reasoning = (data.get('reasoning') or '').strip() or None
    if not session_id or not rec_username:
        return jsonify({'success': False, 'error': 'session_id and recommended_username required'}), 400
    if feedback is not None and feedback not in ('up', 'down'):
        return jsonify({'success': False, 'error': 'feedback must be up, down, or null'}), 400
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()
            c.execute(f"SELECT id FROM steve_chat_sessions WHERE id = {ph} AND username = {ph}", (session_id, username))
            if not c.fetchone():
                return jsonify({'success': False, 'error': 'Session not found'}), 404
            if feedback is None:
                c.execute(f"DELETE FROM steve_recommendation_feedback WHERE session_id = {ph} AND recommended_username = {ph} AND created_by = {ph}", (session_id, rec_username, username))
            elif USE_MYSQL:
                c.execute(f"""INSERT INTO steve_recommendation_feedback 
                    (session_id, recommended_username, feedback, created_by, reasoning_text, query_context)
                    VALUES ({ph}, {ph}, {ph}, {ph}, {ph}, {ph})
                    ON DUPLICATE KEY UPDATE 
                    feedback = VALUES(feedback),
                    reasoning_text = VALUES(reasoning_text),
                    query_context = VALUES(query_context)""",
                    (session_id, rec_username, feedback, username, reasoning, None))
            else:
                c.execute(f"""INSERT INTO steve_recommendation_feedback 
                    (session_id, recommended_username, feedback, created_by, reasoning_text, query_context)
                    VALUES ({ph}, {ph}, {ph}, {ph}, {ph}, {ph})
                    ON CONFLICT(session_id, recommended_username, created_by) DO UPDATE SET 
                    feedback = excluded.feedback,
                    reasoning_text = excluded.reasoning_text,
                    query_context = excluded.query_context""",
                    (session_id, rec_username, feedback, username, reasoning, None))
            conn.commit()

            # Trigger contextual follow-up from Steve for negative feedback
            if feedback == 'down':
                try:
                    follow_up_text = f"Thanks for the feedback on @{rec_username}. Would you like to provide a bit more context on why they weren't the right match for your query? This helps me improve future recommendations."
                    c.execute(f"INSERT INTO steve_chat_messages (session_id, role, text) VALUES ({ph}, 'steve', {ph})", (session_id, follow_up_text))
                    conn.commit()
                except Exception as follow_err:
                    logger.warning(f"Failed to add Steve follow-up for feedback: {follow_err}")

        import threading
        def _aggregate(target_username):
            try:
                _aggregate_feedback_to_firestore(target_username)
            except Exception as e:
                logger.debug(f"Feedback aggregation failed for {target_username}: {e}")
        threading.Thread(target=_aggregate, args=(rec_username,), daemon=True).start()

        return jsonify({'success': True})
    except Exception as e:
        logger.error(f"Error saving steve feedback: {e}", exc_info=True)
        return jsonify({'success': False, 'error': 'Failed to save feedback'}), 500


def _aggregate_feedback_to_firestore(target_username: str):
    """Aggregate all feedback for a user into a net score on Firestore."""
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()
            c.execute(f"SELECT feedback, COUNT(*) as cnt FROM steve_recommendation_feedback WHERE recommended_username = {ph} GROUP BY feedback", (target_username,))
            ups = 0
            downs = 0
            for r in c.fetchall():
                fb = r['feedback'] if hasattr(r, 'keys') else r[0]
                cnt = r['cnt'] if hasattr(r, 'keys') else r[1]
                if fb == 'up':
                    ups = cnt
                elif fb == 'down':
                    downs = cnt
        net_score = ups - downs
        from backend.services.firestore_writes import _get_client as _get_fs
        fs = _get_fs()
        update_data = {
            'feedbackScore': net_score, 
            'feedbackUps': ups, 
            'feedbackDowns': downs
        }
        # TODO: In future iterations, also pull and store latest reasoning_text here for prompt injection
        fs.collection('steve_user_profiles').document(target_username).set(
            update_data,
            merge=True
        )
    except Exception as e:
        logger.warning(f"_aggregate_feedback_to_firestore failed for {target_username}: {e}")


@app.route('/audio_compat/<path:filename>')
def serve_audio_compat(filename):
    """
    Serve audio files with iOS compatibility.
    If the file is WebM and the request is from iOS, transcode to M4A.
    """
    try:
        logger.info(f"audio_compat: Request for {filename}")
        
        # Check if iOS device - be more permissive for Capacitor apps
        ua = request.headers.get('User-Agent', '')
        # Standard iOS indicators
        is_ios = 'iPhone' in ua or 'iPad' in ua or 'iPod' in ua
        # Also check for Safari on mobile (could be iOS WKWebView)
        is_ios = is_ios or ('Safari' in ua and 'Mobile' in ua and 'Android' not in ua)
        # Check for iOS WebKit (Capacitor uses WKWebView)
        is_ios = is_ios or ('AppleWebKit' in ua and 'Mobile' in ua and 'Android' not in ua)
        
        # Allow forcing transcoding via query parameter (for native apps)
        force_transcode = request.args.get('transcode', '').lower() in ('1', 'true', 'yes')
        
        logger.info(f"audio_compat: is_ios={is_ios}, force_transcode={force_transcode}, ua={ua[:100]}, filename={filename}")
        
        # Only transcode webm files for iOS (or if forced)
        if not (is_ios or force_transcode) or not filename.lower().endswith('.webm'):
            logger.info(f"audio_compat: No transcoding needed, redirecting to /uploads/{filename}")
            return redirect(f'/uploads/{filename}')
        
        # Find the original file
        base_dir = os.path.dirname(os.path.abspath(__file__))
        normalized = filename
        if normalized.startswith('uploads/'):
            normalized = normalized[8:]
        if normalized.startswith('voice_messages/'):
            pass  # Already correct path
        
        logger.info(f"audio_compat: Normalized path: {normalized}")
        
        # Check various locations
        possible_paths = [
            os.path.join(base_dir, 'uploads', normalized),
            os.path.join(base_dir, 'static', 'uploads', normalized),
            os.path.join(app.config.get('UPLOAD_FOLDER', 'uploads'), normalized),
        ]
        
        source_file = None
        for p in possible_paths:
            logger.info(f"audio_compat: Checking path: {p}")
            if os.path.exists(p):
                source_file = p
                logger.info(f"audio_compat: Found local file: {p}")
                break
        
        # If not found locally, check R2
        if not source_file:
            r2_public_url = os.environ.get('CLOUDFLARE_R2_PUBLIC_URL', '')
            logger.info(f"audio_compat: File not found locally, R2 URL: {r2_public_url}")
            if r2_public_url:
                # Try multiple R2 URL patterns
                r2_urls_to_try = [
                    f"{r2_public_url}/{normalized}",
                    f"{r2_public_url}/uploads/{normalized}",
                    f"{r2_public_url}/{filename}",
                ]
                
                for r2_url in r2_urls_to_try:
                    try:
                        logger.info(f"audio_compat: Trying R2 URL: {r2_url}")
                        resp = requests.get(r2_url, timeout=30, stream=True)
                        if resp.status_code == 200:
                            # Save to temp file
                            with tempfile.NamedTemporaryFile(suffix='.webm', delete=False) as tmp:
                                for chunk in resp.iter_content(chunk_size=8192):
                                    tmp.write(chunk)
                                source_file = tmp.name
                            logger.info(f"audio_compat: Downloaded from R2 to {source_file}")
                            break
                        else:
                            logger.info(f"audio_compat: R2 returned {resp.status_code} for {r2_url}")
                    except Exception as e:
                        logger.error(f"audio_compat: Failed to download from R2 {r2_url}: {e}")
        
        if not source_file:
            logger.warning(f"audio_compat: Source file not found anywhere: {filename}")
            return redirect(f'/uploads/{filename}')
        
        # Create transcoded M4A file
        try:
            with tempfile.NamedTemporaryFile(suffix='.m4a', delete=False) as tmp_out:
                output_file = tmp_out.name
            
            # Transcode using ffmpeg with iOS-compatible settings
            # Use native AAC encoder for best iOS compatibility
            cmd = [
                'ffmpeg', '-y',
                '-hide_banner',     # Less verbose output
                '-loglevel', 'warning',
                '-i', source_file,
                '-vn',              # No video
                '-c:a', 'aac',      # AAC audio codec
                '-b:a', '128k',     # Audio bitrate  
                '-ar', '44100',     # Sample rate (44.1kHz is standard)
                '-ac', '2',         # Stereo
                '-f', 'ipod',       # Force iPod/iPhone compatible M4A format
                output_file
            ]
            logger.info(f"audio_compat: Running ffmpeg: {' '.join(cmd)}")
            result = subprocess.run(cmd, capture_output=True, timeout=60)
            
            if result.returncode != 0:
                stderr_msg = result.stderr.decode('utf-8', errors='replace')[:500]
                logger.error(f"audio_compat: ffmpeg failed with code {result.returncode}: {stderr_msg}")
                # Cleanup temp files
                if source_file.startswith(tempfile.gettempdir()):
                    try: os.unlink(source_file)
                    except: pass
                try: os.unlink(output_file)
                except: pass
                return jsonify({'error': 'Transcoding failed', 'details': stderr_msg[:200]}), 500
            
            # Log ffmpeg output for debugging
            stdout_msg = result.stdout.decode('utf-8', errors='replace')[:200] if result.stdout else ''
            stderr_msg = result.stderr.decode('utf-8', errors='replace')[:200] if result.stderr else ''
            logger.info(f"audio_compat: ffmpeg succeeded. stdout: {stdout_msg}, stderr: {stderr_msg}")
            
            # Verify output file exists and has content
            if not os.path.exists(output_file):
                logger.error(f"audio_compat: Output file doesn't exist after ffmpeg!")
                if source_file.startswith(tempfile.gettempdir()):
                    try: os.unlink(source_file)
                    except: pass
                return jsonify({'error': 'Output file not created'}), 500
            
            output_size = os.path.getsize(output_file)
            logger.info(f"audio_compat: Output file size: {output_size} bytes")
            
            # Read transcoded file
            with open(output_file, 'rb') as f:
                audio_data = f.read()
            
            file_size = len(audio_data)
            logger.info(f"audio_compat: Transcoded audio read, size: {file_size} bytes")
            
            if file_size == 0:
                logger.error(f"audio_compat: Transcoded file is empty!")
                if source_file.startswith(tempfile.gettempdir()):
                    try: os.unlink(source_file)
                    except: pass
                try: os.unlink(output_file)
                except: pass
                return jsonify({'error': 'Transcoded file is empty'}), 500
            
            # Verify it looks like a valid M4A file (starts with ftyp atom)
            if len(audio_data) > 8:
                header = audio_data[4:8]
                if header != b'ftyp':
                    logger.warning(f"audio_compat: File doesn't look like valid M4A, header: {header}")
            
            # Cleanup temp files
            try: os.unlink(output_file)
            except: pass
            if source_file.startswith(tempfile.gettempdir()):
                try: os.unlink(source_file)
                except: pass
            
            # Serve with proper headers for iOS audio playback
            # Use audio/mp4 mimetype for M4A container (correct mimetype for AAC in M4A)
            response = Response(audio_data, mimetype='audio/mp4')
            response.headers['Content-Type'] = 'audio/mp4'
            response.headers['Content-Length'] = str(file_size)
            response.headers['Accept-Ranges'] = 'bytes'
            response.headers['Cache-Control'] = 'no-cache'  # Don't cache transcoded audio
            logger.info(f"audio_compat: Serving transcoded audio for {filename}, size={file_size}")
            return response
            
        except subprocess.TimeoutExpired:
            logger.error(f"audio_compat: ffmpeg timeout for {filename}")
            return redirect(f'/uploads/{filename}')
        except Exception as e:
            logger.error(f"audio_compat: Transcoding error: {e}")
            return redirect(f'/uploads/{filename}')
            
    except Exception as e:
        logger.error(f"audio_compat error: {e}")
        return redirect(f'/uploads/{filename}')


@app.route('/debug/r2_status')
@login_required
def debug_r2_status():
    """Debug route to check R2 CDN configuration and connectivity"""
    try:
        from backend.services.r2_storage import (
            R2_ENABLED, R2_ACCESS_KEY, R2_SECRET_KEY, R2_BUCKET, 
            R2_ENDPOINT, R2_PUBLIC_URL, get_s3_client, upload_to_r2
        )
        
        status = {
            'r2_enabled': R2_ENABLED,
            'env_vars': {
                'CLOUDFLARE_R2_ENABLED': os.environ.get('CLOUDFLARE_R2_ENABLED', 'NOT SET'),
                'CLOUDFLARE_R2_ACCESS_KEY': '***' + R2_ACCESS_KEY[-4:] if R2_ACCESS_KEY else 'NOT SET',
                'CLOUDFLARE_R2_SECRET_KEY': '***' + R2_SECRET_KEY[-4:] if R2_SECRET_KEY else 'NOT SET',
                'CLOUDFLARE_R2_BUCKET': R2_BUCKET or 'NOT SET',
                'CLOUDFLARE_R2_ENDPOINT': R2_ENDPOINT or 'NOT SET',
                'CLOUDFLARE_R2_PUBLIC_URL': R2_PUBLIC_URL or 'NOT SET',
            },
            'boto3_installed': False,
            'client_created': False,
            'test_upload': None,
        }
        
        # Check boto3
        try:
            import boto3
            status['boto3_installed'] = True
            status['boto3_version'] = boto3.__version__
        except ImportError:
            status['boto3_installed'] = False
            status['boto3_error'] = 'boto3 not installed - run: pip install boto3'
        
        # Try to create client
        if R2_ENABLED and status['boto3_installed']:
            client = get_s3_client()
            status['client_created'] = client is not None
            
            # Try a test upload
            if client:
                try:
                    test_content = b'R2 CDN test file - safe to delete'
                    test_key = 'test/r2_connectivity_test.txt'
                    success, url = upload_to_r2(test_content, test_key, 'text/plain')
                    status['test_upload'] = {
                        'success': success,
                        'url': url,
                        'message': 'Test file uploaded successfully!' if success else 'Upload failed'
                    }
                except Exception as e:
                    status['test_upload'] = {
                        'success': False,
                        'error': str(e)
                    }
        
        return jsonify(status)
    except Exception as e:
        return jsonify({
            'success': False,
            'error': str(e)
        })


