@app.route('/delete_message', methods=['POST'])
@login_required
def delete_message():
    username = session['username']
    message_id = request.form.get('message_id')
    if not message_id:
        return jsonify({'success': False, 'error': 'Message ID required'})
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            c.execute("SELECT sender, receiver FROM messages WHERE id=? AND (sender=? OR receiver=?)",
                      (message_id, username, username))
            row = c.fetchone()
            if not row:
                return jsonify({'success': False, 'error': 'Message not found or not yours'})
            sender = row['sender'] if hasattr(row, 'keys') else row[0]
            receiver = row['receiver'] if hasattr(row, 'keys') else row[1]
            c.execute("DELETE FROM messages WHERE id=?", (message_id,))
            conn.commit()
            
            # Delete from Firestore too
            try:
                from backend.services.firestore_writes import _get_client, _dm_conv_id, USE_FIRESTORE_WRITES
                if USE_FIRESTORE_WRITES:
                    fs = _get_client()
                    conv_id = _dm_conv_id(sender, receiver)
                    fs.collection('dm_conversations').document(conv_id).collection('messages').document(str(message_id)).delete()
            except Exception as fs_err:
                logger.warning(f"Firestore DM message delete failed (non-fatal): {fs_err}")
            
        return jsonify({'success': True})
    except Exception as e:
        logger.error(f"Error deleting message for {username}: {str(e)}")
        return jsonify({'success': False, 'error': 'Failed to delete message'}), 500

@app.route('/api/chat/mute', methods=['POST'])
@login_required
def mute_chat():
    """Mute/unmute push notifications for a DM or group chat."""
    username = session.get('username')
    data = request.get_json() or {}
    other_username = data.get('other_username')
    group_id = data.get('group_id')
    muted = data.get('muted', True)
    try:
        ph = get_sql_placeholder()
        with get_db_connection() as conn:
            c = conn.cursor()
            try:
                c.execute("SELECT 1 FROM user_muted_chats LIMIT 1")
            except Exception:
                if USE_MYSQL:
                    c.execute("CREATE TABLE IF NOT EXISTS user_muted_chats (username VARCHAR(191) NOT NULL, chat_key VARCHAR(255) NOT NULL, muted_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY (username, chat_key))")
                else:
                    c.execute("CREATE TABLE IF NOT EXISTS user_muted_chats (username TEXT NOT NULL, chat_key TEXT NOT NULL, muted_at TEXT DEFAULT (datetime('now')), PRIMARY KEY (username, chat_key))")
            chat_key = f"dm:{other_username}" if other_username else f"group:{group_id}" if group_id else None
            if not chat_key:
                return jsonify({'success': False, 'error': 'other_username or group_id required'}), 400
            if muted:
                if USE_MYSQL:
                    c.execute(f"INSERT INTO user_muted_chats (username, chat_key) VALUES ({ph},{ph}) ON DUPLICATE KEY UPDATE muted_at=NOW()", (username, chat_key))
                else:
                    c.execute(f"INSERT INTO user_muted_chats (username, chat_key) VALUES ({ph},{ph}) ON CONFLICT(username, chat_key) DO UPDATE SET muted_at=datetime('now')", (username, chat_key))
            else:
                c.execute(f"DELETE FROM user_muted_chats WHERE username={ph} AND chat_key={ph}", (username, chat_key))
            conn.commit()
            return jsonify({'success': True, 'muted': bool(muted)})
    except Exception as e:
        logger.error(f"mute_chat error: {e}")
        return jsonify({'success': False, 'error': 'Server error'}), 500


