@app.route('/add_reaction', methods=['POST'])
@login_required
def add_reaction():
    username = session['username']
    post_id = request.form.get('post_id', type=int)
    reaction_type = request.form.get('reaction')

    if not all([post_id, reaction_type]):
        return jsonify({'success': False, 'error': 'Missing data'}), 400

    try:
        comm_id = None
        view_count = None
        with get_db_connection() as conn:
            c = conn.cursor()

            # Check if the user already reacted to this post
            c.execute("SELECT id, reaction_type FROM reactions WHERE post_id = ? AND username = ?", (post_id, username))
            existing = c.fetchone()

            # Retrieve post metadata upfront (owner + community)
            c.execute("SELECT username, community_id FROM posts WHERE id = ?", (post_id,))
            post_data = c.fetchone()
            comm_id = post_data['community_id'] if post_data and hasattr(post_data, 'keys') else (post_data[1] if post_data and len(post_data) > 1 else None)

            if existing:
                if existing['reaction_type'] == reaction_type:
                    # User clicked the same reaction again, so remove it (toggle off)
                    c.execute("DELETE FROM reactions WHERE id = ?", (existing['id'],))
                else:
                    # User changed their reaction, so update it
                    c.execute("UPDATE reactions SET reaction_type = ? WHERE id = ?", (reaction_type, existing['id']))
            else:
                # No existing reaction, so insert a new one
                c.execute("INSERT INTO reactions (post_id, username, reaction_type) VALUES (?, ?, ?)",
                          (post_id, username, reaction_type))

            # Dual-write reaction to Firestore
            try:
                from backend.services.firestore_writes import write_reaction
                final_reaction = None if (existing and existing['reaction_type'] == reaction_type) else reaction_type
                write_reaction(post_id=post_id, username=username, reaction_type=final_reaction)
            except Exception:
                pass

            # Create notification for post owner and other engaged users (only if adding/changing reaction, not removing)
            if post_data and (existing is None or (existing and existing['reaction_type'] != reaction_type)):
                logger.info(f"Reaction notification check - Post owner: {post_data['username'] if post_data else 'None'}, Reactor: {username}")
                owner = post_data['username']
                recipients = set()
                if owner and owner != username:
                    recipients.add(owner)
                # Prior repliers
                try:
                    c.execute("SELECT DISTINCT username FROM replies WHERE post_id=?", (post_id,))
                    for rr in c.fetchall() or []:
                        u = rr['username'] if hasattr(rr,'keys') else rr[0]
                        if u and u != username and u != owner:
                            recipients.add(u)
                except Exception:
                    pass
                # Prior reactors
                try:
                    c.execute("SELECT DISTINCT username FROM reactions WHERE post_id=?", (post_id,))
                    for rv in c.fetchall() or []:
                        u = rv['username'] if hasattr(rv,'keys') else rv[0]
                        if u and u != username and u != owner:
                            recipients.add(u)
                except Exception:
                    pass
                # Insert notifications
                for target in recipients:
                    try:
                        c.execute("""
                            INSERT INTO notifications (user_id, from_user, type, post_id, community_id, message)
                            VALUES (?, ?, 'reaction', ?, ?, ?)
                        """, (target, username, post_id, comm_id, f"{username} reacted in a thread you follow"))
                    except Exception:
                        try:
                            c.execute("""
                                INSERT INTO notifications (user_id, from_user, type, post_id, community_id, message, created_at, is_read)
                                VALUES (?, ?, 'reaction', ?, ?, ?, NOW(), 0)
                                ON CONFLICT(user_id, from_user, type, post_id, community_id) DO UPDATE SET created_at=excluded.created_at, is_read=0, message=excluded.message
                            """, (target, username, post_id, comm_id, f"{username} reacted in a thread you follow"))
                        except Exception:
                            pass
                logger.info(f"Created reaction notifications for {len(recipients)} recipients")
            
            conn.commit()

            new_counts, new_user_reaction = get_post_reaction_summary(c, post_id, username)

            try:
                view_count = upsert_post_view(c, int(post_id), username)
                conn.commit()
            except Exception as view_err:
                logger.warning(f"add_reaction view tracking failed for post {post_id}: {view_err}")

            return jsonify({
                'success': True,
                'counts': new_counts,
                'user_reaction': new_user_reaction,
                'view_count': int(view_count or 0) if view_count is not None else None
            })

    except Exception as e:
        logger.error(f"Error adding reaction: {str(e)}")
        return jsonify({'success': False, 'error': 'Server error'}), 500

    finally:
        try:
            if comm_id:
                invalidate_community_cache(comm_id)
        except Exception as cache_err:
            logger.warning(f"Failed to invalidate cache after reaction for community {comm_id}: {cache_err}")




def _parse_link_urls_from_request(raw) -> list:
    """Parse JSON array of strings from multipart form; only http(s) URLs kept."""
    if not raw:
        return []
    if isinstance(raw, list):
        items = raw
    else:
        try:
            items = json.loads(raw)
        except (json.JSONDecodeError, TypeError):
            return []
    if not isinstance(items, list):
        return []
    out = []
    for x in items:
        if isinstance(x, str) and x.strip().startswith(('http://', 'https://')):
            out.append(x.strip()[:4096])
    return out


def _strip_urls_from_post_content(content: str, urls: list) -> str:
    """Remove URL strings from text (caption-only storage when URLs are in link_urls)."""
    if not content or not urls:
        return (content or '').strip()
    out = content
    for u in urls:
        if not u:
            continue
        out = out.replace(u, '')
    out = re.sub(r'\n{3,}', '\n\n', out)
    return out.strip()


def _normalize_link_urls_json(urls: list) -> str | None:
    out = []
    seen = set()
    for u in urls or []:
        s = (u or '').strip()
        if not s.startswith(('http://', 'https://')):
            continue
        if s in seen:
            continue
        seen.add(s)
        out.append(s)
    return json.dumps(out) if out else None


def _parent_snippet_replied_to(c, post_id: int, parent_reply_id: int | None) -> str:
    """Snippet of the post or parent reply that the new reply is responding to (for notifications)."""
    try:
        if parent_reply_id:
            try:
                c.execute(
                    "SELECT content, image_path, audio_path, video_path FROM replies WHERE id = ?",
                    (parent_reply_id,),
                )
            except Exception:
                c.execute(
                    "SELECT content, image_path, audio_path FROM replies WHERE id = ?",
                    (parent_reply_id,),
                )
        else:
            try:
                c.execute(
                    "SELECT content, image_path, audio_path, video_path FROM posts WHERE id = ?",
                    (post_id,),
                )
            except Exception:
                c.execute(
                    "SELECT content, image_path, audio_path FROM posts WHERE id = ?",
                    (post_id,),
                )
        row = c.fetchone()
        if not row:
            return ""
        if hasattr(row, "keys"):
            content = (row.get("content") or "").strip()
            if content:
                return _truncate_notif_preview(content)
            if row.get("video_path"):
                return "Video"
            if row.get("image_path"):
                return "Photo"
            if row.get("audio_path"):
                return "Voice message"
            return ""
        # tuple row: content, image_path, audio_path, [video_path]
        content = (row[0] or "").strip() if len(row) > 0 else ""
        if content:
            return _truncate_notif_preview(content)
        if len(row) > 3 and row[3]:
            return "Video"
        if len(row) > 1 and row[1]:
            return "Photo"
        if len(row) > 2 and row[2]:
            return "Voice message"
        return ""
    except Exception:
        return ""


def notify_post_reply_recipients(
    *,
    post_id: int,
    from_user: str,
    community_id: int | None,
    parent_reply_id: int | None,
    reply_id: int | None = None,
    reply_content: str | None = None,
):
    """Create in-app notifications and web push for post reply recipients.
    Recipients: post owner (unless sender), parent reply author, and users who engaged
    (replied, reacted on the post, or reacted on a reply). Users who only viewed the post
    (post_views) are never included — they are not queried here.
    
    If reply_id is provided, notifications will link to /reply/{reply_id} for nested replies,
    allowing users to navigate directly to the relevant thread.
    """
    try:
        ensure_notifications_preview_text_column()
        with get_db_connection() as conn:
            c = conn.cursor()
            engaged: set[str] = set()
            
            c.execute("SELECT username FROM posts WHERE id=?", (post_id,))
            row = c.fetchone()
            post_owner = (row['username'] if hasattr(row,'keys') else row[0]) if row else None
            logger.info(f"[Reply Notify] Post {post_id} owner: {post_owner}, replier: {from_user}, parent_reply_id: {parent_reply_id}")
            
            if post_owner:
                engaged.add(post_owner)
            
            parent_author = None
            if parent_reply_id:
                c.execute("SELECT username FROM replies WHERE id=?", (parent_reply_id,))
                r2 = c.fetchone()
                parent_author = (r2['username'] if hasattr(r2,'keys') else r2[0]) if r2 else None
                if parent_author:
                    engaged.add(parent_author)
                    logger.info(f"[Reply Notify] Parent reply author {parent_author} in engaged set")

            try:
                c.execute("SELECT DISTINCT username FROM replies WHERE post_id=?", (post_id,))
                for rr in c.fetchall() or []:
                    uname = rr['username'] if hasattr(rr,'keys') else rr[0]
                    if uname:
                        engaged.add(uname)
            except Exception as qe:
                logger.warning(f"collect prior repliers failed: {qe}")
            try:
                c.execute("SELECT DISTINCT username FROM reactions WHERE post_id=?", (post_id,))
                for rv in c.fetchall() or []:
                    uname = rv['username'] if hasattr(rv,'keys') else rv[0]
                    if uname:
                        engaged.add(uname)
            except Exception as qe2:
                logger.warning(f"collect prior reactors failed: {qe2}")
            try:
                c.execute(
                    """
                    SELECT DISTINCT rr.username FROM reply_reactions rr
                    INNER JOIN replies r ON r.id = rr.reply_id
                    WHERE r.post_id = ?
                    """,
                    (post_id,),
                )
                for rr in c.fetchall() or []:
                    uname = rr['username'] if hasattr(rr,'keys') else rr[0]
                    if uname:
                        engaged.add(uname)
            except Exception as qe3:
                logger.warning(f"collect reply_reactors failed: {qe3}")

            recipients = {u for u in engaged if u and u != from_user}

            # Parent context: snippet of the comment/post being replied to (shown under the main line in-app)
            parent_preview_snip = ""
            try:
                parent_preview_snip = _parent_snippet_replied_to(c, post_id, parent_reply_id)
            except Exception as ps_err:
                logger.warning("parent snippet for reply notify failed: %s", ps_err)

            # Main line: "{user} replied \"{new reply snippet}\"" (inner double-quotes flattened for display)
            new_reply_snip = _truncate_notif_preview(reply_content or "")
            if not new_reply_snip.strip():
                new_reply_snip = "(media)"
            safe_inner = new_reply_snip.replace('"', "'")
            notif_message = f'{from_user} replied "{safe_inner}"'

            # Insert notifications (dedupe 10s by same from_user/post/type/recipient)
            for target in recipients:
                try:
                    if USE_MYSQL:
                        c.execute("""
                            SELECT id FROM notifications
                            WHERE user_id=? AND from_user=? AND type='reply' AND post_id=?
                              AND created_at > DATE_SUB(NOW(), INTERVAL 10 SECOND)
                            LIMIT 1
                        """, (target, from_user, post_id))
                    else:
                        c.execute("""
                            SELECT id FROM notifications
                            WHERE user_id=? AND from_user=? AND type='reply' AND post_id=?
                              AND datetime(created_at) > datetime('now','-10 seconds')
                            LIMIT 1
                        """, (target, from_user, post_id))
                    exists = c.fetchone()
                    if not exists:
                        # Determine notification URL - use reply page for all replies
                        if reply_id:
                            notif_link = f'/reply/{reply_id}'
                        else:
                            notif_link = f'/post/{post_id}'
                        
                        c.execute("""
                            INSERT INTO notifications (user_id, from_user, type, post_id, community_id, message, created_at, is_read, link, preview_text)
                            VALUES (?, ?, 'reply', ?, ?, ?, NOW(), 0, ?, ?)
                            ON DUPLICATE KEY UPDATE
                                created_at = NOW(),
                                message = VALUES(message),
                                is_read = 0,
                                link = VALUES(link),
                                preview_text = VALUES(preview_text)
                        """, (target, from_user, post_id, community_id, notif_message, notif_link, parent_preview_snip or None))
                        conn.commit()
                except Exception as ne:
                    logger.warning(f"reply notify db error to {target}: {ne}")

                # Push notify (tag per user+post to allow coalescing)
                # Use reply page for all replies
                if reply_id:
                    notification_url = f'/reply/{reply_id}'
                else:
                    # Fallback to post page
                    notification_url = f'/post/{post_id}'
                
                try:
                    if new_reply_snip != "(media)":
                        push_body = new_reply_snip
                    else:
                        push_body = parent_preview_snip or "Tap to view the conversation"
                    send_push_to_user(target, {
                        'title': f'New reply from {from_user}',
                        'body': push_body,
                        'url': notification_url,
                        'tag': f'post-reply-{post_id}-{target}'
                    })
                except Exception as pe:
                    logger.warning(f"reply push error to {target}: {pe}")
            
            logger.info(f"[Reply Notify] Notified {len(recipients)} users for post {post_id}: {list(recipients)}")
    except Exception as e:
        logger.error(f"notify_post_reply_recipients error: {e}")


