@app.route('/get_links')
@login_required
def get_links():
    """Get all links for a community or main feed"""
    try:
        username = session['username']
        community_id = request.args.get('community_id')
        
        with get_db_connection() as conn:
            c = conn.cursor()
            
            if community_id:
                # Get links for specific community
                c.execute("""
                    SELECT id, username, url, description, created_at
                    FROM useful_links
                    WHERE community_id = ?
                    ORDER BY created_at DESC
                """, (community_id,))
            else:
                # Get links for main feed (community_id is NULL)
                c.execute("""
                    SELECT id, username, url, description, created_at
                    FROM useful_links
                    WHERE community_id IS NULL
                    ORDER BY created_at DESC
                """)
            
            links_raw = c.fetchall()
            links = []
            
            for link in links_raw:
                links.append({
                    'id': link['id'],
                    'username': link['username'],
                    'url': link['url'],
                    'description': link['description'],
                    'created_at': link['created_at'],
                    'can_delete': link['username'] == username or is_app_admin(username)
                })
            
            # Also return docs (PDFs)
            docs = []
            try:
                if community_id:
                    c.execute("""
                        SELECT id, username, file_path, description, created_at
                        FROM useful_docs
                        WHERE community_id = ?
                        ORDER BY created_at DESC
                    """, (community_id,))
                else:
                    c.execute("""
                        SELECT id, username, file_path, description, created_at
                        FROM useful_docs
                        WHERE community_id IS NULL
                        ORDER BY created_at DESC
                    """)
                for d in c.fetchall() or []:
                    docs.append({
                        'id': d['id'] if hasattr(d,'keys') else d[0],
                        'username': d['username'] if hasattr(d,'keys') else d[1],
                        'file_path': d['file_path'] if hasattr(d,'keys') else d[2],
                        'description': d['description'] if hasattr(d,'keys') else d[3],
                        'created_at': d['created_at'] if hasattr(d,'keys') else d[4]
                    })
            except Exception as de:
                logger.warning(f"get_docs error: {de}")
            return jsonify({'success': True, 'links': links, 'docs': docs})
            
    except Exception as e:
        logger.error(f"Error getting links: {str(e)}")
        return jsonify({'success': False, 'error': str(e)})

def notify_community_new_resource(community_id, username, resource_type, description, conn):
    """Send notifications (in-app + push) to community members when a new link/doc is added"""
    if not community_id:
        return
    try:
        c = conn.cursor()
        
        # Get community name
        c.execute("SELECT name FROM communities WHERE id = ?", (community_id,))
        comm_row = c.fetchone()
        if not comm_row:
            return
        community_name = comm_row['name'] if hasattr(comm_row, 'keys') else comm_row[0]
        
        # Get all community members except the one who added the resource
        c.execute("""
            SELECT DISTINCT u.username
            FROM user_communities uc
            JOIN users u ON uc.user_id = u.id
            WHERE uc.community_id = ? AND u.username != ?
        """, (community_id, username))
        
        members = c.fetchall()
        
        # Create notification message
        resource_label = "document" if resource_type == "doc" else "link"
        desc_preview = (description[:50] + '...') if len(description) > 50 else description
        message = f'{username} added a new {resource_label} to "{community_name}": {desc_preview}'
        notification_link = f'/community/{community_id}/useful_links_react'
        
        # Send notification to each member (in-app + push)
        for member in members:
            member_username = member['username'] if hasattr(member, 'keys') else member[0]
            
            # In-app notification (stored in database, appears on notification page)
            try:
                c.execute("""
                    INSERT INTO notifications (user_id, from_user, type, community_id, message, link)
                    VALUES (?, ?, ?, ?, ?, ?)
                """, (
                    member_username,
                    username,
                    'new_resource',
                    community_id,
                    message,
                    notification_link
                ))
            except Exception as notify_err:
                logger.warning(f"Failed to create in-app notification for {member_username}: {notify_err}")
            
            # Push notification
            try:
                send_push_to_user(member_username, {
                    'title': f'New {resource_label} in {community_name}',
                    'body': f'{username}: {desc_preview}',
                    'url': notification_link,
                    'tag': f'new-resource-{community_id}-{resource_type}'
                })
            except Exception as push_err:
                logger.warning(f"Failed to send push notification to {member_username}: {push_err}")
        
        logger.info(f"Sent new {resource_type} notifications to {len(members)} members in {community_name}")
        
    except Exception as e:
        logger.error(f"Error sending new resource notifications: {e}")

