@app.route('/upload_doc', methods=['POST'])
@login_required
def upload_doc():
    """Upload a PDF document for Useful Links & Docs - uses Cloudflare R2 CDN"""
    try:
        from backend.services.r2_storage import R2_ENABLED, upload_file_to_r2, R2_PUBLIC_URL
        
        username = session['username']
        community_id = request.form.get('community_id')
        description = (request.form.get('description') or '').strip()
        if 'file' not in request.files:
            return jsonify({'success': False, 'error': 'No file provided'})
        f = request.files['file']
        if not f or f.filename == '':
            return jsonify({'success': False, 'error': 'No file selected'})
        # Only PDFs by extension
        from werkzeug.utils import secure_filename
        orig = secure_filename(f.filename)
        ext = orig.rsplit('.', 1)[-1].lower() if '.' in orig else ''
        if ext != 'pdf':
            return jsonify({'success': False, 'error': 'Only PDF files are allowed'})
        
        safe_name = f"doc_{datetime.now().strftime('%Y%m%d_%H%M%S')}_{username}.pdf"
        r2_key = f"docs/{safe_name}"
        
        # Try to upload to R2 CDN first
        if R2_ENABLED:
            success, r2_url = upload_file_to_r2(f, r2_key, 'application/pdf')
            if success and r2_url:
                # Store the full R2 URL in the database
                file_path = r2_url
                logger.info(f"Document uploaded to R2: {r2_url}")
            else:
                logger.warning("R2 upload failed, falling back to local storage")
                # Fall back to local storage
                base_dir = os.path.dirname(os.path.abspath(__file__))
                upload_dir = os.path.join(base_dir, 'uploads', 'docs')
                os.makedirs(upload_dir, exist_ok=True)
                local_path = os.path.join(upload_dir, safe_name)
                f.seek(0)
                f.save(local_path)
                file_path = f"docs/{safe_name}"
        else:
            # R2 not enabled, use local storage
            base_dir = os.path.dirname(os.path.abspath(__file__))
            upload_dir = os.path.join(base_dir, 'uploads', 'docs')
            os.makedirs(upload_dir, exist_ok=True)
            local_path = os.path.join(upload_dir, safe_name)
            try:
                f.save(local_path)
            except Exception as se:
                logger.error(f"upload save error: {se}")
                return jsonify({'success': False, 'error': 'Could not save file on server'})
            file_path = f"docs/{safe_name}"
        
        with get_db_connection() as conn:
            c = conn.cursor()
            c.execute("""
                INSERT INTO useful_docs (community_id, username, file_path, description, created_at)
                VALUES (?, ?, ?, ?, ?)
            """, (community_id if community_id else None, username, file_path, description, datetime.now().strftime('%Y-%m-%d %H:%M:%S')))
            
            # Send notifications to community members
            if community_id:
                doc_description = description or orig  # Use filename if no description
                notify_community_new_resource(community_id, username, 'doc', doc_description, conn)
            
            conn.commit()
        
        # Return appropriate path based on storage type
        if file_path.startswith('http'):
            return jsonify({'success': True, 'message': 'Document uploaded to CDN', 'path': file_path})
        else:
            return jsonify({'success': True, 'message': 'Document uploaded', 'path': f"/uploads/{file_path}"})
    except Exception as e:
        logger.error(f"upload_doc error: {e}")
        return jsonify({'success': False, 'error': 'Server error'})

@app.route('/delete_doc', methods=['POST'])
@login_required
def delete_doc():
    """Delete a previously uploaded PDF document"""
    try:
        username = session.get('username')
        doc_id = request.form.get('doc_id')
        if not doc_id:
            return jsonify({'success': False, 'error': 'doc_id required'})
        with get_db_connection() as conn:
            c = conn.cursor()
            # Fetch doc owner and path
            c.execute("SELECT username, file_path FROM useful_docs WHERE id = ?", (doc_id,))
            row = c.fetchone()
            if not row:
                return jsonify({'success': False, 'error': 'Document not found'})
            owner = row['username'] if hasattr(row, 'keys') else row[0]
            path = row['file_path'] if hasattr(row, 'keys') else row[1]
            if username != owner and not is_app_admin(username):
                return jsonify({'success': False, 'error': 'Forbidden'})
            # Delete DB row
            c.execute("DELETE FROM useful_docs WHERE id = ?", (doc_id,))
            conn.commit()
        # Attempt to delete file on disk
        try:
            base_dir = os.path.dirname(os.path.abspath(__file__))
            disk_path = os.path.join(base_dir, 'uploads', path)
            if os.path.exists(disk_path):
                os.remove(disk_path)
        except Exception as fe:
            logger.warning(f"Could not remove doc file {path}: {fe}")
        return jsonify({'success': True})
    except Exception as e:
        logger.error(f"Error deleting doc: {e}")
        return jsonify({'success': False, 'error': 'Server error'})

@app.route('/rename_doc', methods=['POST'])
@login_required
def rename_doc():
    """Rename a document's description/display name"""
    try:
        username = session.get('username')
        doc_id = request.form.get('doc_id')
        new_name = request.form.get('new_name', '').strip()
        
        if not doc_id:
            return jsonify({'success': False, 'error': 'doc_id required'})
        if not new_name:
            return jsonify({'success': False, 'error': 'new_name required'})
        if len(new_name) > 200:
            return jsonify({'success': False, 'error': 'Name too long (max 200 characters)'})
            
        with get_db_connection() as conn:
            c = conn.cursor()
            # Check ownership
            c.execute("SELECT username FROM useful_docs WHERE id = ?", (doc_id,))
            row = c.fetchone()
            if not row:
                return jsonify({'success': False, 'error': 'Document not found'})
            owner = row['username'] if hasattr(row, 'keys') else row[0]
            if username != owner and not is_app_admin(username):
                return jsonify({'success': False, 'error': 'Only the uploader can rename this document'})
            
            # Update description
            c.execute("UPDATE useful_docs SET description = ? WHERE id = ?", (new_name, doc_id))
            conn.commit()
            
        return jsonify({'success': True, 'message': 'Document renamed'})
    except Exception as e:
        logger.error(f"Error renaming doc: {e}")
        return jsonify({'success': False, 'error': 'Server error'})

