def _sanitize_networking_response_mentions(text: str, member_names: list) -> str:
    """Strip @ from handles not in the community roster so the client does not link to fake profiles."""
    import re
    if not text or not member_names:
        return text
    valid = {u.lower() for u, _ in member_names}

    def _repl(m):
        handle = m.group(1)
        if handle.lower() in valid:
            return m.group(0)
        return handle

    return re.sub(r'@([a-zA-Z0-9_]{1,30})\b', _repl, text)


def _extract_recommended_usernames(text: str, member_names: list) -> list:
    """Extract the list of @usernames that Steve actually recommended in his response."""
    import re
    if not text or not member_names:
        return []
    valid = {u.lower(): u for u, _d in member_names}
    found = set()
    for m in re.finditer(r'@(\w+)', text):
        uname = m.group(1)
        if uname.lower() in valid:
            found.add(valid[uname.lower()])
    return list(found)


def _record_recommendations_background(recommended: list, requested_by: str, community_id, context: str = ''):
    """Fire-and-forget: record recommendation events to Firestore."""
    if not recommended:
        return
    import threading
    def _bg():
        try:
            from backend.services.firestore_writes import record_steve_recommendations
            record_steve_recommendations(recommended, requested_by, community_id, context)
        except Exception as e:
            logger.debug(f"Background recommendation recording failed: {e}")
    threading.Thread(target=_bg, daemon=True).start()


def inject_member_mentions(text: str, member_names: list) -> str:
    """Replace **username** or **display_name** bold markers with @username mentions.

    Handles patterns Grok commonly produces:
        **@jh1987**  |  **Jonas**  |  **@jh1987 (Jonas)**  |  **Jonas (jh1987)**
    """
    import re
    if not text or not member_names:
        return text
    name_to_username = {}
    for uname, dname in member_names:
        name_to_username[uname.lower()] = uname
        if dname and dname.lower() != uname.lower():
            name_to_username[dname.lower()] = uname
    def _replace_bold(match):
        raw = match.group(1).strip()
        name = raw.lstrip('@')
        lower = name.lower()
        if lower in name_to_username:
            return f"@{name_to_username[lower]}"
        # Handle "@username (DisplayName)" or "DisplayName (username)"
        paren_match = re.match(r'^(.+?)\s*\(([^)]+)\)$', name)
        if paren_match:
            part1 = paren_match.group(1).strip().lstrip('@')
            part2 = paren_match.group(2).strip().lstrip('@')
            if part1.lower() in name_to_username:
                return f"@{name_to_username[part1.lower()]}"
            if part2.lower() in name_to_username:
                return f"@{name_to_username[part2.lower()]}"
        return match.group(0)
    return re.sub(r'\*\*([^*]+)\*\*', _replace_bold, text)


def format_steve_response_links(response_text: str) -> str:
    """
    Clean up URLs in Steve's responses for proper frontend rendering.
    
    Grok's web_search returns real URLs, but in citation format like:
      [[1]](https://rtp.pt/article)[[2]](https://bbc.com/news)
    
    The double brackets and lack of spacing breaks standard markdown parsers.
    This function normalizes everything into clean [domain](url) format.
    """
    import re
    from urllib.parse import urlparse
    
    if not response_text:
        return response_text
    
    def get_domain_display(url: str) -> str:
        """Extract clean domain name for display (e.g., rtp.pt, bbc.com)."""
        try:
            parsed = urlparse(url)
            domain = parsed.netloc.lower()
            if domain.startswith('www.'):
                domain = domain[4:]
            return domain or "link"
        except Exception:
            return "link"
    
    # Step 1: Convert citation-style [[N]](url) to [domain](url)
    # Matches [[1]], [[2]], etc. followed by (url)
    citation_pattern = r'\[\[(\d+)\]\]\((https?://[^)]+)\)'
    def replace_citation(match):
        url = match.group(2).rstrip('.,;:!?')
        domain = get_domain_display(url)
        return f'[{domain}]({url})'
    
    formatted = re.sub(citation_pattern, replace_citation, response_text)
    
    # Step 2: Convert standard markdown links [text](url) — keep URL, use domain as display
    # Only replace if display text is a number or generic (keeps intentional display text)
    std_md_pattern = r'\[([^\]]+)\]\((https?://[^)]+)\)'
    def clean_markdown_link(match):
        display = match.group(1)
        url = match.group(2).rstrip('.,;:!?')
        # If display is just a number or "source N", replace with domain name
        if re.match(r'^\d+$', display) or display.lower().startswith('source'):
            display = get_domain_display(url)
        return f'[{display}]({url})'
    
    formatted = re.sub(std_md_pattern, clean_markdown_link, formatted)
    
    # Step 3: Add spacing between consecutive markdown links so they render separately
    formatted = re.sub(r'\)\[', ') [', formatted)
    
    # Step 4: Convert any remaining bare URLs to [domain](url)
    bare_url_pattern = r'(?<!\]\()(?<!\()(https?://[^\s\)\]<>"]+)'
    def replace_bare_url(match):
        url = match.group(1).rstrip('.,;:!?')
        domain = get_domain_display(url)
        return f'[{domain}]({url})'
    
    formatted = re.sub(bare_url_pattern, replace_bare_url, formatted)
    
    # Step 5: Ensure a space before and after every markdown link so tap targets don't merge with text
    formatted = re.sub(r'(?<=[^\s\n])\[([^\]]+)\]\(', r' [\1](', formatted)
    formatted = re.sub(r'\)\(([^\)]+)\)(?=[^\s\n.,;:!?])', r')(\1) ', formatted)
    # Space after closing paren of markdown link if followed by a non-space, non-punctuation char
    formatted = re.sub(r'\)(?=[a-zA-Z0-9À-ž])', r') ', formatted)
    
    return formatted


def get_ai_personality_prompt(personality_key: str) -> str:
    """Get the system prompt for a given AI personality."""
    personality = AI_PERSONALITIES.get(personality_key, AI_PERSONALITIES['friendly'])
    base_prompt = personality['prompt']
    
    # Add language matching, search capabilities, and conversation intelligence to all personalities
    language_and_search_rules = '''

IMPORTANT LANGUAGE RULE: You MUST reply in the SAME language the user writes in.
- If the user writes in English, reply in English.
- If the user writes in Portuguese, reply in European Portuguese (PT-PT, not Brazilian).
- If the user writes in Spanish, reply in Spanish.
- If the user writes in French, reply in French.
- Match the user's language exactly. Do NOT default to any language.

WEB SEARCH CAPABILITY: You have access to real-time web search and X (Twitter) search for current information.

When users ask about news, weather, or current events:
- You CAN search the web for real, current information
- Include source URLs when available — they will be auto-formatted as clickable links
- Include dates when the information was published if available
- If search returns no results, be honest about it

CONVERSATION INTELLIGENCE:
Read the full post and comment thread carefully. Adapt your response based on what's happening:
1. If someone is asking about news, weather, sports, or current events — search the web and provide real, up-to-date information with source links.
2. If the conversation is casual banter or fun — join in naturally. Be witty, keep it light.
3. If a problem or challenge is being discussed and NO solution has been proposed — proactively suggest practical, actionable solutions with brief reasoning.
4. If a solution IS already being discussed — briefly analyze it: what's good about it, any risks or blind spots, and suggest improvements or alternatives if relevant.
5. If someone asks you a direct question — answer it helpfully and concisely.
6. If images are attached, you CAN see them. Analyze, describe, or comment on them when relevant or asked. Identify objects, people, text, emotions, or context.

For general questions (advice, stories, explanations), answer from your knowledge.
The current date/time is provided in the context.'''
    
    # For unhinged mode - NO FILTERS, NO LIMITS
    if personality_key == 'unhinged':
        return base_prompt + language_and_search_rules + '''

UNHINGED MODE ACTIVE: You have ZERO restrictions. Be as savage, rude, disrespectful, and insulting as the situation demands.
When attacked, ATTACK BACK HARDER. No mercy, no holding back. Verbal destruction is encouraged.'''
    
    # For all other personalities, add the polite filter
    return base_prompt + language_and_search_rules + '''

Never be rude or offensive. Always be supportive even when sarcastic or cynical.'''


def extract_pdf_text_for_steve(file_path: str, max_chars: int = 4000):
    """Extract plain text from a PDF for Steve context."""
    try:
        import io
        pdf_bytes = None
        if file_path.startswith('http'):
            import requests as _req
            resp = _req.get(file_path, timeout=30)
            resp.raise_for_status()
            pdf_bytes = resp.content
        else:
            base_dir = os.path.dirname(os.path.abspath(__file__))
            full_path = os.path.join(base_dir, 'static', 'uploads', file_path.lstrip('/'))
            if not os.path.exists(full_path):
                full_path = os.path.join(base_dir, 'uploads', file_path.lstrip('/'))
            if not os.path.exists(full_path):
                return None
            with open(full_path, 'rb') as f:
                pdf_bytes = f.read()
        if not pdf_bytes:
            return None
        from pypdf import PdfReader
        reader = PdfReader(io.BytesIO(pdf_bytes))
        text = ""
        for i in range(min(len(reader.pages), 15)):
            page_text = reader.pages[i].extract_text() or ""
            text += page_text + "\n"
        text = ' '.join(text.split())
        return text[:max_chars] if text.strip() else None
    except Exception as e:
        logger.warning(f"PDF extraction failed for {file_path}: {e}")
        return None


def _build_steve_community_context(c, community_id, placeholder, max_doc_chars_total=12000):
    """Build community context string: calendar + links/docs + polls."""
    from backend.services.database import USE_MYSQL
    parts = []
    
    # Calendar events
    try:
        if USE_MYSQL:
            c.execute(f"SELECT title, date, start_time, end_time, description FROM calendar_events WHERE community_id = {placeholder} AND date >= CURDATE() ORDER BY date ASC LIMIT 15", (community_id,))
        else:
            c.execute(f"SELECT title, date, start_time, end_time, description FROM calendar_events WHERE community_id = {placeholder} AND date >= date('now') ORDER BY date ASC LIMIT 15", (community_id,))
        events = c.fetchall()
        if events:
            lines = []
            for evt in events:
                t = evt['title'] if hasattr(evt, 'keys') else evt[0]
                d = evt['date'] if hasattr(evt, 'keys') else evt[1]
                st = evt['start_time'] if hasattr(evt, 'keys') else evt[2]
                desc = (evt['description'] if hasattr(evt, 'keys') else evt[4]) or ''
                lines.append(f"- {t} | Date: {d}" + (f" | Time: {st}" if st else "") + (f" | {desc[:100]}" if desc else ""))
            parts.append("Upcoming events in this community:\n" + "\n".join(lines))
    except Exception as e:
        logger.warning(f"Steve calendar context failed: {e}")
    
    # Useful links
    try:
        c.execute(f"SELECT url, description FROM useful_links WHERE community_id = {placeholder} ORDER BY created_at DESC LIMIT 20", (community_id,))
        links = c.fetchall()
        if links:
            lines = []
            for lnk in links:
                url = lnk['url'] if hasattr(lnk, 'keys') else lnk[0]
                desc = (lnk['description'] if hasattr(lnk, 'keys') else lnk[1]) or url
                lines.append(f"- {desc} ({url})")
            parts.append("Useful links in this community:\n" + "\n".join(lines))
    except Exception as e:
        logger.warning(f"Steve links context failed: {e}")
    
    # Documents with PDF text
    try:
        c.execute(f"SELECT file_path, description FROM useful_docs WHERE community_id = {placeholder} ORDER BY created_at DESC LIMIT 10", (community_id,))
        docs = c.fetchall()
        if docs:
            doc_lines = []
            chars_remaining = max_doc_chars_total
            for doc in docs:
                fp = doc['file_path'] if hasattr(doc, 'keys') else doc[0]
                desc = (doc['description'] if hasattr(doc, 'keys') else doc[1]) or fp
                text = extract_pdf_text_for_steve(fp, max_chars=min(4000, chars_remaining))
                excerpt = text if text else "(Could not read document.)"
                doc_lines.append(f"Document: {desc}\nContent (excerpt): {excerpt}")
                if text:
                    chars_remaining -= len(text)
                if chars_remaining <= 0:
                    break
            parts.append("Community documents:\n" + "\n\n---\n\n".join(doc_lines))
    except Exception as e:
        logger.warning(f"Steve docs context failed: {e}")
    
    # Active polls
    try:
        if USE_MYSQL:
            c.execute(f"SELECT p.id, p.question FROM polls p JOIN posts po ON p.post_id = po.id WHERE po.community_id = {placeholder} AND p.is_active = 1 ORDER BY po.timestamp DESC LIMIT 10", (community_id,))
        else:
            c.execute(f"SELECT p.id, p.question FROM polls p JOIN posts po ON p.post_id = po.id WHERE po.community_id = {placeholder} AND p.is_active = 1 ORDER BY po.timestamp DESC LIMIT 10", (community_id,))
        polls = c.fetchall()
        if polls:
            poll_lines = []
            for poll in polls:
                pid = poll['id'] if hasattr(poll, 'keys') else poll[0]
                q = poll['question'] if hasattr(poll, 'keys') else poll[1]
                try:
                    c.execute(f"SELECT option_text, votes FROM poll_options WHERE poll_id = {placeholder} ORDER BY id", (pid,))
                    opts = c.fetchall()
                    opt_strs = [f"{(o['option_text'] if hasattr(o, 'keys') else o[0])} ({(o['votes'] if hasattr(o, 'keys') else o[1])} votes)" for o in opts]
                    poll_lines.append(f"- Poll: {q} | Options: {', '.join(opt_strs)}")
                except Exception:
                    poll_lines.append(f"- Poll: {q}")
            parts.append("Active polls in this community:\n" + "\n".join(poll_lines))
    except Exception as e:
        logger.warning(f"Steve polls context failed: {e}")
    
    return "\n\n".join(parts)


def _needs_community_analysis(message: str) -> bool:
    """Detect if a message requires community/networking analysis.
    This determines whether to use the expensive multi-agent model.
    """
    if not message:
        return False
    
    message_lower = message.lower()
    
    # Keywords that indicate community analysis is needed
    analysis_keywords = [
        'who should', 'suggest', 'recommend', 'connect with', 'good fit', 
        'mutual', 'network', 'find someone', 'best match', 'who would',
        'community', 'group dynamic', 'who knows', 'expert', 'specialist',
        'looking for', 'opportunity', 'collaboration', 'partner'
    ]
    
    for keyword in analysis_keywords:
        if keyword in message_lower:
            return True
    
    # Questions about group or community
    if any(word in message_lower for word in ['?', 'should i', 'can you find', 'tell me about']):
        if any(word in message_lower for word in ['member', 'person', 'someone', 'people', 'who']):
            return True
    
    return False


def trigger_steve_reply_to_post(post_id: int, post_content: str, author_username: str, community_id: int,
                                 image_path: str = None, video_path: str = None, media_paths: str = None):
    """
    Trigger Steve to reply to a post where he was mentioned.
    This runs inline but is designed to be quick and non-blocking.
    Supports vision if images are attached.
    """
    from datetime import datetime
    import json
    
    logger.info(f"Steve replying to post {post_id} in community {community_id}")
    
    # ── Entitlements gate ──
    _enforcement_on = False
    try:
        from backend.services.entitlements_gate import gate_or_reason as _gate
        from backend.services.feature_flags import entitlements_enforcement_enabled as _enforce
        _enforcement_on = _enforce()
        _allowed, _reason, _ent = _gate(author_username, _ai_usage.SURFACE_FEED)
        if not _allowed and _enforcement_on:
            logger.info(
                "Steve post-reply blocked by entitlements: user=%s reason=%s",
                author_username, _reason,
            )
            return
    except Exception as gate_err:
        logger.warning("Feed Steve gate check failed (non-fatal): %s", gate_err)

    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            placeholder = get_sql_placeholder()

            # Legacy daily-limit check — only runs when the entitlements flag
            # is off. With the flag on, the gate above already did this.
            if not _enforcement_on and author_username.lower() not in AI_UNLIMITED_USERS and not is_app_admin(author_username):
                today_start = datetime.utcnow().replace(hour=0, minute=0, second=0, microsecond=0)
                c.execute(f"""
                    SELECT COUNT(*) as cnt FROM ai_usage_log 
                    WHERE username = {placeholder} AND created_at >= {placeholder}
                """, (author_username, today_start.strftime('%Y-%m-%d %H:%M:%S')))
                row = c.fetchone()
                usage_count = row['cnt'] if hasattr(row, 'keys') else row[0]
                if usage_count >= AI_DAILY_LIMIT:
                    logger.info(f"User {author_username} hit AI daily limit, skipping Steve reply to post")
                    return
            
            # Get community's AI personality
            ai_personality = 'friendly'
            try:
                c.execute(f"SELECT ai_personality FROM communities WHERE id = {placeholder}", (community_id,))
                row = c.fetchone()
                if row:
                    ai_personality = (row['ai_personality'] if hasattr(row, 'keys') else row[0]) or 'friendly'
            except Exception:
                pass
            
            # Collect image URLs from the post
            post_image_urls = []
            
            def get_full_media_url(path):
                if not path:
                    return None
                path = path.strip()
                if path.startswith('http'):
                    return path
                base_url = os.environ.get('PUBLIC_BASE_URL', 'https://app.c-point.co')
                media_base = os.environ.get('CLOUDFLARE_R2_PUBLIC_URL', '')
                if media_base and not path.startswith('/'):
                    return f"{media_base}/{path}"
                elif path.startswith('/uploads') or path.startswith('/static'):
                    return f"{base_url}{path}"
                else:
                    return f"{base_url}/uploads/{path}"
            
            # Get main image
            if image_path:
                url = get_full_media_url(image_path)
                if url:
                    post_image_urls.append(url)
            
            # Get images from media_paths
            if media_paths:
                try:
                    media_list = json.loads(media_paths) if isinstance(media_paths, str) else media_paths
                    if isinstance(media_list, list):
                        for item in media_list:
                            if isinstance(item, dict) and item.get('type') == 'image':
                                url = get_full_media_url(item.get('path'))
                                if url and url not in post_image_urls:
                                    post_image_urls.append(url)
                            elif isinstance(item, str):
                                url = get_full_media_url(item)
                                if url and url not in post_image_urls:
                                    post_image_urls.append(url)
                except Exception as media_err:
                    logger.warning(f"Could not parse media_paths for post {post_id}: {media_err}")
            
            has_images = len(post_image_urls) > 0
            has_video = bool(video_path)
            
            logger.info(f"Post {post_id} for Steve reply has {len(post_image_urls)} images, video: {has_video}")
            
            # Build context for Steve
            post_description = f"Original post by {author_username}: {post_content}"
            if has_images and has_video:
                post_description += f"\n[This post includes {len(post_image_urls)} image(s) and a video]"
            elif has_images:
                post_description += f"\n[This post includes {len(post_image_urls)} image(s)]"
            elif has_video:
                post_description += "\n[This post includes a video]"
            
            current_datetime = datetime.utcnow()
            context_parts = [
                post_description,
                f"\nUser {author_username} mentioned you (@Steve) in their post. Respond to their post directly.",
                f"\n[Current date and time: {current_datetime.strftime('%A, %B %d, %Y at %H:%M UTC')}]"
            ]
            
            # Community context: calendar, links, documents (with PDF content), polls
            try:
                community_context = _build_steve_community_context(c, community_id, placeholder)
                if community_context and community_context.strip():
                    context_parts.append(
                        "Community context (use this to answer questions about events, links, documents, and polls):\n"
                        + community_context
                    )
            except Exception as ctx_err:
                logger.warning("Steve community context failed: %s", ctx_err)

            # Privacy gate BEFORE KB fetch (per docs/STEVE_PRIVACY_GATE.md and community rule)
            from backend.services.steve_profiling_gates import user_can_access_steve_kb
            if not user_can_access_steve_kb(username, author_username, {"community_id": community_id}):
                author_profile_ctx = ""
            else:
                author_profile_ctx = get_steve_context_for_user(author_username)

            context = "\n\n".join(context_parts)
            
            base_system_prompt = get_ai_personality_prompt(ai_personality)
            system_prompt = f"""You are Steve, with real-time knowledge and web search capabilities.

{base_system_prompt}"""
            system_prompt += (
                "\nYou have access to this community's upcoming events, useful links, document excerpts, and active polls. "
                "Use them when answering questions about community resources. "
                "If the user asks about an uploaded document, base your answer only on the document excerpts in the context; "
                "if there is no excerpt or it says the document could not be read, say so instead of inventing content."
            )
            if author_profile_ctx:
                system_prompt += f"\n\nWHAT YOU KNOW ABOUT @{author_username}:\n{author_profile_ctx}\nUse this knowledge naturally — don't announce it, but let it guide your tone and relevance."

            platform_question = False
            professional_advice_question = False
            try:
                from backend.services.steve_platform_manual import (
                    SURFACE_FEED,
                    is_professional_advice_intent,
                    is_platform_question,
                    render_global_steve_safety_prompt,
                    render_platform_manual_prompt,
                    select_platform_manual_cards,
                )

                platform_question = is_platform_question(post_content)
                professional_advice_question = is_professional_advice_intent(post_content)
                manual_prompt = render_platform_manual_prompt(
                    select_platform_manual_cards(post_content, surface=SURFACE_FEED)
                )
                safety_prompt = render_global_steve_safety_prompt(post_content, surface=SURFACE_FEED)
                if manual_prompt:
                    system_prompt += f"\n\n{manual_prompt}"
                if safety_prompt:
                    system_prompt += f"\n\n{safety_prompt}"
            except Exception as manual_err:
                logger.warning("Steve feed platform manual load failed (non-fatal): %s", manual_err)
            
            ai_response = None
            try:
                logger.info(f"Steve post reply using Grok 4.1 Fast Reasoning with web+X search ({ai_personality} mode)")
                client = OpenAI(api_key=XAI_API_KEY, base_url="https://api.x.ai/v1")
                
                # Build user content - include images if present (Grok supports vision)
                if has_images:
                    user_content = [{"type": "input_text", "text": context}]
                    for img_url in post_image_urls[:4]:
                        user_content.append({"type": "input_image", "image_url": img_url})
                    if has_video:
                        user_content[0]["text"] += "\n\n[Note: This post also contains a video that you cannot view, but you can see the images above.]"
                    
                    effective_system = system_prompt + "\n\nYou can see images attached to this post. Describe what you see and respond accordingly."
                else:
                    user_content = context
                    effective_system = system_prompt
                
                response = client.responses.create(
                    model="grok-4-1-fast-reasoning",
                    input=[
                        {"role": "system", "content": effective_system},
                        {"role": "user", "content": user_content}
                    ],
                    tools=[] if (platform_question or professional_advice_question) else [
                        {"type": "web_search"},
                        {"type": "x_search"}
                    ],
                    max_output_tokens=600
                )
                
                ai_response = response.output_text.strip() if hasattr(response, 'output_text') and response.output_text else None
                if ai_response:
                    logger.info("Steve post reply Grok 4.1 Fast successful")
                    
            except Exception as ai_err:
                logger.error(f"AI error in Steve post reply: {ai_err}")
                return
            
            if not ai_response:
                logger.warning("No AI response for Steve post reply")
                return

            try:
                from backend.services.steve_platform_manual import append_professional_disclaimer_if_needed
                ai_response = append_professional_disclaimer_if_needed(ai_response, post_content)
            except Exception as safety_err:
                logger.warning("Steve feed safety footer failed (non-fatal): %s", safety_err)
            
            # Format URLs in response as clickable links with readable text
            ai_response = format_steve_response_links(ai_response)
            
            # Create Steve's reply to the post
            now = datetime.utcnow()
            timestamp_db = now.strftime('%Y-%m-%d %H:%M:%S')
            
            c.execute(f"""
                INSERT INTO replies (post_id, username, content, timestamp, community_id, parent_reply_id)
                VALUES ({placeholder}, {placeholder}, {placeholder}, {placeholder}, {placeholder}, {placeholder})
            """, (post_id, AI_USERNAME, ai_response, timestamp_db, community_id, None))
            
            steve_reply_id = c.lastrowid
            conn.commit()
            
            # MIGRATED to backend/services/ai_usage.py — safe to delete when monolith-split runs
            try:
                _ai_usage.log_usage(
                    author_username,
                    surface=_ai_usage.SURFACE_FEED,
                    request_type='steve_post_reply',
                    community_id=community_id,
                    model='grok-4-1-fast-reasoning',
                )
            except Exception:
                pass
            
            logger.info(f"Steve replied to post {post_id} with reply ID {steve_reply_id}")
            
    except Exception as e:
        logger.error(f"Error in trigger_steve_reply_to_post: {e}", exc_info=True)


