@app.route('/get_reply_reactors/<int:reply_id>')
@login_required
def get_reply_reactors(reply_id: int):
    """Return users who reacted to a reply + viewers, mirroring get_post_reactors."""
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()
            c.execute(f"SELECT id FROM replies WHERE id = {ph}", (reply_id,))
            if not c.fetchone():
                return jsonify({'success': False, 'error': 'Reply not found'}), 404

            c.execute(f"""
                SELECT rr.reaction_type, rr.username, up.profile_picture
                FROM reply_reactions rr
                LEFT JOIN user_profiles up ON up.username = rr.username
                WHERE rr.reply_id = {ph}
                ORDER BY rr.reaction_type, rr.id DESC
            """, (reply_id,))
            rows = c.fetchall() or []

            by_type: dict = {}
            for row in rows:
                if hasattr(row, 'keys'):
                    rt = row['reaction_type']
                    uname = row['username']
                    pic = row.get('profile_picture') if 'profile_picture' in row.keys() else None
                else:
                    rt, uname = row[0], row[1]
                    pic = row[2] if len(row) > 2 else None
                by_type.setdefault(rt, []).append({'username': uname, 'profile_picture': pic})

            groups = [{'reaction_type': k, 'users': v} for k, v in by_type.items()]
            order = {'heart': 0, 'thumbs-up': 1, 'thumbs-down': 2}
            groups.sort(key=lambda g: order.get(g['reaction_type'], 99))

            def _normalize_pic(value):
                if not value:
                    return None
                s = str(value).strip()
                if s.startswith(('http://', 'https://', '/uploads', '/static')):
                    return s
                if s.startswith('uploads/'):
                    return '/' + s
                return f"/uploads/{s}"

            for g in groups:
                for u in g['users']:
                    u['profile_picture'] = _normalize_pic(u.get('profile_picture'))

            ensure_reply_views_table(c)
            view_count = _count_reply_views_excluding_admin(c, reply_id)
            viewers: list = []
            try:
                c.execute(f"""
                    SELECT rv.username, rv.viewed_at, up.profile_picture
                    FROM reply_views rv
                    LEFT JOIN user_profiles up ON up.username = rv.username
                    WHERE rv.reply_id = {ph}
                      AND LOWER(rv.username) <> LOWER({ph})
                    ORDER BY rv.viewed_at DESC
                    LIMIT 100
                """, (reply_id, 'admin'))
                viewer_rows = c.fetchall() or []
            except Exception:
                viewer_rows = []

            for vr in viewer_rows:
                if hasattr(vr, 'keys'):
                    uname = vr.get('username')
                    viewed_at_raw = vr.get('viewed_at')
                    pic = vr.get('profile_picture')
                else:
                    uname = vr[0] if len(vr) > 0 else None
                    viewed_at_raw = vr[1] if len(vr) > 1 else None
                    pic = vr[2] if len(vr) > 2 else None
                if not uname:
                    continue
                viewed_at_str = viewed_at_raw.isoformat() if isinstance(viewed_at_raw, datetime) else (str(viewed_at_raw).strip() if viewed_at_raw else None)
                viewers.append({
                    'username': uname,
                    'profile_picture': _normalize_pic(pic),
                    'viewed_at': viewed_at_str,
                })

            return jsonify({
                'success': True,
                'groups': groups,
                'view_count': int(view_count or 0),
                'viewers': viewers,
            })
    except Exception as e:
        logger.error(f"get_reply_reactors error: {e}")
        return jsonify({'success': False, 'error': 'Server error'}), 500


@app.route('/get_post')
@login_required
def get_post():
    username = session.get('username')
    post_id = request.args.get('post_id', type=int)
    
    if not post_id:
        return jsonify({'success': False, 'error': 'Post ID is required'}), 400
    
    # --- Firestore dual-read with MySQL hydration ---
    try:
        from backend.services.firestore_reads import USE_FIRESTORE_READS
        if USE_FIRESTORE_READS:
            from backend.services.firestore_reads import get_post_detail as fs_get_post
            fs_post = fs_get_post(post_id, username)
            if fs_post:
                try:
                    with get_db_connection() as hconn:
                        hc = hconn.cursor()
                        # Always prefer MySQL content (authoritative after edits)
                        mysql_row = None
                        try:
                            hc.execute("SELECT content, link_urls, community_id FROM posts WHERE id = ?", (post_id,))
                            mysql_row = hc.fetchone()
                        except Exception:
                            try:
                                hc.execute("SELECT content, community_id FROM posts WHERE id = ?", (post_id,))
                                mysql_row = hc.fetchone()
                            except Exception:
                                mysql_row = None
                        if mysql_row:
                            mysql_content = mysql_row['content'] if hasattr(mysql_row, 'keys') else mysql_row[0]
                            if mysql_content:
                                fs_post['content'] = mysql_content
                            fs_community_id = None
                            lu = None
                            try:
                                if hasattr(mysql_row, 'keys'):
                                    fs_community_id = mysql_row.get('community_id')
                                    lu = mysql_row.get('link_urls')
                                elif len(mysql_row) >= 3:
                                    lu = mysql_row[1]
                                    fs_community_id = mysql_row[2]
                                else:
                                    fs_community_id = mysql_row[1]
                                if isinstance(lu, str) and lu.strip():
                                    fs_post['link_urls'] = json.loads(lu)
                                elif isinstance(lu, list):
                                    fs_post['link_urls'] = lu
                            except Exception:
                                fs_community_id = (
                                    mysql_row.get('community_id')
                                    if hasattr(mysql_row, 'keys')
                                    else (mysql_row[2] if len(mysql_row) > 2 else mysql_row[1])
                                )
                        else:
                            fs_community_id = fs_post.get('community_id')

                        # Post view count
                        try:
                            hc.execute("SELECT COUNT(*) as cnt FROM post_views WHERE post_id = ?", (post_id,))
                            vr = hc.fetchone()
                            fs_post['view_count'] = int((vr['cnt'] if hasattr(vr, 'keys') else vr[0]) if vr else 0)
                        except Exception:
                            pass

                        # Community admin flag
                        fs_post['is_community_admin'] = bool(
                            fs_community_id and (
                                is_community_owner(username, fs_community_id)
                                or is_community_admin(username, fs_community_id)
                            )
                        )

                        # Hydrate replies: view counts, profile pics, reactions
                        all_reply_ids = []
                        def _collect_reply_ids(replies):
                            for r in replies:
                                all_reply_ids.append(r['id'])
                                _collect_reply_ids(r.get('children', []))
                        _collect_reply_ids(fs_post.get('replies', []))

                        if all_reply_ids:
                            ph = get_sql_placeholder()
                            phs = ','.join([ph] * len(all_reply_ids))

                            # Firestore can contain stale reply docs if an older delete path
                            # removed only the SQL row. Filter the visible reply tree against
                            # authoritative SQL ids before hydrating anything else.
                            valid_reply_ids = set(all_reply_ids)
                            try:
                                hc.execute(
                                    f"SELECT id FROM replies WHERE id IN ({phs})",
                                    tuple(all_reply_ids),
                                )
                                valid_reply_ids = {
                                    int(row['id'] if hasattr(row, 'keys') else row[0])
                                    for row in (hc.fetchall() or [])
                                }
                            except Exception:
                                valid_reply_ids = set(all_reply_ids)

                            if valid_reply_ids != set(all_reply_ids):
                                def _filter_existing_replies(replies):
                                    visible_replies = []
                                    for reply in replies:
                                        rid = int(reply.get('id') or 0)
                                        if rid not in valid_reply_ids:
                                            continue
                                        children = _filter_existing_replies(reply.get('children', []))
                                        reply['children'] = children
                                        reply['reply_count'] = len(children)
                                        visible_replies.append(reply)
                                    return visible_replies
                                fs_post['replies'] = _filter_existing_replies(fs_post.get('replies', []))
                                all_reply_ids = [rid for rid in all_reply_ids if rid in valid_reply_ids]
                                if not all_reply_ids:
                                    fs_post['replies'] = []
                                phs = ','.join([ph] * len(all_reply_ids)) if all_reply_ids else ''

                            # Reply view counts
                            reply_vcs = {}
                            try:
                                ensure_reply_views_table(hc)
                                params_rv = list(all_reply_ids) + ['admin']
                                hc.execute(
                                    f"SELECT reply_id, COUNT(*) as cnt FROM reply_views WHERE reply_id IN ({phs}) AND LOWER(username) <> LOWER({ph}) GROUP BY reply_id",
                                    tuple(params_rv),
                                )
                                for row in hc.fetchall():
                                    rid = row['reply_id'] if hasattr(row, 'keys') else row[0]
                                    cnt = row['cnt'] if hasattr(row, 'keys') else row[1]
                                    reply_vcs[int(rid)] = int(cnt or 0)
                            except Exception:
                                pass

                            # Reply profile pictures
                            reply_authors = set()
                            def _collect_authors(replies):
                                for r in replies:
                                    if r.get('username'):
                                        reply_authors.add(r['username'])
                                    _collect_authors(r.get('children', []))
                            _collect_authors(fs_post.get('replies', []))
                            pp_map = {}
                            if reply_authors:
                                a_phs = ','.join([ph] * len(reply_authors))
                                try:
                                    hc.execute(f"SELECT username, profile_picture FROM user_profiles WHERE username IN ({a_phs})", tuple(reply_authors))
                                    for row in hc.fetchall():
                                        pp_map[row['username'] if hasattr(row, 'keys') else row[0]] = row['profile_picture'] if hasattr(row, 'keys') else row[1]
                                except Exception:
                                    pass

                            # Reply reactions
                            reply_rxs = {}
                            user_reply_rxs = {}
                            try:
                                hc.execute(f"SELECT reply_id, reaction_type, COUNT(*) as count FROM reply_reactions WHERE reply_id IN ({phs}) GROUP BY reply_id, reaction_type", tuple(all_reply_ids))
                                for row in hc.fetchall():
                                    rid = row['reply_id'] if hasattr(row, 'keys') else row[0]
                                    rtype = row['reaction_type'] if hasattr(row, 'keys') else row[1]
                                    cnt = row['count'] if hasattr(row, 'keys') else row[2]
                                    reply_rxs.setdefault(int(rid), {})[rtype] = cnt
                            except Exception:
                                pass
                            try:
                                params_urx = list(all_reply_ids) + [username]
                                hc.execute(f"SELECT reply_id, reaction_type FROM reply_reactions WHERE reply_id IN ({phs}) AND username = {ph}", tuple(params_urx))
                                for row in hc.fetchall():
                                    rid = row['reply_id'] if hasattr(row, 'keys') else row[0]
                                    rtype = row['reaction_type'] if hasattr(row, 'keys') else row[1]
                                    user_reply_rxs[int(rid)] = rtype
                            except Exception:
                                pass

                            reply_media = {}
                            try:
                                hc.execute(
                                    f"SELECT id, image_path, video_path, audio_path, audio_summary FROM replies WHERE id IN ({phs})",
                                    tuple(all_reply_ids),
                                )
                                for row in hc.fetchall() or []:
                                    if hasattr(row, 'keys'):
                                        rid = int(row['id'])
                                        reply_media[rid] = {
                                            'image_path': row.get('image_path'),
                                            'video_path': row.get('video_path'),
                                            'audio_path': row.get('audio_path'),
                                            'audio_summary': row.get('audio_summary'),
                                        }
                                    else:
                                        rid = int(row[0])
                                        reply_media[rid] = {
                                            'image_path': row[1] if len(row) > 1 else None,
                                            'video_path': row[2] if len(row) > 2 else None,
                                            'audio_path': row[3] if len(row) > 3 else None,
                                            'audio_summary': row[4] if len(row) > 4 else None,
                                        }
                            except Exception:
                                pass

                            # Apply hydrated data to replies
                            def _hydrate(replies):
                                for r in replies:
                                    rid = r['id']
                                    r['view_count'] = reply_vcs.get(rid, 0)
                                    r['profile_picture'] = pp_map.get(r.get('username'))
                                    r['reactions'] = reply_rxs.get(rid, {})
                                    r['user_reaction'] = user_reply_rxs.get(rid)
                                    media = reply_media.get(int(rid))
                                    if media:
                                        if media.get('image_path'):
                                            r['image_path'] = media['image_path']
                                        if media.get('video_path'):
                                            r['video_path'] = media['video_path']
                                        if media.get('audio_path'):
                                            r['audio_path'] = media['audio_path']
                                        if media.get('audio_summary') is not None:
                                            r['audio_summary'] = media['audio_summary']
                                    _hydrate(r.get('children', []))
                            _hydrate(fs_post.get('replies', []))

                        # Post author profile picture
                        try:
                            hc.execute("SELECT profile_picture FROM user_profiles WHERE username = ?", (fs_post.get('username', ''),))
                            pp = hc.fetchone()
                            fs_post['profile_picture'] = pp['profile_picture'] if pp and 'profile_picture' in pp.keys() else None
                        except Exception:
                            pass

                except Exception as hydrate_err:
                    logger.warning(f"MySQL hydration of Firestore post failed (serving Firestore as-is): {hydrate_err}")

                logger.info(f"Firestore+MySQL hybrid post read: post {post_id}")
                return jsonify({'success': True, 'post': fs_post})
    except Exception as fs_err:
        logger.warning(f"Firestore post read failed, falling back to MySQL: {fs_err}")

    # Full MySQL fallback
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            
            # Fetch the post
            c.execute("SELECT * FROM posts WHERE id = ?", (post_id,))
            post_raw = c.fetchone()
            
            if not post_raw:
                return jsonify({'success': False, 'error': 'Post not found'}), 404
            
            post = dict(post_raw)
            try:
                lu = post.get('link_urls')
                if isinstance(lu, str) and lu.strip():
                    post['link_urls'] = json.loads(lu)
            except Exception:
                pass
            allow_nsfw_imagine = False
            community_id = post.get('community_id') if isinstance(post, dict) else None
            if community_id:
                try:
                    c.execute("SELECT allow_nsfw_imagine FROM communities WHERE id = ?", (community_id,))
                    allow_row = c.fetchone()
                    if allow_row is not None:
                        allow_nsfw_imagine = bool(allow_row['allow_nsfw_imagine'] if hasattr(allow_row, 'keys') else allow_row[0])
                except Exception as allow_err:
                    logger.warning(f"Failed to fetch allow_nsfw_imagine for community {community_id}: {allow_err}")
            post['allow_nsfw_imagine'] = allow_nsfw_imagine
            # Attach profile picture for post author
            try:
                c.execute("SELECT profile_picture FROM user_profiles WHERE username = ?", (post['username'],))
                pp = c.fetchone()
                post['profile_picture'] = pp['profile_picture'] if pp and 'profile_picture' in pp.keys() else None
            except Exception:
                post['profile_picture'] = None
            
            # Fetch replies for the post (top-level first)
            c.execute("SELECT * FROM replies WHERE post_id = ? ORDER BY timestamp DESC", (post_id,))
            replies_raw = [dict(row) for row in c.fetchall()]
            # Build nested tree by parent_reply_id
            children_map = {}
            for r in replies_raw:
                pid = r.get('parent_reply_id')
                children_map.setdefault(pid, []).append(r)
            def build_tree(parent_id=None):
                arr = []
                for r in children_map.get(parent_id, []):
                    r['children'] = build_tree(r['id'])
                    arr.append(r)
                return arr
            post['replies'] = build_tree(None)
            
            reaction_counts, user_reaction = get_post_reaction_summary(c, post_id, username)
            post['reactions'] = reaction_counts
            post['user_reaction'] = user_reaction
            
            # Add reaction counts for each reply and user reaction
            def hydrate_reply_metrics(reply):
                # Attach profile picture per reply
                try:
                    c.execute("SELECT profile_picture FROM user_profiles WHERE username = ?", (reply['username'],))
                    pr = c.fetchone()
                    reply['profile_picture'] = pr['profile_picture'] if pr and 'profile_picture' in pr.keys() else None
                except Exception:
                    reply['profile_picture'] = None
                counts, user_reaction = get_reply_reaction_summary(c, reply['id'], username)
                reply['reactions'] = counts
                reply['user_reaction'] = user_reaction
                try:
                    ensure_reply_views_table(c)
                    reply['view_count'] = _count_reply_views_excluding_admin(c, reply['id'])
                except Exception:
                    reply['view_count'] = 0
                try:
                    c.execute("SELECT COUNT(*) as cnt FROM replies WHERE parent_reply_id = ?", (reply['id'],))
                    cnt_row = c.fetchone()
                    reply['reply_count'] = cnt_row['cnt'] if cnt_row and hasattr(cnt_row, 'keys') else (cnt_row[0] if cnt_row else 0)
                except Exception:
                    reply['reply_count'] = len(reply.get('children', []))
                for ch in reply.get('children', []):
                    hydrate_reply_metrics(ch)
            for reply in post['replies']:
                hydrate_reply_metrics(reply)

            # Fetch AI videos for carousel
            c.execute("""
                SELECT ij.result_path, ij.created_by, ij.created_at, ij.style
                FROM imagine_jobs ij
                WHERE ij.target_type = 'post'
                AND ij.target_id = ?
                AND ij.status = 'completed'
                AND ij.result_path IS NOT NULL
                ORDER BY ij.created_at ASC
            """, (post_id,))
            ai_videos_raw = c.fetchall()
            post['ai_videos'] = [
                {
                    'video_path': row['result_path'],
                    'generated_by': row['created_by'],
                    'created_at': row['created_at'],
                    'style': row['style']
                }
                for row in ai_videos_raw
            ]

            # Add view count
            try:
                c.execute("SELECT COUNT(*) as cnt FROM post_views WHERE post_id = ?", (post_id,))
                view_row = c.fetchone()
                post['view_count'] = view_row['cnt'] if view_row and hasattr(view_row, 'keys') else (view_row[0] if view_row else 0)
            except Exception as view_err:
                logger.warning(f"Failed to get view count for post {post_id}: {view_err}")
                post['view_count'] = 0

            # Community admin/owner flag so the frontend can show delete/edit for all posts
            post_community_id = post.get('community_id')
            post['is_community_admin'] = bool(
                post_community_id and (
                    is_community_owner(username, post_community_id)
                    or is_community_admin(username, post_community_id)
                )
            )

            return jsonify({'success': True, 'post': post})
            
    except Exception as e:
        logger.error(f"Error fetching post {post_id}: {str(e)}")
        return jsonify({'success': False, 'error': 'Server error'}), 500


@app.route('/api/post/<int:post_id>/summary', methods=['GET'])
@login_required
def get_post_summary(post_id: int):
    """Generate an AI summary of a post and its discussion using Grok."""
    username = session.get('username')
    
    if not XAI_API_KEY:
        return jsonify({'success': False, 'error': 'AI service not available'}), 503
    
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()
            
            # Fetch the post
            c.execute(f"SELECT id, username, content, timestamp FROM posts WHERE id = {ph}", (post_id,))
            post_raw = c.fetchone()
            
            if not post_raw:
                return jsonify({'success': False, 'error': 'Post not found'}), 404
            
            post_author = post_raw['username'] if hasattr(post_raw, 'keys') else post_raw[1]
            post_content = post_raw['content'] if hasattr(post_raw, 'keys') else post_raw[2]
            
            # Fetch all replies for the post
            c.execute(f"""
                SELECT username, content, timestamp 
                FROM replies 
                WHERE post_id = {ph} 
                ORDER BY timestamp ASC
            """, (post_id,))
            replies_raw = c.fetchall()
            
            # Build the discussion content
            discussion_parts = [f"Original post by @{post_author}:\n{post_content}"]
            
            if replies_raw:
                discussion_parts.append("\n\nComments and replies:")
                for reply in replies_raw:
                    reply_author = reply['username'] if hasattr(reply, 'keys') else reply[0]
                    reply_content = reply['content'] if hasattr(reply, 'keys') else reply[1]
                    discussion_parts.append(f"\n@{reply_author}: {reply_content}")
            
            full_discussion = "\n".join(discussion_parts)
            
            # Limit discussion length to avoid token limits
            if len(full_discussion) > 8000:
                full_discussion = full_discussion[:8000] + "\n\n[Discussion truncated due to length...]"
            
            # Generate summary using Grok
            from openai import OpenAI
            from datetime import datetime
            
            current_datetime = datetime.utcnow()
            
            system_prompt = """You are a helpful assistant that summarizes social media discussions.

LANGUAGE RULE: Detect the language of the discussion and write your summary in THAT SAME language.
- If the discussion is in Portuguese, write the summary in European Portuguese (PT-PT).
- If in English, write in English.
- If in Spanish, write in Spanish.

Create a clear, concise summary that captures:
1. The main topic or point of the original post
2. Key points raised in the comments
3. Any consensus or disagreements
4. Notable insights or conclusions

Keep the summary to 3-5 sentences maximum. Be objective and informative."""

            context = f"Please summarize this discussion:\n\n{full_discussion}"
            
            client = OpenAI(
                api_key=XAI_API_KEY,
                base_url="https://api.x.ai/v1"
            )
            
            response = client.chat.completions.create(
                model="grok-4-1-fast-non-reasoning",
                messages=[
                    {"role": "system", "content": system_prompt},
                    {"role": "user", "content": context}
                ],
                max_tokens=500,
                temperature=0.5
            )
            
            summary = response.choices[0].message.content.strip() if response.choices else None
            
            if not summary:
                return jsonify({'success': False, 'error': 'Failed to generate summary'}), 500
            
            return jsonify({
                'success': True, 
                'summary': summary,
                'post_id': post_id,
                'reply_count': len(replies_raw)
            })
            
    except Exception as e:
        logger.error(f"Error generating summary for post {post_id}: {str(e)}")
        return jsonify({'success': False, 'error': 'Failed to generate summary'}), 500


@app.route('/api/reply/<int:reply_id>')
@login_required
def api_get_reply(reply_id):
    """Get a specific reply with its nested replies (X/Twitter style thread view)."""
    username = session.get('username')
    
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()
            
            # Fetch the main reply
            c.execute(f"SELECT * FROM replies WHERE id = {ph}", (reply_id,))
            reply_raw = c.fetchone()
            
            if not reply_raw:
                return jsonify({'success': False, 'error': 'Reply not found'}), 404
            
            reply = dict(reply_raw)
            post_id = reply.get('post_id')
            
            # Get the parent post info
            c.execute(f"SELECT id, username, content, community_id, timestamp FROM posts WHERE id = {ph}", (post_id,))
            post_raw = c.fetchone()
            post_info = dict(post_raw) if post_raw else None
            
            # Get profile picture for the main reply
            try:
                c.execute(f"SELECT profile_picture FROM user_profiles WHERE username = {ph}", (reply['username'],))
                pp = c.fetchone()
                reply['profile_picture'] = pp['profile_picture'] if pp and hasattr(pp, 'keys') else (pp[0] if pp else None)
            except Exception:
                reply['profile_picture'] = None
            
            # Get reaction counts and user reaction for main reply
            reply_counts, reply_user_reaction = get_reply_reaction_summary(c, reply_id, username)
            reply['reactions'] = reply_counts
            reply['user_reaction'] = reply_user_reaction
            try:
                ensure_reply_views_table(c)
                reply['view_count'] = _count_reply_views_excluding_admin(c, reply_id)
            except Exception:
                reply['view_count'] = 0
            
            # Fetch all nested replies (replies to this reply)
            c.execute(f"SELECT * FROM replies WHERE parent_reply_id = {ph} ORDER BY timestamp ASC", (reply_id,))
            nested_replies_raw = c.fetchall()
            nested_replies = [dict(r) for r in nested_replies_raw]
            
            # Collect usernames for profile pictures
            nested_usernames = set(r['username'] for r in nested_replies if r.get('username'))
            
            # Batch fetch profile pictures
            pp_map = {}
            if nested_usernames:
                user_placeholders = ','.join([ph for _ in nested_usernames])
                c.execute(f"SELECT username, profile_picture FROM user_profiles WHERE username IN ({user_placeholders})", tuple(nested_usernames))
                for r in c.fetchall():
                    uname = r['username'] if hasattr(r, 'keys') else r[0]
                    pp = r['profile_picture'] if hasattr(r, 'keys') else r[1]
                    pp_map[uname] = pp
            
            # Hydrate nested replies with profile pics, reactions, and view counts
            for nr in nested_replies:
                nr['profile_picture'] = pp_map.get(nr['username'])
                nr_counts, nr_user_reaction = get_reply_reaction_summary(c, nr['id'], username)
                nr['reactions'] = nr_counts
                nr['user_reaction'] = nr_user_reaction
                try:
                    nr['view_count'] = _count_reply_views_excluding_admin(c, nr['id'])
                except Exception:
                    nr['view_count'] = 0
                c.execute(f"SELECT COUNT(*) as cnt FROM replies WHERE parent_reply_id = {ph}", (nr['id'],))
                cnt_row = c.fetchone()
                nr['reply_count'] = cnt_row['cnt'] if cnt_row and hasattr(cnt_row, 'keys') else (cnt_row[0] if cnt_row else 0)
            
            reply['nested_replies'] = nested_replies
            
            # Count direct replies to the main reply
            c.execute(f"SELECT COUNT(*) as cnt FROM replies WHERE parent_reply_id = {ph}", (reply_id,))
            cnt_row = c.fetchone()
            reply['reply_count'] = cnt_row['cnt'] if cnt_row and hasattr(cnt_row, 'keys') else (cnt_row[0] if cnt_row else 0)
            
            # Build the full parent chain (all ancestors from root comment to immediate parent)
            parent_chain = []
            current_parent_id = reply.get('parent_reply_id')
            while current_parent_id:
                c.execute(
                    f"SELECT id, username, content, timestamp, parent_reply_id, image_path, video_path, audio_path, audio_summary FROM replies WHERE id = {ph}",
                    (current_parent_id,),
                )
                parent_raw = c.fetchone()
                if not parent_raw:
                    break
                parent_data = dict(parent_raw)
                # Get profile picture
                c.execute(f"SELECT profile_picture FROM user_profiles WHERE username = {ph}", (parent_data['username'],))
                pp = c.fetchone()
                parent_data['profile_picture'] = pp['profile_picture'] if pp and hasattr(pp, 'keys') else (pp[0] if pp else None)
                parent_chain.insert(0, parent_data)  # Insert at beginning to maintain order (oldest first)
                current_parent_id = parent_data.get('parent_reply_id')
            
            # Also get post author's profile picture
            if post_info:
                c.execute(f"SELECT profile_picture FROM user_profiles WHERE username = {ph}", (post_info['username'],))
                pp = c.fetchone()
                post_info['profile_picture'] = pp['profile_picture'] if pp and hasattr(pp, 'keys') else (pp[0] if pp else None)
                # Get post image if any
                c.execute(f"SELECT image_path FROM posts WHERE id = {ph}", (post_id,))
                post_img = c.fetchone()
                post_info['image_path'] = post_img['image_path'] if post_img and hasattr(post_img, 'keys') else (post_img[0] if post_img else None)
            
            return jsonify({
                'success': True,
                'reply': reply,
                'post': post_info,
                'parent_chain': parent_chain  # Full chain from root comment to immediate parent
            })
            
    except Exception as e:
        logger.error(f"Error fetching reply {reply_id}: {str(e)}")
        return jsonify({'success': False, 'error': 'Server error'}), 500

