APP_STORE_URL = "https://apps.apple.com/us/app/cpoint/id6755534074"
DEFAULT_INVITE_LOGO = '/static/cpoint-logo.svg'

@app.route('/api/public/logo')
def api_public_logo():
    """Public logo endpoint (no auth). Returns R2 logo URL or redirects to it."""
    logo_url = get_invite_logo_url()
    if not logo_url or not logo_url.startswith('http'):
        base = PUBLIC_BASE_URL or request.host_url.rstrip('/')
        logo_url = f"{base}{logo_url}" if logo_url else f"{base}/static/cpoint-logo.svg"
    return redirect(logo_url)

def get_invite_logo_url():
    """Get the invite logo URL from database, resolving R2 paths to full URLs."""
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            if USE_MYSQL:
                c.execute("SELECT `value` FROM site_settings WHERE `key` = 'invite_logo'")
            else:
                c.execute("SELECT value FROM site_settings WHERE key = 'invite_logo'")
            row = c.fetchone()
            if row:
                val = row[0] if isinstance(row, tuple) else row['value']
                if val:
                    if val.startswith('http'):
                        return val
                    # Resolve R2 path to full URL - ONLY via R2_PUBLIC_URL
                    try:
                        from backend.services.r2_storage import R2_PUBLIC_URL
                        if R2_PUBLIC_URL:
                            return f"{R2_PUBLIC_URL.rstrip('/')}/{val.lstrip('/')}"
                    except Exception:
                        pass
                    # R2 not available - fall through to default (don't return bare path)
    except Exception as e:
        logger.warning(f"Could not fetch invite logo: {e}")
    # Fallback: absolute URL to default logo (never return a relative path)
    base = PUBLIC_BASE_URL or 'https://app.c-point.co'
    return f"{base}/static/cpoint-logo.svg"

@app.route('/invite/<token>')
def invite_landing(token):
    """Invite landing page - always directs users to the app"""
    user_agent = request.headers.get('User-Agent', '').lower()
    is_ios = 'iphone' in user_agent or 'ipad' in user_agent or 'ipod' in user_agent
    is_android = 'android' in user_agent
    
    logo_url = get_invite_logo_url()
    base_url = PUBLIC_BASE_URL or request.host_url.rstrip('/')
    
    # Verify the invitation exists
    community_name = "a community"
    invited_by = "a member"
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            c.execute("""
                SELECT c.name as community_name, ci.invited_by_username, ci.used
                FROM community_invitations ci
                JOIN communities c ON ci.community_id = c.id
                WHERE ci.token = ?
            """, (token,))
            invitation = c.fetchone()
            if invitation:
                community_name = invitation['community_name'] if hasattr(invitation, 'keys') else invitation[0]
                invited_by = invitation['invited_by_username'] if hasattr(invitation, 'keys') else invitation[1]
                used = invitation['used'] if hasattr(invitation, 'keys') else invitation[2]
    except Exception as e:
        logger.error(f"Error in invite_landing: {e}")
    
    app_store_url = APP_STORE_URL if 'APP_STORE_URL' in dir() else "https://apps.apple.com/app/id6755534074"
    play_store_url = f"https://play.google.com/store/apps/details?id=co.cpoint.app"

    # Build the "Open in App" target. On Android we use an intent:// URL so Chrome
    # can open the app (via the verified https App Link) or fall back to the Play
    # Store natively — no confirm() dialog, no JS timer required. iOS / desktop
    # fall back to the custom cpoint:// scheme, which Safari routes through the
    # system "Open in C.Point?" sheet or Universal Links.
    if is_android:
        android_fallback = quote(play_store_url, safe='')
        app_url = (
            f"intent://app.c-point.co/invite/{token}"
            f"#Intent;scheme=https;package=co.cpoint.app;"
            f"S.browser_fallback_url={android_fallback};end"
        )
    else:
        app_url = f"cpoint://invite/{token}"

    store_href = app_store_url if is_ios else (play_store_url if is_android else app_store_url)
    store_label = "Download from App Store" if is_ios else ("Download from Google Play" if is_android else "Download the App")
    store_btn = f'<a href="{store_href}" class="btn btn-secondary" id="storeDownloadBtn">{store_label}</a>'
    invite_https_url = f"{base_url}/invite/{token}"
    token_js = json.dumps(token)
    invite_https_js = json.dumps(invite_https_url)
    store_href_js = json.dumps(store_href)
    is_android_js = 'true' if is_android else 'false'
    is_ios_js = 'true' if is_ios else 'false'

    return f"""<!DOCTYPE html>
<html><head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <meta name="apple-itunes-app" content="app-id=6755534074, app-argument=https://app.c-point.co/invite/{token}">
    <title>Join {community_name} on C.Point</title>
    <style>
        * {{ margin:0; padding:0; box-sizing:border-box; }}
        body {{ font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif; background:#000; color:#fff; min-height:100vh; display:flex; align-items:center; justify-content:center; padding:20px; }}
        .container {{ max-width:400px; text-align:center; }}
        .logo {{ width:80px; height:80px; margin:0 auto 20px; }}
        .logo img {{ width:100%; height:100%; object-fit:contain; border-radius:16px; }}
        h1 {{ font-size:22px; margin-bottom:10px; }}
        .invite-info {{ color:#4db6ac; font-size:17px; margin-bottom:6px; }}
        .invited-by {{ color:#888; font-size:13px; margin-bottom:28px; }}
        .btn {{ display:block; width:100%; padding:14px 24px; border-radius:12px; text-decoration:none; font-weight:600; font-size:15px; margin-bottom:10px; border:none; cursor:pointer; }}
        .btn:active {{ opacity:0.8; }}
        .btn-primary {{ background:#4db6ac; color:#000; }}
        .btn-secondary {{ background:#1a1a1a; color:#fff; border:1px solid #333; }}
        .hint {{ color:#666; font-size:12px; margin-top:16px; line-height:1.5; }}
        .btn-tertiary {{ background:transparent; color:#888; font-size:13px; padding:10px; margin-top:4px; }}
    </style>
</head>
<body>
    <div class="container">
        <div class="logo"><img src="{logo_url}" alt="C.Point" /></div>
        <h1>You're Invited!</h1>
        <p class="invite-info">Join <strong>{community_name}</strong></p>
        <p class="invited-by">Invited by {invited_by}</p>
        <a href="{app_url}" class="btn btn-primary" id="openAppBtn">Open in C.Point App</a>
        <p style="color:#555; font-size:12px; margin:14px 0 10px;">Don't have the app yet?</p>
        {store_btn}
        <button type="button" class="btn btn-tertiary" id="copyInviteLinkBtn">Copy invite link</button>
        <p class="hint">After you install, open the app from your home screen — we save your invite automatically when you tap Download above. If you don&apos;t land in the right community, open this page again and tap &quot;Open in C.Point App&quot;, or on Sign in use &quot;Use invite from clipboard&quot;.</p>
    </div>
    <script>
(function() {{
        var IS_ANDROID = {is_android_js};
        var IS_IOS = {is_ios_js};
        var INVITE_TOKEN = {token_js};
        var INVITE_HTTPS_URL = {invite_https_js};
        var STORE_HREF = {store_href_js};
        var clipPayload = 'cpoint:invite:' + INVITE_TOKEN;
        function copyDeferredInvite() {{
            if (navigator.clipboard && navigator.clipboard.writeText) {{
                return navigator.clipboard.writeText(clipPayload);
            }}
            return Promise.reject();
        }}
        function copyInviteHttps() {{
            if (navigator.clipboard && navigator.clipboard.writeText) {{
                return navigator.clipboard.writeText(INVITE_HTTPS_URL);
            }}
            return Promise.reject();
        }}
        var openBtn = document.getElementById('openAppBtn');
        if (openBtn) {{
            openBtn.addEventListener('click', function(e) {{
                // Stash the token on the clipboard so a fresh install can pick it up.
                copyDeferredInvite().catch(function() {{}});

                // Android: href is an intent:// URL with S.browser_fallback_url.
                // Chrome opens the app via the verified https App Link if installed,
                // otherwise redirects to the Play Store on its own. No JS timer
                // and no confirm() dialog needed.
                if (IS_ANDROID) return;

                // iOS / desktop: let the anchor trigger cpoint://. If the app is
                // installed, Safari shows the system "Open in C.Point?" sheet and
                // the page goes hidden when it launches. If the app is not
                // installed, nothing happens — after a short delay we silently
                // redirect to the App Store. visibilitychange is the reliable
                // signal on iOS that the system handed off to the app.
                var cancelled = false;
                function cancelFallback() {{ cancelled = true; }}
                document.addEventListener('visibilitychange', function() {{
                    if (document.hidden) cancelFallback();
                }});
                window.addEventListener('pagehide', cancelFallback);
                window.addEventListener('blur', cancelFallback);
                setTimeout(function() {{
                    if (cancelled) return;
                    if (document.hidden) return;
                    window.location.href = STORE_HREF;
                }}, 2500);
            }});
        }}
        var storeBtn = document.getElementById('storeDownloadBtn');
        if (storeBtn) {{
            storeBtn.addEventListener('click', function(e) {{
                e.preventDefault();
                var href = storeBtn.getAttribute('href') || STORE_HREF;
                copyDeferredInvite().then(function() {{
                    window.location.href = href;
                }}).catch(function() {{
                    window.location.href = href;
                }});
            }});
        }}
        var copyLinkBtn = document.getElementById('copyInviteLinkBtn');
        if (copyLinkBtn) {{
            copyLinkBtn.addEventListener('click', function() {{
                copyInviteHttps().then(function() {{
                    copyLinkBtn.textContent = 'Copied!';
                    setTimeout(function() {{ copyLinkBtn.textContent = 'Copy invite link'; }}, 2000);
                }}).catch(function() {{}});
            }});
        }}
}})();
    </script>
</body></html>"""

@app.route('/api/invitation/verify', methods=['GET'])
def verify_invitation():
    """Verify invitation token and return invitation details"""
    token = request.args.get('token', '').strip()
    
    if not token:
        return jsonify({'success': False, 'error': 'Token required'}), 400
    
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            c.execute("""
                SELECT ci.id, ci.community_id, ci.invited_email, ci.used,
                       c.name as community_name, ci.invited_by_username
                FROM community_invitations ci
                JOIN communities c ON ci.community_id = c.id
                WHERE ci.token = ?
            """, (token,))
            
            invitation = c.fetchone()
            
            if not invitation:
                return jsonify({'success': False, 'error': 'Invalid invitation'}), 404
            
            used = invitation['used'] if hasattr(invitation, 'keys') else invitation[3]
            if used:
                return jsonify({'success': False, 'error': 'Invitation already used'}), 400
            
            return jsonify({
                'success': True,
                'email': invitation['invited_email'] if hasattr(invitation, 'keys') else invitation[2],
                'community_name': invitation['community_name'] if hasattr(invitation, 'keys') else invitation[4],
                'invited_by': invitation['invited_by_username'] if hasattr(invitation, 'keys') else invitation[5],
                'community_id': invitation['community_id'] if hasattr(invitation, 'keys') else invitation[1],
            })
            
    except Exception as e:
        logger.error(f"Error verifying invitation: {e}")
        return jsonify({'success': False, 'error': 'Server error'}), 500

