def _collect_mentions(text: str) -> list:
    """Return lowercased usernames mentioned with @, avoiding emails and words."""
    try:
        import re as _re
        # Negative lookbehind to ensure @ is not preceded by a word character (avoids emails)
        pattern = _re.compile(r"(?<!\w)@([A-Za-z0-9_]{1,30})")
        return list({ m.group(1).lower() for m in pattern.finditer(text or '') })
    except Exception:
        return []


def _truncate_notif_preview(text: str, max_len: int = 160) -> str:
    """Single-line truncated snippet for in-app / push notification previews."""
    if not text:
        return ""
    s = " ".join(str(text).replace("\r", " ").split())
    if len(s) <= max_len:
        return s
    return s[: max_len - 1].rstrip() + "…"


def process_mentions_for_post(post_id: int, author_username: str):
    """
    Process @mentions in a post and notify ALL mentioned users who exist on the platform.
    Users are ALWAYS notified when tagged, regardless of community membership.
    """
    try:
        ensure_notifications_preview_text_column()
        with get_db_connection() as conn:
            c = conn.cursor()
            c.execute("SELECT content, community_id FROM posts WHERE id = ?", (post_id,))
            row = c.fetchone()
            if not row:
                return
            content = row['content'] if hasattr(row, 'keys') else row[0]
            community_id = row['community_id'] if hasattr(row, 'keys') else row[1]
            mention_preview = _truncate_notif_preview(content or "")
            mentions = _collect_mentions(content)
            if not mentions:
                return
            
            current_lower = (author_username or '').lower()
            logger.info(f"[Mention Post] post_id={post_id} author={author_username} mentions={mentions}")
            
            # Resolve ALL mentioned usernames to actual users on the platform
            notified = set()
            for mention_lower in mentions:
                if mention_lower == current_lower:
                    continue  # Don't notify yourself
                
                # Find the user by username (case insensitive)
                c.execute("SELECT username FROM users WHERE LOWER(username)=? LIMIT 1", (mention_lower,))
                user_row = c.fetchone()
                if not user_row:
                    continue  # User doesn't exist on platform
                
                target = user_row['username'] if hasattr(user_row, 'keys') else user_row[0]
                if target in notified:
                    continue  # Already notified
                
                notified.add(target)
                
                try:
                    # Insert notification with link to post
                    notif_link = f"/post/{post_id}"
                    if USE_MYSQL:
                        c.execute("""
                            INSERT INTO notifications (user_id, from_user, type, post_id, community_id, message, created_at, is_read, link, preview_text)
                            VALUES (?, ?, 'mention_post', ?, ?, ?, NOW(), 0, ?, ?)
                            ON DUPLICATE KEY UPDATE created_at = NOW(), is_read = 0, message = VALUES(message), link = VALUES(link), preview_text = VALUES(preview_text)
                        """, (target, author_username, post_id, community_id, f"{author_username} mentioned you in a post", notif_link, mention_preview or None))
                    else:
                        now_ts = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                        c.execute("""
                            INSERT INTO notifications (user_id, from_user, type, post_id, community_id, message, created_at, is_read, link, preview_text)
                            VALUES (?, ?, 'mention_post', ?, ?, ?, ?, 0, ?, ?)
                        """, (target, author_username, post_id, community_id, f"{author_username} mentioned you in a post", now_ts, notif_link, mention_preview or None))
                    conn.commit()
                    
                    # Send push notification
                    try:
                        send_push_to_user(target, {
                            'title': 'You were mentioned',
                            'body': mention_preview or f"{author_username} mentioned you in a post",
                            'url': notif_link,
                            'tag': f"mention-post-{post_id}-{target}"
                        })
                    except Exception as pe:
                        logger.warning(f"[Mention Post] push error to {target}: {pe}")
                except Exception as ne:
                    logger.warning(f"[Mention Post] db error for {target}: {ne}")
            
            logger.info(f"[Mention Post] Notified {len(notified)} users: {list(notified)}")
    except Exception as e:
        logger.warning(f"process_mentions_for_post error: {e}")

def process_mentions_for_reply(post_id: int, author_username: str, community_id: int|None, reply_id: int|None = None):
    """
    Process @mentions in a reply and notify ALL mentioned users who exist on the platform.
    Users are ALWAYS notified when tagged, regardless of community membership.
    Works for comments, replies, and nested replies.
    """
    try:
        ensure_notifications_preview_text_column()
        with get_db_connection() as conn:
            c = conn.cursor()
            # Get exact reply content if reply_id provided, else most recent by this author/post
            if reply_id:
                c.execute("SELECT content FROM replies WHERE id=? LIMIT 1", (reply_id,))
            else:
                c.execute("""
                    SELECT content FROM replies
                    WHERE post_id=? AND username=?
                    ORDER BY id DESC
                    LIMIT 1
                """, (post_id, author_username))
            row = c.fetchone()
            if not row:
                return
            content = row['content'] if hasattr(row, 'keys') else row[0]
            reply_preview = _truncate_notif_preview(content or "")
            mentions = _collect_mentions(content)
            if not mentions:
                return
            
            current_lower = (author_username or '').lower()
            logger.info(f"[Mention Reply] post_id={post_id} reply_id={reply_id} author={author_username} mentions={mentions}")
            
            # Resolve ALL mentioned usernames to actual users on the platform
            notified = set()
            for mention_lower in mentions:
                if mention_lower == current_lower:
                    continue  # Don't notify yourself
                
                # Find the user by username (case insensitive)
                c.execute("SELECT username FROM users WHERE LOWER(username)=? LIMIT 1", (mention_lower,))
                user_row = c.fetchone()
                if not user_row:
                    continue  # User doesn't exist on platform
                
                target = user_row['username'] if hasattr(user_row, 'keys') else user_row[0]
                if target in notified:
                    continue  # Already notified
                
                notified.add(target)
                
                # Use reply page URL if reply_id available, otherwise post page
                notif_link = f"/reply/{reply_id}" if reply_id else f"/post/{post_id}"
                
                try:
                    if USE_MYSQL:
                        c.execute("""
                            INSERT INTO notifications (user_id, from_user, type, post_id, community_id, message, created_at, is_read, link, preview_text)
                            VALUES (?, ?, 'mention_reply', ?, ?, ?, NOW(), 0, ?, ?)
                            ON DUPLICATE KEY UPDATE created_at = NOW(), is_read = 0, message = VALUES(message), link = VALUES(link), preview_text = VALUES(preview_text)
                        """, (target, author_username, post_id, community_id, f"{author_username} mentioned you in a reply", notif_link, reply_preview or None))
                    else:
                        now_ts = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
                        c.execute("""
                            INSERT INTO notifications (user_id, from_user, type, post_id, community_id, message, created_at, is_read, link, preview_text)
                            VALUES (?, ?, 'mention_reply', ?, ?, ?, ?, 0, ?, ?)
                        """, (target, author_username, post_id, community_id, f"{author_username} mentioned you in a reply", now_ts, notif_link, reply_preview or None))
                    conn.commit()
                    
                    # Send push notification
                    try:
                        send_push_to_user(target, {
                            'title': 'You were mentioned',
                            'body': reply_preview or f"{author_username} mentioned you in a reply",
                            'url': notif_link,
                            'tag': f"mention-reply-{reply_id or post_id}-{target}"
                        })
                    except Exception as pe:
                        logger.warning(f"[Mention Reply] push error to {target}: {pe}")
                except Exception as ne:
                    logger.warning(f"[Mention Reply] db error for {target}: {ne}")
            
            logger.info(f"[Mention Reply] Notified {len(notified)} users: {list(notified)}")
    except Exception as e:
        logger.warning(f"process_mentions_for_reply error: {e}")

