@app.route('/get_active_chat_counts')
@login_required
def get_active_chat_counts():
    """Return number of distinct chat partners per community for the current user."""
    username = session.get('username')
    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            # Map usernames to id for joins
            c.execute("SELECT id FROM users WHERE username=?", (username,))
            me = c.fetchone()
            if not me:
                return jsonify({ 'success': False, 'error': 'user not found' }), 404
            # Communities the user belongs to
            c.execute("""
                SELECT c.id, c.name
                FROM communities c
                JOIN user_communities uc ON c.id = uc.community_id
                JOIN users u ON uc.user_id = u.id
                WHERE u.username = ?
            """, (username,))
            comms = [dict(row) for row in c.fetchall()]
            results = []
            for comm in comms:
                # Distinct partners in this community: any user who shares this community and has message with me
                c.execute("""
                    SELECT DISTINCT m.sender as user
                    FROM messages m
                    WHERE m.receiver = ?
                    UNION
                    SELECT DISTINCT m.receiver as user
                    FROM messages m
                    WHERE m.sender = ?
                """, (username, username))
                partners = {row['user'] for row in c.fetchall()}
                if not partners:
                    results.append({ 'community_id': comm['id'], 'community_name': comm['name'], 'active_chats': 0 })
                    continue
                placeholders = ",".join(["?"]*len(partners))
                params = list(partners)
                # Intersect with community members
                c.execute(f"""
                    SELECT COUNT(DISTINCT u.username) as cnt
                    FROM users u
                    JOIN user_communities uc ON u.id = uc.user_id
                    WHERE uc.community_id = ? AND u.username IN ({placeholders}) AND u.username != ?
                """, [comm['id'], *params, username])
                row = c.fetchone()
                cnt = row['cnt'] if isinstance(row, dict) else (row[0] if row else 0)
                results.append({ 'community_id': comm['id'], 'community_name': comm['name'], 'active_chats': cnt or 0 })
            return jsonify({ 'success': True, 'counts': results })
    except Exception as e:
        logger.error(f"Error in get_active_chat_counts: {e}")
        return jsonify({ 'success': False, 'error': 'server error' }), 500

@app.route('/api/admin/embeddings/backfill', methods=['POST'])
@login_required
def admin_embeddings_backfill():
    """Backfill chunked embeddings for all profiles (or only missing ones).

    Pass ``{"force": true}`` in the JSON body to re-embed ALL profiles
    (needed after changing what data feeds into the embedding chunks,
    e.g. adding KB data).  Default behaviour only embeds profiles that
    are missing one or more chunks.
    """
    username = session.get('username')
    if not is_app_admin(username):
        return jsonify({'success': False, 'error': 'Unauthorized'}), 403
    try:
        force = (request.get_json() or {}).get('force', False)
        from backend.services.firestore_reads import _get_client as _get_fs_client
        from backend.services.embedding_service import CHUNK_TYPES, EMBEDDING_DIMS
        fs = _get_fs_client()
        to_embed = []
        for doc in fs.collection('steve_user_profiles').stream():
            if force:
                to_embed.append(doc.id)
            else:
                data = doc.to_dict()
                embs = data.get('embeddings') or {}
                has_all = all(
                    isinstance(embs.get(ct), list) and len(embs.get(ct, [])) == EMBEDDING_DIMS
                    for ct in CHUNK_TYPES
                )
                if not has_all:
                    to_embed.append(doc.id)

        if not to_embed:
            return jsonify({'success': True, 'message': 'All profiles already have full chunked embeddings', 'count': 0})

        import threading
        def _run_backfill(usernames):
            from backend.services.embedding_service import compute_and_store_embeddings
            ok = 0
            for u in usernames:
                try:
                    if compute_and_store_embeddings(u):
                        ok += 1
                except Exception as e:
                    logger.warning(f"Backfill embedding failed for {u}: {e}")
            logger.info(f"Chunked embedding backfill complete: {ok}/{len(usernames)} succeeded")

        t = threading.Thread(target=_run_backfill, args=(to_embed,), daemon=True)
        t.start()
        mode = "force re-embed (KB-aware)" if force else "missing-only backfill"
        return jsonify({'success': True, 'message': f'{mode} started for {len(to_embed)} profiles', 'count': len(to_embed)})
    except Exception as e:
        logger.error(f"Embedding backfill error: {e}", exc_info=True)
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/embeddings/status', methods=['GET'])
@login_required
def admin_embeddings_status():
    """Report chunked embedding coverage and FAISS index health."""
    username = session.get('username')
    if not is_app_admin(username):
        return jsonify({'success': False, 'error': 'Unauthorized'}), 403
    try:
        from backend.services.embedding_service import profile_index, CHUNK_TYPES, EMBEDDING_DIMS
        from backend.services.firestore_reads import _get_client as _get_fs_client
        fs = _get_fs_client()
        total = 0
        with_chunked = 0
        with_legacy = 0
        chunk_counts = {ct: 0 for ct in CHUNK_TYPES}
        for doc in fs.collection('steve_user_profiles').stream():
            total += 1
            data = doc.to_dict()
            embs = data.get('embeddings') or {}
            if isinstance(embs, dict) and any(
                isinstance(embs.get(ct), list) and len(embs.get(ct, [])) == EMBEDDING_DIMS
                for ct in CHUNK_TYPES
            ):
                with_chunked += 1
                for ct in CHUNK_TYPES:
                    if isinstance(embs.get(ct), list) and len(embs.get(ct, [])) == EMBEDDING_DIMS:
                        chunk_counts[ct] += 1
            elif data.get('embedding') and isinstance(data['embedding'], list) and len(data['embedding']) == EMBEDDING_DIMS:
                with_legacy += 1
        return jsonify({
            'success': True,
            'total_profiles': total,
            'with_chunked_embeddings': with_chunked,
            'with_legacy_embedding': with_legacy,
            'missing_any_embedding': total - with_chunked - with_legacy,
            'chunk_coverage': chunk_counts,
            'faiss_index_vectors': profile_index.size,
            'faiss_index_users': profile_index.user_count,
            'faiss_ready': profile_index.is_ready,
        })
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/networking/health', methods=['GET'])
@login_required
def admin_networking_health():
    """Networking health dashboard data: load distribution, feedback, outcomes."""
    username = session.get('username')
    if not is_app_admin(username):
        return jsonify({'success': False, 'error': 'Unauthorized'}), 403
    try:
        from backend.services.firestore_reads import _get_client as _get_fs_client
        fs = _get_fs_client()
        load_distribution = []
        feedback_summary = {'total_up': 0, 'total_down': 0, 'users_with_feedback': 0}
        outcome_summary = {'users_with_outcomes': 0, 'avg_response_rate': 0}
        response_rates = []
        for doc in fs.collection('steve_user_profiles').stream():
            data = doc.to_dict()
            rec_count = data.get('recommendationCount30d', 0) or 0
            if rec_count > 0:
                load_distribution.append({'username': doc.id, 'count': rec_count})
            fb_ups = data.get('feedbackUps', 0) or 0
            fb_downs = data.get('feedbackDowns', 0) or 0
            if fb_ups or fb_downs:
                feedback_summary['total_up'] += fb_ups
                feedback_summary['total_down'] += fb_downs
                feedback_summary['users_with_feedback'] += 1
            rr = data.get('introductionResponseRate')
            if rr is not None:
                response_rates.append(rr)
                outcome_summary['users_with_outcomes'] += 1
        load_distribution.sort(key=lambda x: -x['count'])
        if response_rates:
            outcome_summary['avg_response_rate'] = round(sum(response_rates) / len(response_rates), 2)
        return jsonify({
            'success': True,
            'load_distribution': load_distribution[:50],
            'feedback_summary': feedback_summary,
            'outcome_summary': outcome_summary,
        })
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


STALE_PROFILE_DAYS = int(os.environ.get('STALE_PROFILE_DAYS', '30'))
STALE_PROFILE_BATCH = int(os.environ.get('STALE_PROFILE_BATCH', '5'))


# ── Weekly KB auto-synthesis dispatcher (Cloud Scheduler) ────────────────
# Activated via Cloud Scheduler daily. Each day processes exactly one
# bucket (hash(username) % 7 == today's weekday), so every active user is
# refreshed once per calendar week without spikes. Gated by a KB-level
# kill switch (KB_WEEKLY_AUTO_ENABLED) and the shared CRON_SHARED_SECRET.
def _kb_weekly_auto_enabled() -> bool:
    return (os.environ.get('KB_WEEKLY_AUTO_ENABLED', 'true') or '').strip().lower() == 'true'


def _kb_weekly_batch_max() -> int:
    try:
        v = int(os.environ.get('KB_WEEKLY_BATCH_MAX', '200'))
    except ValueError:
        v = 200
    return max(1, min(v, 2000))


@app.route('/api/cron/kb/weekly-synthesis', methods=['POST'])
def cron_kb_weekly_synthesis():
    """Refresh the member Knowledge Base for one day's bucket of active users.

    Triggered daily by Cloud Scheduler; each call handles the bucket
    ``datetime.utcnow().weekday()`` (0=Mon..6=Sun) so every active user is
    refreshed once per 7-day window. Users are considered active if they
    have at least one post or reply in the last ``KB_ACTIVE_WINDOW_DAYS``
    days (default 7).

    Auth: shared ``X-Cron-Secret`` header (``CRON_SHARED_SECRET`` env).

    Query params:
      ``dry_run`` (``1``/``true``) — list candidates, don't synthesize.
      ``bucket`` — override the computed day-of-week bucket (0..6).
      ``window_days`` — override the active-window size.
    """
    expected = os.environ.get('CRON_SHARED_SECRET') or ''
    provided = request.headers.get('X-Cron-Secret') or ''
    if not expected or provided != expected:
        return jsonify({'success': False, 'error': 'forbidden'}), 403

    if not _kb_weekly_auto_enabled():
        return jsonify({
            'success': True,
            'skipped': True,
            'reason': 'kb_weekly_auto_disabled',
            'dispatched': 0,
        })

    dry_run = (request.args.get('dry_run') or '').strip().lower() in {'1', 'true', 'yes', 'on'}

    try:
        bucket_override = request.args.get('bucket')
        bucket = int(bucket_override) if bucket_override not in (None, '') else datetime.utcnow().weekday()
    except (TypeError, ValueError):
        return jsonify({'success': False, 'error': 'invalid_bucket'}), 400

    try:
        window_override = request.args.get('window_days')
        window_days = int(window_override) if window_override not in (None, '') else None
    except (TypeError, ValueError):
        return jsonify({'success': False, 'error': 'invalid_window_days'}), 400

    try:
        from backend.services.steve_knowledge_base import (
            USE_KNOWLEDGE_BASE_V1,
            get_active_usernames_for_kb_sweep,
            schedule_knowledge_synthesis,
        )
        if not USE_KNOWLEDGE_BASE_V1:
            return jsonify({
                'success': True,
                'skipped': True,
                'reason': 'kb_v1_disabled',
                'dispatched': 0,
            })

        batch_max = _kb_weekly_batch_max()
        usernames = get_active_usernames_for_kb_sweep(
            bucket,
            window_days=window_days,
            limit=batch_max,
        )

        if dry_run:
            return jsonify({
                'success': True,
                'dry_run': True,
                'bucket': bucket,
                'window_days': window_days,
                'candidate_count': len(usernames),
                'candidates': usernames[:50],
                'dispatched': 0,
            })

        dispatched = 0
        for u in usernames:
            try:
                schedule_knowledge_synthesis(u)
                dispatched += 1
            except Exception as disp_err:
                logger.warning("KB weekly dispatch failed for %s: %s", u, disp_err)

        logger.info(
            "KB weekly synthesis: dispatched %d/%d for bucket %d (window=%s)",
            dispatched, len(usernames), bucket, window_days,
        )
        return jsonify({
            'success': True,
            'bucket': bucket,
            'candidate_count': len(usernames),
            'dispatched': dispatched,
        })
    except Exception as e:
        logger.exception("KB weekly synthesis error: %s", e)
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/steve_profiles/refresh_stale', methods=['POST'])
@login_required
def admin_steve_profiles_refresh_stale():
    """Re-analyze the N most stale Steve profiles in the background.

    Intended to be called daily by Cloud Scheduler or from the admin dashboard.
    Configurable via env: STALE_PROFILE_DAYS (default 30), STALE_PROFILE_BATCH (default 5).
    """
    username = session.get('username')
    if not is_app_admin(username):
        return jsonify({'success': False, 'error': 'Unauthorized'}), 403

    data = request.get_json(silent=True) or {}
    max_age_days = int(data.get('max_age_days', STALE_PROFILE_DAYS))
    batch_size = min(int(data.get('batch_size', STALE_PROFILE_BATCH)), 20)

    try:
        from backend.services.firestore_reads import _get_client as _get_fs_client
        from datetime import timedelta
        fs = _get_fs_client()
        cutoff = datetime.utcnow() - timedelta(days=max_age_days)

        stale = []
        for doc in fs.collection('steve_user_profiles').stream():
            d = doc.to_dict()
            last = d.get('lastUpdated')
            if last is None:
                stale.append((doc.id, None))
                continue
            if isinstance(last, str):
                try:
                    last = datetime.fromisoformat(last.replace('Z', '+00:00').replace('+00:00', ''))
                except Exception:
                    stale.append((doc.id, None))
                    continue
            if last < cutoff:
                stale.append((doc.id, last))

        stale.sort(key=lambda x: x[1] or datetime.min)
        to_refresh = [u for u, _ in stale[:batch_size]]

        if not to_refresh:
            return jsonify({'success': True, 'message': f'No profiles older than {max_age_days} days', 'count': 0})

        import threading
        def _run_refresh(usernames):
            ok = 0
            for u in usernames:
                try:
                    success, _, _ = _execute_steve_profile_analysis(u, depth='standard', reset=False)
                    if success:
                        ok += 1
                        try:
                            invalidate_steve_context_cache(u)
                        except Exception:
                            pass
                except Exception as e:
                    logger.warning(f"Stale refresh failed for {u}: {e}")
            logger.info(f"Stale profile refresh complete: {ok}/{len(usernames)} succeeded")

        t = threading.Thread(target=_run_refresh, args=(to_refresh,), daemon=True)
        t.start()
        return jsonify({
            'success': True,
            'message': f'Refreshing {len(to_refresh)} stale profiles (>{max_age_days} days old)',
            'count': len(to_refresh),
            'usernames': to_refresh,
        })
    except Exception as e:
        logger.error(f"Stale refresh error: {e}", exc_info=True)
        return jsonify({'success': False, 'error': str(e)}), 500


@app.route('/api/admin/networking/compute_outcomes', methods=['POST'])
@login_required
def admin_compute_networking_outcomes():
    """Correlate Steve recommendations with DM history to compute response rates.

    For each user who has been recommended, checks whether the requester
    opened a DM within 7 days and whether the recommended person replied.
    Writes introductionResponseRate to Firestore.
    """
    username = session.get('username')
    if not is_app_admin(username):
        return jsonify({'success': False, 'error': 'Unauthorized'}), 403
    try:
        import threading
        def _run():
            try:
                _compute_all_outcome_rates()
            except Exception as e:
                logger.error(f"Outcome computation failed: {e}", exc_info=True)
        threading.Thread(target=_run, daemon=True).start()
        return jsonify({'success': True, 'message': 'Outcome computation started in background'})
    except Exception as e:
        return jsonify({'success': False, 'error': str(e)}), 500


def _compute_all_outcome_rates():
    """Scan recommendation logs and correlate with DM data to compute response rates."""
    from backend.services.firestore_reads import _get_client as _get_fs_client
    from backend.services.firestore_writes import _get_client as _get_fs_write_client
    from datetime import timedelta

    fs_r = _get_fs_client()
    fs_w = _get_fs_write_client()

    user_recs = {}
    for doc in fs_r.collection('steve_user_profiles').stream():
        data = doc.to_dict()
        recs = data.get('recentRecommendations', [])
        if recs:
            user_recs[doc.id] = recs

    if not user_recs:
        logger.info("No recommendation data to compute outcomes for")
        return

    try:
        with get_db_connection() as conn:
            c = conn.cursor()
            stats = {}
            for rec_username, recs in user_recs.items():
                intros_received = 0
                intros_replied = 0
                for rec in recs:
                    requester = rec.get('by', '')
                    rec_date = rec.get('date')
                    if not requester or not rec_date:
                        continue
                    window_end = rec_date + timedelta(days=7)
                    ph = get_sql_placeholder()
                    c.execute(f"""
                        SELECT COUNT(*) FROM messages
                        WHERE sender = {ph} AND receiver = {ph}
                        AND timestamp > {ph} AND timestamp < {ph}
                    """, (requester, rec_username, str(rec_date)[:19], str(window_end)[:19]))
                    row = c.fetchone()
                    dm_count = row[0] if row and not hasattr(row, 'keys') else (row.get('COUNT(*)', 0) if row else 0)
                    if dm_count > 0:
                        intros_received += 1
                        c.execute(f"""
                            SELECT COUNT(*) FROM messages
                            WHERE sender = {ph} AND receiver = {ph}
                            AND timestamp > {ph} AND timestamp < {ph}
                        """, (rec_username, requester, str(rec_date)[:19], str(window_end)[:19]))
                        reply_row = c.fetchone()
                        reply_count = reply_row[0] if reply_row and not hasattr(reply_row, 'keys') else (reply_row.get('COUNT(*)', 0) if reply_row else 0)
                        if reply_count > 0:
                            intros_replied += 1

                if intros_received > 0:
                    rate = round(intros_replied / intros_received, 2)
                    stats[rec_username] = {
                        'introductionResponseRate': rate,
                        'introductionsReceived': intros_received,
                        'introductionsReplied': intros_replied,
                    }

            for uname, data in stats.items():
                fs_w.collection('steve_user_profiles').document(uname).set(data, merge=True)
            logger.info(f"Outcome rates computed for {len(stats)} users")
    except Exception as e:
        logger.error(f"_compute_all_outcome_rates error: {e}", exc_info=True)


@app.route('/api/admin/knowledge_base/network/<int:network_id>/insights', methods=['POST', 'OPTIONS'], endpoint='admin_network_insights')
@login_required
def admin_network_insights(network_id):
    """Generate *real* strategic network insights using Grok reasoning over the Knowledge Base.
    Respects network_type as a strategic knob. Replaces previous mock data."""
    username = session.get('username')
    if request.method == 'OPTIONS':
        response = make_response()
        return add_cors_headers(response)
    if not is_app_admin(username):
        response = jsonify({'success': False, 'error': 'Unauthorized'})
        return add_cors_headers(response), 403
    try:
        from backend.services.steve_knowledge_base import fetch_network_kb_data

        # Get network metadata
        with get_db_connection() as conn:
            c = conn.cursor()
            ph = get_sql_placeholder()
            c.execute(f"SELECT network_type, name FROM communities WHERE id = {ph}", (network_id,))
            row = c.fetchone()
            if not row:
                return jsonify({'success': False, 'error': 'Network not found'}), 404
            network_type = (row['network_type'] if hasattr(row, 'keys') else row[0]) or 'professional'
            network_name = (row['name'] if hasattr(row, 'keys') else row[1]) or f'Network {network_id}'

        # Fetch real KB data (auto-synthesizes if none exists yet)
        kb_data = fetch_network_kb_data(network_id, auto_synthesize=True)
        meta = kb_data.get("_meta", {})
        member_count = meta.get("memberCount", 0)
        kb_count = meta.get("membersWithKB", 0)
        dims_available = meta.get("hasDimensions", 0)

        # Build a structured KB dump for the prompt
        kb_sections = []
        for dim_name in ("NetworkIndex", "NetworkExpertise", "NetworkGeographyCulture",
                         "NetworkComposition", "NetworkInferredContext", "NetworkUniqueFingerprint"):
            dim_data = kb_data.get(dim_name, {})
            if dim_data:
                kb_sections.append(f"### {dim_name}\n{json.dumps(dim_data, indent=1, default=str)[:3000]}")

        kb_block = "\n\n".join(kb_sections) if kb_sections else "No Knowledge Base data available yet. Run member profiling first."

        prompt = f"""You are Steve, a master network strategist for C.Point communities.

Network: {network_name}
Type: {network_type}
Members: {member_count} total, {kb_count} with synthesized Knowledge Bases
KB Dimensions Available: {dims_available}/6

=== REAL KNOWLEDGE BASE DATA ===
{kb_block}
=== END KB DATA ===

Using ONLY the real Knowledge Base data above, produce **actionable, specific** strategic insights.
Use {network_type} as the primary lens — Professional networks prioritize career clusters and CompanyIntel; Social networks prioritize engagement and events; Sports prioritize performance and team dynamics.

CRITICAL RULES - FOUNDER AWARENESS & POST REASONING:
- Use the "founderInfo" section from NetworkIndex if present. If the platform founder (Paulo) is a member, acknowledge this but DO NOT let his individual profile dominate the network analysis. Treat him as "Platform Architect / Steve Creator" providing infrastructure. Focus analysis on the organic community dynamics and collective intelligence of regular members.
- For posts and comments: Show DEEP reasoning. Understand original post vs reply context, semantic intent, thread structure (direct reply vs reply-to-reply), and cultural/slang nuances. Link insights to genuine patterns in identity, expertise, values, or network dynamics. Avoid random or superficial observations.
- Every claim MUST be backed by specific data from the KB above. Do NOT hallucinate or invent data or communities.
- memberCount in group recommendations must reflect actual numbers from the KB (excluding founder inflation).
- If data is sparse, say so honestly rather than fabricating patterns.
- Reference real expertise domains, locations, companies, rare qualities, and relational patterns from the KB data.

Return ONLY valid JSON matching this schema:
{{
  "summary": "2-3 sentence high-level strategic overview referencing specific KB patterns",
  "groupRecommendations": [
    {{
      "title": "Specific group name based on real KB clusters",
      "memberCount": <actual count from KB data>,
      "rationale": "Reason tied to specific KB signals you can see in the data above",
      "suggestedName": "slug-name",
      "confidence": 0.0-1.0
    }}
  ],
  "contentIdeas": [
    "Concrete content idea tied to real network data"
  ],
  "talentSignals": [
    "Specific talent pattern with evidence from the KB data above"
  ]
}}"""

        client = OpenAI(
            api_key=XAI_API_KEY,
            base_url="https://api.x.ai/v1"
        )

        completion = client.chat.completions.create(
            model=GROK_MODEL_FAST,
            messages=[
                {"role": "system", "content": "You are Steve, a master network strategist. Respond with valid JSON only. Ground EVERY claim in the provided Knowledge Base data. Never hallucinate, invent patterns, or reference non-existent communities. Use founderInfo from NetworkIndex if present. If the platform founder is a member, acknowledge this but focus analysis on organic community dynamics rather than letting his profile dominate. Show deep reasoning about posts and comments - understand context, reply chains, semantic intent, and cultural nuances."},
                {"role": "user", "content": prompt}
            ],
            temperature=0.4,
            max_tokens=3000,
            response_format={"type": "json_object"}
        )

        insights_data = json.loads(completion.choices[0].message.content.strip())

        result = {
            "success": True,
            "buildMarker": _BUILD_MARKER,
            "insights": {
                "networkId": network_id,
                "generatedAt": datetime.utcnow().isoformat(),
                "networkType": network_type,
                "memberCount": member_count,
                "membersWithKB": kb_count,
                "kbDimensions": dims_available,
                "buildMarker": _BUILD_MARKER,
                **insights_data
            }
        }

        logger.info("Real network insights generated for network %s (type=%s, members=%d, kb=%d, dims=%d, model=%s, build=%s)",
                     network_id, network_type, member_count, kb_count, dims_available, GROK_MODEL_FAST, _BUILD_MARKER)
        response = jsonify(result)
        return add_cors_headers(response)

    except json.JSONDecodeError as json_err:
        logger.error(f"Failed to parse Grok JSON for insights {network_id}: {json_err}")
        fallback = {
            "summary": f"Analysis for {network_name} ({network_type}). Grok returned malformed JSON - check logs.",
            "groupRecommendations": [],
            "contentIdeas": ["Review KB data quality", "Run full network synthesis first"],
            "talentSignals": ["Check Firestore steve_knowledge_base collection for this network"]
        }
        response = jsonify({"success": True, "buildMarker": _BUILD_MARKER, "insights": {**fallback, "buildMarker": _BUILD_MARKER, "networkId": network_id, "generatedAt": datetime.utcnow().isoformat(), "networkType": network_type}})
        return add_cors_headers(response)
    except Exception as e:
        logger.error(f"Error generating real network insights for {network_id}: {e}", exc_info=True)
        response = jsonify({'success': False, 'error': str(e), 'buildMarker': _BUILD_MARKER})
        return add_cors_headers(response), 500


